const TECHS = [
  // ─── Lower Paleolithic ─────────────────────────────────────────
  { id: "bipedal-gait", name: "Bipedal Locomotion", era: "lower-paleo", category: "subsistence",
    year: "~6 Mya", prereqs: [],
    desc: "Habitual upright walking on two legs, appearing in early hominins by ~6 million years ago and unmistakable in Australopithecus afarensis ('Lucy', 3.2 Mya). Skeletal markers — angled femurs, an S-curved spine, valgus knees, and arched feet — distinguish hominins from quadruped apes. Bipedalism freed the hands for tool use and load-carrying, reduced midday heat exposure on the African savanna, and is the postural foundation that every later hominin trait builds on." },
  { id: "wooden-club", name: "Wooden Club", era: "lower-paleo", category: "weapons",
    year: "~3 Mya", prereqs: [],
    desc: "Hand-held wooden bludgeons, the simplest weapon. Wood rots without trace, but chimpanzee analogues, blunt-force trauma in early hominin remains, and ethnographic evidence make clubs almost certainly older than the Oldowan stone industry. They probably remained the standard close-quarters weapon for two million years before composite spears displaced them, and they still recur as ceremonial and military objects (mace, war club, shillelagh) wherever metal is scarce." },
  { id: "gestural-communication", name: "Gestural Communication", era: "lower-paleo", category: "social",
    year: "~3 Mya", prereqs: [],
    desc: "Coordinated signaling with hands, faces, posture, and vocal calls — capabilities present in apes but elaborated by hominins into intentional reference, deictic pointing, and pantomime. The mirror-neuron and hand-control circuitry that supports gesture overlaps anatomically with that of speech, and many linguists argue gesture preceded vocal language by over a million years before brain growth and a descended larynx made articulate sound possible." },
  { id: "oldowan", name: "Oldowan Stone Tools", era: "lower-paleo", category: "tools",
    year: "~3.3 Mya", prereqs: [],
    desc: "Simple chipped pebble cores and sharp flakes struck from cobbles by direct hammerstone percussion. The oldest examples at Lomekwi 3 (Kenya, 3.3 Mya) actually predate the genus Homo, but the industry is best known from Olduvai Gorge where Mary and Louis Leakey identified it in the 1930s. Used for butchering carcasses, processing plants, and cracking bones for marrow, Oldowan tools persisted nearly two million years and established the stone-on-stone reduction tradition underlying every later lithic technology." },
  { id: "scavenging", name: "Organized Scavenging", era: "lower-paleo", category: "subsistence",
    year: "~2.6 Mya", prereqs: ["oldowan"],
    desc: "Aggressive 'power scavenging' from kills left by leopards, hyenas, and saber-tooth cats, using Oldowan flakes to slice through hide and crack long bones for marrow. At Bouri (Ethiopia, ~2.5 Mya), hominin cut-marks overlie carnivore tooth-marks, showing humans took the carcass after the original predator. This high-fat, high-calorie diet, unavailable to any vegetarian primate, is the metabolic foundation that allowed the brain to expand from ~450 cc in early Homo toward the modern range." },
  { id: "persistence-hunting", name: "Persistence Hunting", era: "lower-paleo", category: "weapons",
    year: "~2 Mya", prereqs: ["bipedal-gait"],
    desc: "Endurance running that drives ungulate prey to heat exhaustion under midday sun. Humans uniquely combine sweat cooling, hairlessness, narrow waists, and long springy Achilles tendons — capabilities that emerge in Homo erectus by ~2 Mya. Anthropologists Bramble and Lieberman argue this hunting style preceded projectile weapons and shaped the entire modern human body plan. Persistence hunts of antelope are still occasionally practiced by the San in the Kalahari." },
  { id: "fire-use", name: "Use of Fire", era: "lower-paleo", category: "tools",
    year: "~1.5 Mya", prereqs: [],
    desc: "Tending fire from lightning strikes or grass burns for warmth, light, predator deterrence, and softening tough plant foods. Burnt bone and ash at Wonderwerk Cave (South Africa, ~1 Mya) and Gesher Benot Ya'aqov (Israel, 790 kya) push the date well into Homo erectus territory. Whether erectus could make fire is debated, but tending it for hundreds of thousands of years was enough to build the dependence on cooked food that the modern human gut anatomy reflects." },
  { id: "acheulean", name: "Acheulean Hand Axes", era: "lower-paleo", category: "tools",
    year: "~1.76 Mya", prereqs: ["oldowan"],
    desc: "Bifacially worked teardrop hand-axes and cleavers, requiring 30+ controlled blows to a flint nodule with carefully judged angles and force. Made by Homo erectus from ~1.76 Mya at Kokiselei (Kenya), the form persists for over a million years across three continents — a stability unmatched by any later technology. Their symmetry implies an internal mental template, and the long apprenticeship needed to make one suggests demonstration-based teaching, possibly even proto-language." },
  { id: "windbreaks", name: "Windbreaks & Camps", era: "lower-paleo", category: "shelter",
    year: "~1.8 Mya", prereqs: [],
    desc: "Temporary brush windbreaks built around hearths — the first identifiable home-bases where butchery, tool-making, and child-rearing happened in one fixed spot. Ring-shaped scatters of debris at FxJj 50 (Koobi Fora, Kenya, 1.6 Mya) and post-hole arrangements at Terra Amata (France, 380 kya) imply repeated stays. The shift from 'wherever the carcass is' to 'a place we return to' reorganizes social life around a camp and is a precondition for all later sedentism." },
  { id: "wooden-spear", name: "Wooden Thrusting Spear", era: "lower-paleo", category: "weapons",
    year: "~400 kya", prereqs: ["acheulean", "wooden-club"],
    desc: "Two-meter spears of spruce and pine, fire-hardened and balanced for thrusting and short throws. Eight perfectly preserved examples were excavated from a 400-kya peat bog at Schöningen (Germany), alongside the butchered bones of more than twenty wild horses. The find ended a long argument: pre-modern humans were active hunters of large game, not opportunistic scavengers. Coordinating an ambush of a herd implies organized planning and division of roles — proto-language at least, possibly something more." },
  { id: "fire-making", name: "Fire-Making", era: "lower-paleo", category: "tools",
    year: "~400 kya", prereqs: ["fire-use"],
    desc: "Producing fire on demand by friction (a drilled spindle in a fire-board) or percussion (striking pyrite or marcasite against flint). Black flint-and-pyrite striking kits appear in Mousterian Neanderthal sites by ~50 kya, and ethnographic evidence makes friction methods deeply familiar across every Holocene culture. Once fire is replicable rather than tended, dependence on natural ignition collapses and humans can colonize cold regions — a precondition for later expansion into northern Eurasia and eventually the Americas." },
  { id: "cooking", name: "Cooking", era: "lower-paleo", category: "subsistence",
    year: "~400 kya", prereqs: ["fire-making", "scavenging"],
    desc: "Heat-processing food to break down starches, denature proteins, and kill pathogens. Richard Wrangham's 'cooking hypothesis' argues that the calorie surplus from cooked food allowed Homo erectus to grow a 50% larger brain on a smaller gut: cooked food extracts more energy with less digestive work. The earliest hearth-like residues at Wonderwerk Cave are ~1 Mya, but cooking only becomes routine archaeologically by ~400 kya. Modern humans cannot survive long-term on raw wild food." },

  // ─── Middle Paleolithic ────────────────────────────────────────
  { id: "digging-stick", name: "Digging Stick", era: "middle-paleo", category: "tools",
    year: "~300 kya", prereqs: ["oldowan"],
    desc: "Fire-sharpened wooden poles used to unearth tubers, roots, bulbs, and small game from burrows. Wood rarely preserves, but tooth-wear patterns in early hominins, residue analysis, and the universal presence of digging sticks among modern foragers (San, Hadza, Aboriginal Australians) make this almost certainly the most important wooden tool of the Pleistocene. Underground storage organs are calorie-dense, drought-resilient, and inaccessible to most other primates — digging sticks unlocked a major food category." },
  { id: "levallois", name: "Levallois Technique", era: "middle-paleo", category: "tools",
    year: "~300 kya", prereqs: ["acheulean"],
    desc: "A prepared-core knapping technique in which the toolmaker shapes a flint nodule with preliminary blows so that a single final strike removes a flake of predictable size and shape. Appearing ~300 kya in the Mousterian and Middle Stone Age industries, Levallois reduction requires planning several steps ahead and is taken as evidence of a major cognitive shift. The same principles still underlie modern stone-tool production by knappers worldwide." },
  { id: "hafting", name: "Hafting", era: "middle-paleo", category: "tools",
    year: "~200 kya", prereqs: ["levallois"],
    desc: "Binding stone points and blades to wooden shafts using sinew, plant fiber, pitch, or birch tar. Hafted Levallois points appear by ~200 kya, transforming hand-held tools into spears, axes, and adzes whose force is multiplied by a long lever arm. The technique requires foresight to assemble parts that look nothing like the finished tool, and is the basis of every composite implement that follows — from Neolithic sickles to medieval halberds." },
  { id: "birch-tar", name: "Birch-Bark Tar", era: "middle-paleo", category: "tools",
    year: "~200 kya", prereqs: ["fire-making", "levallois"],
    desc: "Heat-distilled adhesive made by smoldering birch bark in low-oxygen pits, producing a thick black resin that hardens on cooling. Königsaue (Germany, ~80 kya) and earlier Italian sites yield birch tar lumps with Neanderthal fingerprints. As the world's first synthetic material — its production requires controlled temperatures around 350°C — it is direct evidence of pyrotechnical sophistication in pre-modern humans, and is still used in traditional bowmaking." },
  { id: "hide-clothing", name: "Hide Clothing", era: "middle-paleo", category: "shelter",
    year: "~170 kya", prereqs: ["acheulean"],
    desc: "Scraped, softened, and stitched animal hides used as garments, footwear, and shelter coverings. Although hides decompose, dedicated hide-scrapers (steep-edged 'side-scrapers' and 'end-scrapers') become abundant by ~170 kya, and lice genetics independently date the divergence of body lice from head lice — implying clothing — to roughly the same window. Tailored clothing is the technology that lets hominins survive winters in glacial Eurasia and eventually colonize Siberia and the Americas." },
  { id: "shellfishing", name: "Shellfish Gathering", era: "middle-paleo", category: "subsistence",
    year: "~165 kya", prereqs: ["cooking"],
    desc: "Coastal foraging for mussels, limpets, oysters, and crabs at sites like Pinnacle Point (South Africa, ~165 kya). Marine resources are predictable, accessible, and rich in long-chain omega-3 fatty acids that support brain growth. Shellfish heaps (middens) are also the first evidence of large-scale resource mapping by tide tables — humans had to plan around lunar cycles. Coastal routes likely guided the migration of modern humans out of Africa around the Indian Ocean rim." },
  { id: "pigments", name: "Pigments & Body Paint", era: "middle-paleo", category: "social",
    year: "~160 kya", prereqs: [],
    desc: "Powdered and bound red ochre (iron oxide), yellow ochre, and black manganese used for body decoration, hide processing, and possibly symbolic marking. Engraved ochre blocks at Blombos Cave (~75–100 kya) carry deliberate cross-hatched patterns, taken by many archaeologists as the oldest evidence of abstract symbolic thought. Pigment processing also requires recipes and storage — early evidence of recipe-style technical knowledge." },
  { id: "composite-spear", name: "Composite Spear", era: "middle-paleo", category: "weapons",
    year: "~150 kya", prereqs: ["hafting", "wooden-spear"],
    desc: "Wooden shafts tipped with hafted stone points (Levallois or pointed flakes), throwable at ~15 m or thrust at close range. Stone-tipped spears appear by ~150 kya in Africa and are used by both modern humans and Neanderthals. Compared to fire-hardened wooden spears, the stone tip pierces hide and bone more reliably and stays sharp through repeated use. Standoff distance from large prey rises substantially, reducing hunter casualties." },
  { id: "shell-beads", name: "Shell Beads", era: "middle-paleo", category: "social",
    year: "~140 kya", prereqs: ["pigments", "shellfishing"],
    desc: "Pierced sea-shells (Nassarius and Glycymeris) strung as necklaces or sewn onto clothing — deliberately selected, sometimes imported from coasts hundreds of kilometers away, and often colored with ochre. Found at Skhul (Israel, ~100 kya) and Taforalt (Morocco, ~82 kya), they are the earliest unambiguous personal ornaments and identity markers, implying both symbolic communication and trade or kinship networks of substantial reach." },
  { id: "water-flask", name: "Water Containers", era: "middle-paleo", category: "tools",
    year: "~120 kya", prereqs: ["shellfishing"],
    desc: "Punctured, polished ostrich-eggshell flasks engraved with identifying marks, used to carry water across arid landscapes. Found from Diepkloof Rock Shelter (South Africa, ~60 kya) onward in regular cached sets, they are durable, repairable, and far lighter than gourds or pottery. Portable water means foragers can cross dry intervals between water sources, expanding usable territory and connecting otherwise isolated wet patches into a functional landscape." },
  { id: "burial", name: "Deliberate Burial", era: "middle-paleo", category: "social",
    year: "~120 kya", prereqs: ["pigments"],
    desc: "Intentional interment of the dead in prepared graves, sometimes accompanied by ochre, flowers, or grave goods. Sites like Qafzeh (Israel, ~100 kya), Shanidar (Iraq, Neanderthal, ~70 kya), and Sungir (Russia, ~30 kya, with thousands of beaded ornaments) suggest beliefs about the dead extending beyond mere disposal. Burial is the earliest archaeologically visible practice that strongly implies symbolic thought about persons and possibly an afterlife." },
  { id: "proto-language", name: "Proto-Language", era: "middle-paleo", category: "social",
    year: "~100 kya", prereqs: ["gestural-communication", "cooking"],
    desc: "Spoken communication beyond simple alarm calls, with combinable units and reference to absent things. The hyoid bone in Kebara Neanderthal anatomy, FOXP2 gene variants shared with Neanderthals, and the planning required for Schöningen-style cooperative hunting all point to articulate speech well before modern humans appeared. Whether Neanderthals had fully syntactic language is still debated, but most linguists place some form of language at or before 500 kya." },

  // ─── Upper Paleolithic ─────────────────────────────────────────
  { id: "rafts", name: "Rafts & Dugouts", era: "upper-paleo", category: "transport",
    year: "~50 kya", prereqs: [],
    desc: "Bound-log or bamboo rafts and primitive dugouts capable of crossing open water beyond sight of land. The colonization of Sahul (Australia + New Guinea) by ~50–65 kya required at least eight sea crossings of 50–100 km, with one stretch of ~90 km. These voyages predate any other evidence of seafaring by tens of thousands of years and imply not just craft but planning, group transport, and confidence to leave a known coast." },
  { id: "blade-tech", name: "Blade Technology", era: "upper-paleo", category: "tools",
    year: "~50 kya", prereqs: ["levallois"],
    desc: "Long, narrow flakes (length at least twice width) struck systematically from prismatic cores prepared with a striking platform. Blade industries appear in Africa by ~70 kya and dominate Eurasia by ~50 kya during the Upper Paleolithic transition. They yield five times as much cutting edge per kilogram of stone as Mousterian flakes, making lithic raw material go further and enabling more specialized tools (burins, end-scrapers, backed knives) cut from a single core." },
  { id: "bone-tools", name: "Bone & Antler Tools", era: "upper-paleo", category: "tools",
    year: "~45 kya", prereqs: ["blade-tech"],
    desc: "Awls, needles, points, harpoons, and shafts shaped from bone, antler, ivory, and tooth — materials largely ignored by earlier industries despite their toughness and workability. The Aurignacian (~45 kya) and Solutrean (~22 kya) made bone-working a major industry. Bone holds detail better than most stones, allowing decoration, and enables tools (eyed needles, barbed harpoons) impossible in stone alone." },
  { id: "needles", name: "Eyed Needles", era: "upper-paleo", category: "tools",
    year: "~40 kya", prereqs: ["bone-tools", "hide-clothing"],
    desc: "Bone or ivory needles with drilled or carved eyes, allowing thread to pull through layers of hide and produce fitted, layered, and closeable garments. The earliest known examples come from Denisova Cave (Siberia, ~50 kya) and the Aurignacian. Tailored clothing — as opposed to draped hides — sealed body heat far more effectively and is the technological prerequisite for surviving Last Glacial Maximum winters in northern Eurasia." },
  { id: "cave-art", name: "Cave Painting", era: "upper-paleo", category: "social",
    year: "~40 kya", prereqs: ["pigments"],
    desc: "Figurative paintings and engravings on cave walls, rendered in ochre, charcoal, and manganese, often with sophisticated technique: shading, perspective, and movement implied by repeated outlines. Sulawesi (Indonesia) holds dated examples ~45 kya; Chauvet (France) was painted ~36 kya; Lascaux is ~17 kya. The art is typically deep underground and depicts animals far more often than humans, suggesting ritual rather than decorative function." },
  { id: "flute", name: "Bone Flute", era: "upper-paleo", category: "social",
    year: "~40 kya", prereqs: ["bone-tools"],
    desc: "Flutes carved from bird bone (vulture, swan) and mammoth ivory, with finger holes producing a usable musical scale. The Hohle Fels and Geißenklösterle flutes from Germany date to ~40 kya. The Divje Babe Cave bear-bone flute, attributed to Neanderthals at ~50 kya, is contested but plausible. Music — like art — has no direct survival function, making the flutes some of the earliest evidence of leisure, ritual, or aesthetic experience." },
  { id: "bow-drill", name: "Bow Drill", era: "upper-paleo", category: "tools",
    year: "~40 kya", prereqs: ["fire-making", "bone-tools"],
    desc: "A wooden spindle spun rapidly inside a fire-board by reciprocating motion of a strung bow, generating enough friction heat to ignite tinder. The bow-drill multiplies hand-drill technique by an order of magnitude in speed and reduces fatigue. The same mechanism, scaled up, becomes the lathe and the pump-drill, and the technique is still taught in survival schools and used in some indigenous fire-starting traditions." },
  { id: "tally-bones", name: "Tally Marks", era: "upper-paleo", category: "knowledge",
    year: "~40 kya", prereqs: ["bone-tools"],
    desc: "Notched bones recording counts in groups of fives, tens, or other bases. The Lebombo bone (Eswatini, ~43 kya) carries 29 notches; the Ishango bone (DR Congo, ~20 kya) has groups of marks suggesting more than simple counting — possibly arithmetic or lunar accounting. These are the earliest known mathematical artifacts, predating writing by tens of thousands of years and showing that abstract numerical thought far predated agriculture." },
  { id: "oil-lamp", name: "Oil Lamp", era: "upper-paleo", category: "tools",
    year: "~40 kya", prereqs: ["fire-making", "bone-tools"],
    desc: "Stone basins or scooped flat stones holding rendered animal fat with a moss or lichen wick. Hundreds of lamps were recovered from Lascaux and Altamira where they lit deep-cave painting sessions. Lamps extend the working day past sunset and unlock the use of dark cave interiors, expanding both habitable space and the sites available for ritual or art." },
  { id: "spun-fiber", name: "Spun Fiber & Cordage", era: "upper-paleo", category: "tools",
    year: "~36 kya", prereqs: ["bone-tools"],
    desc: "Twisted plant-fiber cordage (flax, nettle, bast) — the foundation of every later rope, net, snare, sling, bowstring, hafting, and woven textile. A 36-kya twisted flax fiber from Dzudzuana Cave (Georgia) is the oldest direct evidence, but the universality of cordage among modern foragers and its presupposition by spear-hafting make it almost certainly far older. Cordage is the most underrated invention in this whole tree." },
  { id: "figurines", name: "Figurines & Sculpture", era: "upper-paleo", category: "social",
    year: "~35 kya", prereqs: ["bone-tools", "pigments"],
    desc: "Three-dimensional carved figures in ivory, antler, stone, and fired clay, depicting humans (often emphatically female), animals, and human-animal hybrids. The Löwenmensch (lion-man) from Hohlenstein-Stadel is ~40 kya; Venus figurines like Willendorf, Dolní Věstoníce, and Lespugue span ~30–25 kya. Their portability — unlike cave art — let them travel, and their stylistic conventions repeat across thousands of kilometers, implying shared symbolic codes." },
  { id: "microliths", name: "Microliths", era: "upper-paleo", category: "tools",
    year: "~35 kya", prereqs: ["blade-tech"],
    desc: "Tiny standardized blade segments (1–3 cm) snapped from larger blades and embedded in slotted bone or wood handles to make composite tools. Found from Howieson's Poort (South Africa, ~65 kya) onward, microliths spread globally during the Mesolithic. They are modular: a single broken bit can be swapped without remaking the whole tool, conserving stone and making tool-maintenance far easier." },
  { id: "shamanism", name: "Shamanism", era: "upper-paleo", category: "social",
    year: "~30 kya", prereqs: ["cave-art", "burial"],
    desc: "Ritual specialists believed to mediate between the living and a spirit world through trance, dance, costume, music, and ingested compounds. Shamanic motifs — therianthropes, animal transformation, hand stencils — recur in cave art across Europe, southern Africa, and Australia. The shaman is the first identifiable religious profession and a likely model for later priests, prophets, and healers." },
  { id: "trade-networks", name: "Long-Distance Trade", era: "upper-paleo", category: "economy",
    year: "~30 kya", prereqs: ["figurines", "shell-beads"],
    desc: "Movement of obsidian, marine shell, ochre, ivory, and amber across hundreds of kilometers, sometimes across mountain ranges or arms of sea. By ~30 kya, Aurignacian sites in central Europe contain Mediterranean shell ornaments. Trade implies durable kin and alliance ties between groups: information, mates, and innovations travel along the same routes as the goods, and the networks themselves become the substrate for later civilizations." },
  { id: "atlatl", name: "Spear-Thrower (Atlatl)", era: "upper-paleo", category: "weapons",
    year: "~30 kya", prereqs: ["composite-spear"],
    desc: "A short stick with a hooked end that effectively lengthens the throwing arm, doubling dart range and kinetic energy at impact. Made of bone, antler, or wood and often elaborately carved, atlatls appear by ~30 kya across Europe and persist until the bow displaces them. Inuit and Aztec used them historically, the latter against Spanish armor with surprising effect at short range." },
  { id: "lunar-tally", name: "Lunar Calendar", era: "upper-paleo", category: "knowledge",
    year: "~30 kya", prereqs: ["tally-bones"],
    desc: "Bones marked with sequences of notches that match lunar phase counts (29 or 30 marks per cycle, often grouped). The Blanchard bone (Dordogne, ~30 kya) and several Ishango-style artifacts have been interpreted as lunar calendars by archaeologists like Alexander Marshack. Whether or not specific examples are calendars, regular tracking of the moon by mobile foragers is the bedrock of all later astronomy and timekeeping." },
  { id: "harpoon", name: "Barbed Harpoon", era: "upper-paleo", category: "weapons",
    year: "~25 kya", prereqs: ["bone-tools"],
    desc: "Bone or antler points carved with backward-pointing barbs, often with a detachable head and a line, used to take fish, seals, and large birds. The Katanda harpoons (DR Congo, ~90 kya) push the form back surprisingly early. Barbs prevent the prey from escaping after being struck, and detachable heads mean a thrashing animal can't snap the shaft — a meaningful efficiency gain in fishing and aquatic hunting." },

  // ─── Mesolithic ────────────────────────────────────────────────
  { id: "dog", name: "Dog Domestication", era: "mesolithic", category: "subsistence",
    year: "~15 kya", prereqs: ["bone-tools"],
    desc: "Wolves selectively bred toward tameness, smaller size, and reduced fear of humans, becoming hunting partners, sentries, and camp companions. Genetic and archaeological evidence (Bonn-Oberkassel burial, Germany, ~14 kya; Goyet Cave, Belgium, possibly ~36 kya) place domestication in the Late Pleistocene, making the dog the only species domesticated before agriculture. The relationship transformed both species: human hunters with dogs are dramatically more effective, and dogs co-evolved with cooked-food digestion." },
  { id: "ground-stone", name: "Ground Stone Tools", era: "mesolithic", category: "tools",
    year: "~13 kya", prereqs: ["microliths"],
    desc: "Pecked and ground stone tools — celts, axes, mortars, palettes — produced by abrasion against another stone with sand and water rather than by chipping. Slower to make than knapped tools but tougher and more impact-resistant, ground-stone axes can fell large trees and break up sod. Australian Aboriginal sites push the technique back to ~35 kya, but it becomes pervasive only with the Mesolithic shift toward woodland exploitation and clearance." },
  { id: "bow-arrow", name: "Bow and Arrow", era: "mesolithic", category: "weapons",
    year: "~12 kya", prereqs: ["atlatl", "microliths"],
    desc: "A flexible stave (yew, bamboo, sinew-backed wood) storing elastic energy released through a string into a feathered arrow. Earliest direct arrowheads come from Sibudu Cave (~64 kya, South Africa) but bows become widespread only by the late Pleistocene. Compared to atlatl darts, arrows are quieter, faster to nock and release, more accurate at distance, and easier to carry in numbers — transforming both hunting and human conflict." },
  { id: "spun-fiber-mat", name: "Mat Weaving", era: "mesolithic", category: "tools",
    year: "~12 kya", prereqs: ["spun-fiber"],
    desc: "Plaited grass, reed, and bast mats used as floor covers, sleeping pads, sail-cloth, and roofing under thatch. Mats were the first textile architecture: they reuse the cordage technology of the Upper Paleolithic to enclose space. Imprints in clay at Pavlovian sites (~27 kya) and surviving Mesolithic finds at Antrea (Finland) show plaiting was already routine before pottery and weaving emerged." },
  { id: "basketry", name: "Basketry", era: "mesolithic", category: "tools",
    year: "~12 kya", prereqs: ["spun-fiber"],
    desc: "Plaited containers, traps, and cradles woven from willow, reed, and bark. Basketry is older than pottery, lighter than wood, and far more portable than stone vessels. It enables food storage and transport, fish traps, infant carriers, and (with pitch lining) even water-tight containers. Pre-pottery Neolithic sites and Mesolithic camps across Eurasia and the Americas yield basket impressions in dried mud as the earliest indirect evidence." },
  { id: "semi-sedentism", name: "Semi-Sedentary Camps", era: "mesolithic", category: "shelter",
    year: "~12 kya", prereqs: ["shellfishing"],
    desc: "Year-round or strongly seasonal occupation of base camps near unusually rich resources — salmon runs, oak forests, shellfish coasts — that let foragers stay put without yet farming. Natufian villages in the Levant (12.5–9.7 kya) had stone-walled houses, storage pits, and burials, all before agriculture. Semi-sedentism enables population growth, accumulation of heavy goods (grindstones, pottery), and the social institutions that make full villages possible." },
  { id: "mortar-pestle", name: "Mortar & Pestle", era: "mesolithic", category: "tools",
    year: "~12 kya", prereqs: ["ground-stone"],
    desc: "Paired stone vessels for crushing and grinding nuts, seeds, pigments, and medicines. Bedrock mortars in Natufian sites and portable basalt sets across Mesolithic Europe show how grinding became routine before agriculture. Many wild seeds (acorns, wild barley) need processing to be edible at scale, and the mortar-pestle is the bridge from gathered food to staple food. The same form persists in pharmacies and kitchens today." },
  { id: "sickle-flint", name: "Flint Sickle", era: "mesolithic", category: "subsistence",
    year: "~12 kya", prereqs: ["microliths"],
    desc: "Curved bone or wooden hafts inset with sharp flint blades, used to harvest stands of wild cereals while their grains were still on the stalk. Natufian sickles (~12 kya, Levant) show characteristic sickle-gloss on the cutting edges from silica polishing. Harvesting wild grasses with sickles unintentionally selects for plants that don't shatter — the first step toward domesticated wheat and barley, well before any deliberate cultivation." },
  { id: "fishing-net", name: "Fishing Nets", era: "mesolithic", category: "subsistence",
    year: "~10 kya", prereqs: ["harpoon", "spun-fiber"],
    desc: "Knotted plant-fiber nets and seines that capture fish in volume rather than one at a time. Surviving Mesolithic nets at Antrea (Finland, ~10 kya) and net-weights at Magnitnaya (Russia) show the technology was established. Mass capture turns fishing from opportunistic activity into a reliable food source supporting denser, more sedentary populations along productive rivers and coasts." },
  { id: "fish-weir", name: "Fish Weirs", era: "mesolithic", category: "subsistence",
    year: "~10 kya", prereqs: ["basketry", "fishing-net"],
    desc: "Stone or wattle barriers across tidal flats, stream mouths, or shoals that funnel fish into traps as the tide drops or the current pushes them. Submerged Mesolithic weirs survive in Europe (Maglemose) and pre-contact North America. A weir is essentially industrial-scale fishing without nets, requiring no daily attention — a labor-saving technology that allowed semi-sedentary people to extract huge calorie surpluses." },
  { id: "canoe", name: "Dugout Canoe", era: "mesolithic", category: "transport",
    year: "~10 kya", prereqs: ["rafts"],
    desc: "Hollowed-out logs, often shaped by controlled burning and adzing, providing reliable transport on rivers and lakes. The Pesse canoe (Netherlands, ~10 kya) is the oldest known. Canoes opened up inland waterways for fishing, hunting, and trade and are far easier to handle than rafts. Where they evolved further — outrigger canoes in Oceania, birch-bark canoes in North America — they became long-distance vehicles." },
  { id: "snowshoe-ski", name: "Snowshoes & Skis", era: "mesolithic", category: "transport",
    year: "~10 kya", prereqs: ["basketry", "hide-clothing"],
    desc: "Wood and sinew snowshoes (broad mesh distributing weight) and proto-skis (narrow planks for gliding) that opened northern boreal and tundra zones to sustained winter travel. The Vis 1 ski fragment (Russia, ~8 kya) is the oldest surviving ski. Without these, hunting in deep snow is impossibly tiring; with them, mobility through northern winters becomes routine and hunting parties can pursue elk and reindeer year-round." },

  // ─── Neolithic ─────────────────────────────────────────────────
  { id: "plant-cultivation", name: "Plant Cultivation", era: "neolithic", category: "subsistence",
    year: "~11 kya", prereqs: ["basketry", "semi-sedentism", "sickle-flint"],
    desc: "Deliberate sowing, weeding, and harvesting of wild cereals — eventually domesticated through unconscious selection for non-shattering rachis and larger grain. The earliest cultivation appears in the Levantine 'Fertile Crescent' (PPNA Jericho, ~11 kya) with emmer, einkorn, barley, and pulses, with independent origins in China (rice, millet ~10 kya), Mesoamerica (maize ~9 kya), and the Andes (potato, quinoa). The shift commits a society to staying near its fields and is the opening move of the Agricultural Revolution." },
  { id: "animal-domestication", name: "Animal Domestication", era: "neolithic", category: "subsistence",
    year: "~10.5 kya", prereqs: ["dog"],
    desc: "Selective breeding and herding of sheep, goats, pigs, cattle, and later equids. Sheep and goats were the first livestock (Zagros foothills, ~10.5 kya), valued initially for meat, then increasingly for milk, wool, and traction. Domesticated animals walking calories — they convert grass and crop residues humans can't eat into protein, fat, hides, and labor — and reorganized social structures around herd ownership, transhumance, and pastoralism." },
  { id: "polished-stone", name: "Polished Stone Axes", era: "neolithic", category: "tools",
    year: "~10 kya", prereqs: ["ground-stone"],
    desc: "Ground and polished stone axes — typically of jadeite, basalt, greenstone — durable enough to fell mature trees and clear forest. Compared to chipped axes they hold an edge longer, resist shattering on impact, and can be re-sharpened. Polished axes from sources like Mont Viso (Italy) and the Langdale axe quarries (England) traveled hundreds of kilometers as prestige goods, and the labor of clearing forest with them is what made permanent farming possible across temperate Eurasia." },
  { id: "pottery", name: "Pottery", era: "neolithic", category: "tools",
    year: "~10 kya", prereqs: ["cooking", "basketry", "water-flask"],
    desc: "Fired clay vessels for cooking, fermentation, water carriage, and grain storage. Pottery in East Asia (Xianrendong, China, ~20 kya) actually predates agriculture by millennia, though it explodes in the Neolithic with sedentary villages. Firing chemically transforms clay into a hard, watertight ceramic and requires controlled temperatures around 600–900°C — the same pyrotechnical knowledge that later enables metallurgy and glass-making." },
  { id: "village", name: "Permanent Villages", era: "neolithic", category: "shelter",
    year: "~10 kya", prereqs: ["semi-sedentism", "plant-cultivation", "windbreaks"],
    desc: "Permanent settlements of mudbrick or timber houses, sometimes thousands of inhabitants, with shared walls, lanes, storage, and ritual buildings. Jericho (~10 kya) had stone walls and a tower; Çatalhöyük (~9 kya, Anatolia) housed thousands in densely packed rooftop-entry homes. Villages concentrate population, generate surplus, and create the conditions for specialization, inheritance, and inequality that all later social complexity depends on." },
  { id: "adobe-brick", name: "Adobe Brick", era: "neolithic", category: "shelter",
    year: "~10 kya", prereqs: ["pottery", "village"],
    desc: "Sun-dried mud bricks of clay, sand, water, and chopped straw — uniform, stackable, repairable, and produced from the local soil. Adobe construction at Jericho and Çatalhöyük lets buildings rise in regular geometric forms and stand for centuries. The technique persists from the Neolithic to the modern American Southwest and Sahel, scaling up to entire cities and surviving wherever the climate is dry enough to keep the bricks from melting back into earth." },
  { id: "megaliths", name: "Megalithic Monuments", era: "neolithic", category: "social",
    year: "~11 kya", prereqs: ["trade-networks"],
    desc: "Large standing stones arranged in alignments, circles, dolmens, and passage tombs, often astronomically oriented. Göbekli Tepe (Turkey, ~11 kya) astonishingly predates farming, was built by hunter-gatherers, and proves that monumental ritual architecture could precede agriculture. Stonehenge (~5 kya, England), Carnac (Brittany), Newgrange (Ireland) show the form continuing through the Neolithic. The labor required implies large-scale cooperation and shared cosmology." },
  { id: "ritual-religion", name: "Organized Religion", era: "neolithic", category: "social",
    year: "~10 kya", prereqs: ["burial", "megaliths", "shamanism"],
    desc: "Standardized myths, calendars, and ritual specialists serving settled communities — the institutional successor of shamanism, oriented around fixed shrines, agricultural cycles, ancestors, and named deities. Çatalhöyük's bull shrines, Göbekli Tepe's animal pillars, and Neolithic figurine traditions show religion organizing the year and the village. Religion both legitimated emerging hierarchies and stored cosmological knowledge in transmissible form." },
  { id: "pottery-wheel", name: "Pottery Wheel", era: "neolithic", category: "tools",
    year: "~6 kya", prereqs: ["pottery"],
    desc: "A horizontally rotating disc that lets a potter shape symmetric vessels at speed using centripetal force and skilled hands. Slow tournettes appear in Mesopotamia by ~6 kya; fast wheels by ~3 kya. The pottery wheel is the first deliberate use of continuous rotational motion as a productive technology — the conceptual ancestor of the spoked wheel, the lathe, and ultimately every spinning machine in the Industrial Revolution." },
  { id: "weaving", name: "Loom Weaving", era: "neolithic", category: "tools",
    year: "~9 kya", prereqs: ["basketry", "animal-domestication", "needles"],
    desc: "Warp-and-weft textiles produced on a loom — initially the warp-weighted vertical loom or the back-strap horizontal loom — using flax, then wool, then cotton. Loom weights and impressed clay show weaving by ~9 kya across the Near East. Cloth replaces hides as the standard garment for most people, can be tailored more precisely, dyed, and traded over long distances, and becomes the most important non-food product of pre-industrial societies." },
  { id: "domesticated-flax", name: "Flax & Cotton", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["plant-cultivation", "weaving"],
    desc: "Linum usitatissimum cultivated for both seed (linseed oil) and fiber (linen). Domesticated flax appears in the Levant by ~9 kya. Cotton (Gossypium) was independently domesticated in the Indus Valley and Mesoamerica. These fiber crops free clothing from the supply of animals and hides, and become the basis for textile-driven economies from Pharaonic Egypt to Mughal India to industrial Britain." },
  { id: "irrigation", name: "Irrigation", era: "neolithic", category: "subsistence",
    year: "~8 kya", prereqs: ["village", "plant-cultivation"],
    desc: "Channeled river water diverted to crops via canals, ditches, basins, and gates — multiplying yields in arid floodplains. Mesopotamian and Egyptian large-scale irrigation appears by ~7 kya; the Nile's annual flood was managed with basin irrigation that left silt behind. Irrigation requires coordination beyond a single household, contributes to the rise of administrative states, and is sometimes argued (Wittfogel's 'hydraulic hypothesis') to have driven early state formation directly." },
  { id: "plow-ard", name: "Ard Plow", era: "neolithic", category: "subsistence",
    year: "~6 kya", prereqs: ["animal-domestication", "polished-stone", "digging-stick"],
    desc: "Animal-drawn scratch plow that breaks soil far faster than a digging stick, opening heavy land that hand cultivation can't handle. Sumerian and Egyptian images show ards in routine use by ~5 kya. The ard doesn't turn the soil over (a moldboard plow does that, much later) but its furrow is enough for cereal seeding. Pairing ards with oxen also reorganizes farming around livestock-owning households." },
  { id: "millstone", name: "Millstone", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["ground-stone", "plant-cultivation"],
    desc: "Paired flat (saddle quern) or rotary stones that grind grain into flour, a labor-intensive but unavoidable step in cereal-based diets. Saddle querns are routine in PPNB sites; rotary querns become widespread by the Iron Age. Daily flour for bread and porridge is what makes grain a staple, and millstones — from a few kilograms in Neolithic homes to tonnes in Roman water-mills — are the workhorse infrastructure of pre-industrial nutrition." },
  { id: "fermentation-brewing", name: "Fermentation & Brewing", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["pottery", "plant-cultivation"],
    desc: "Controlled microbial transformation of grain, fruit, milk, and vegetables into beer, mead, wine, cheese, yogurt, and leavened bread. The earliest archaeological brewing residues appear at Göbekli Tepe and PPNA Levantine sites. Fermentation preserves perishable harvests, makes calories shelf-stable, and produces alcohol — both a social lubricant and a ritual substance. Some archaeologists argue beer rather than bread was the original driver of cereal cultivation." },
  { id: "granary", name: "Granaries & Storage", era: "neolithic", category: "subsistence",
    year: "~9 kya", prereqs: ["plant-cultivation", "pottery"],
    desc: "Dedicated structures — pits, silos, raised platforms, mudbrick rooms — for surplus grain. Mesolithic Natufian storage features and PPNA Jordan Valley granaries (~10 kya) actually predate full agriculture. Surplus storage means a population can survive lean years and feed non-farming specialists; it also creates the first portable wealth and the first thing worth raiding, contributing to inequality and warfare." },
  { id: "sledge-runner", name: "Sledge", era: "neolithic", category: "transport",
    year: "~8 kya", prereqs: ["polished-stone"],
    desc: "Wood or whalebone runners under a load-platform, dragged over snow, mud, log rollers, or grass. Sledges are older and simpler than wheeled vehicles and remained important wherever snow or rough terrain made wheels impractical (Arctic, Alps, log skids). They are also the form on which the wheel was likely first added — Bronean log rollers under sledges naturally evolve toward the wheeled cart." },
  { id: "sail-primitive", name: "Square Sail", era: "neolithic", category: "transport",
    year: "~7 kya", prereqs: ["canoe", "spun-fiber-mat"],
    desc: "Reed-mat or linen square sails on a single mast above a canoe or raft, capturing wind to supplement paddling. Earliest evidence comes from Predynastic Egyptian Nile boats (~6 kya). A square sail can only run before the wind, but on long rivers like the Nile that's enough to revolutionize transport — heavy cargo can move upstream with a fair wind and downstream with the current, halving labor in both directions." },
  { id: "copper-smelting", name: "Copper Smelting", era: "neolithic", category: "tools",
    year: "~7 kya", prereqs: ["pottery", "polished-stone"],
    desc: "Reducing copper ore (malachite, azurite, native copper) in clay-lined furnaces with charcoal at temperatures around 1100°C, then casting into ingots or shapes. Earliest smelted copper appears at Çatalhöyük and Tal-i Iblis (Iran, ~6.5 kya), but the technology becomes routine in the Chalcolithic. Copper is the first metal humans extracted at scale — too soft for serious tools alone, but the gateway to bronze and to the broader pyrotechnical knowledge underlying all later metallurgy." },
  { id: "mathematics-counting", name: "Counting Systems", era: "neolithic", category: "knowledge",
    year: "~9 kya", prereqs: ["tally-bones", "granary"],
    desc: "Standardized numeral systems tied to commodity accounting — sheep, jars of grain, days. Mesopotamian sexagesimal counting and Egyptian decimal numerals both develop alongside writing in the late 4th millennium BCE. Once numbers are abstract symbols rather than tally marks, they can be added, multiplied, and recorded in transactions and contracts — the basis of all later mathematics, accounting, and astronomy." },
  { id: "proto-writing-tokens", name: "Proto-Writing", era: "neolithic", category: "communication",
    year: "~8 kya", prereqs: ["mathematics-counting", "granary"],
    desc: "Clay tokens of distinct shapes (cones, spheres, discs) representing commodities, sealed inside hollow clay 'bullae' as accounting records. Sumerian sites like Uruk show the system in use by ~4 kya, and the impressions of tokens on bulla surfaces are the direct ancestor of cuneiform pictograms. Writing was thus born from accounting — bureaucratic memory long before it carried literature." },

  // ─── Bronze Age ────────────────────────────────────────────────
  { id: "bronze-metallurgy", name: "Bronze Metallurgy", era: "bronze", category: "tools",
    year: "~3300 BCE", prereqs: ["copper-smelting"],
    desc: "Tin-copper alloy (typically ~10% tin) producing a metal far harder, more castable, and more durable than copper alone. Earliest at Vinča/Pločnik in the Balkans (~7 kya) and Sumer (~5.3 kya), bronze defines an age and reshapes warfare, agriculture, and trade. Because tin and copper rarely occur together, bronze depends on long-distance trade — Cornish tin and Cypriot copper both crossed the Mediterranean — and links far-flung regions into a single technological economy." },
  { id: "bronze-tools", name: "Bronze Tools", era: "bronze", category: "tools",
    year: "~3200 BCE", prereqs: ["bronze-metallurgy"],
    desc: "Cast and hammered bronze axes, chisels, saws, sickles, and razors — sharper, harder, and more durable than stone or copper, and re-castable when worn or broken. Adoption transformed agriculture (better plowshares, sickles), construction (saws and chisels), and crafts (engraving tools, fine metalwork). The fact that broken bronze can be melted down and reused is itself revolutionary: durable wealth could be repurposed in ways stone and bone never permitted." },
  { id: "bronze-weapons", name: "Bronze Weapons", era: "bronze", category: "weapons",
    year: "~3200 BCE", prereqs: ["bronze-metallurgy", "composite-spear"],
    desc: "Cast bronze swords, daggers, spear points, axes, and armor scales. Bronze swords appear in the Aegean and Levant by ~3300 BCE and reach mature long-sword form by ~1600 BCE (Naue II). Stone weapons become obsolete on the battlefield, and the high cost of bronze (with imported tin) ties military power to ruling-class control of trade routes — a key dynamic of all Bronze Age civilizations from Mycenae to Shang China." },
  { id: "iron-meteoric", name: "Meteoric Iron", era: "bronze", category: "tools",
    year: "~3200 BCE", prereqs: ["bronze-metallurgy"],
    desc: "Cold-worked iron from meteorites, recognizable by its high nickel content. The dagger of Tutankhamun (~1330 BCE) is the most famous example — its nickel signature confirms meteoric origin. Found in royal Mesopotamian, Egyptian, Chinese, and Inuit contexts as rare and prestigious objects, meteoric iron taught Bronze Age smiths that the metal could be worked at all, paving the way for the smelted iron that would eventually displace bronze entirely." },
  { id: "spoked-wheel", name: "Spoked Wheel", era: "bronze", category: "transport",
    year: "~3500 BCE", prereqs: ["pottery-wheel", "sledge-runner"],
    desc: "Light wheels built from a hub, spokes, and a bent or jointed rim, replacing solid disc wheels and dramatically reducing the weight of a cart while preserving strength. Earliest examples appear with Andronovo and Sintashta cultures of the Eurasian steppe (~2000 BCE). Spoked wheels are the precondition for fast vehicles — chariots, light carts — and remained the dominant wheel form until the bicycle and automobile redesigned them in the 19th century." },
  { id: "wheeled-cart", name: "Wheeled Cart", era: "bronze", category: "transport",
    year: "~3500 BCE", prereqs: ["spoked-wheel", "animal-domestication"],
    desc: "Solid-wheel and later spoked-wheel carts pulled by oxen or donkeys, carrying loads from one to several tons that no human porter could move. Earliest depictions on Sumerian Standard of Ur and pictograms (~3500 BCE), with wooden wheels surviving from Slovenia at ~3200 BCE. Carts increase land freight throughput by an order of magnitude and reorganize where settlements can be — distance from a navigable river suddenly matters far less." },
  { id: "horse-domestication", name: "Horse Domestication", era: "bronze", category: "transport",
    year: "~3500 BCE", prereqs: ["animal-domestication"],
    desc: "Tamed Eurasian steppe horses, beginning with the Botai culture of Kazakhstan around 5500 BCE for milk and meat, and reaching mounted-warrior form by ~2000 BCE with Sintashta. Horses transform speed, range, and traction: a mounted scout covers in one day what a foot scout does in three; cavalry and chariot warfare become possible. Indo-European language expansion, steppe nomadism, and the Silk Road are all downstream of domesticated horses." },
  { id: "chariot", name: "War Chariot", era: "bronze", category: "weapons",
    year: "~2000 BCE", prereqs: ["wheeled-cart", "horse-domestication", "bronze-metallurgy"],
    desc: "Two-horse fighting platforms with archer and driver, built around a light spoked-wheel frame. Sintashta chariots appear ~2000 BCE; by 1700 BCE they dominate battlefields from Mycenae to Shang China and the Hyksos use them to overrun Egypt. The chariot is the first integrated weapons system: vehicle, motive power, and ranged weapon combined. Their dominance lasts until cavalry on stronger, larger horses with proper saddles displaces them in the Iron Age." },
  { id: "composite-bow", name: "Composite Bow", era: "bronze", category: "weapons",
    year: "~2000 BCE", prereqs: ["bow-arrow", "hafting"],
    desc: "Layered horn, wood, and sinew bow producing far more energy per inch than a self-bow, allowing a short weapon (~1 m) to outperform a long self-bow. Used by Sumerians, Hittites, Scythians, Mongols, Manchus, and Comanche, the composite bow is the canonical horse-archer weapon — short enough to fire from a galloping horse, powerful enough to pierce armor at 100 m. Its construction takes a year and requires master-level woodwork and gluing." },
  { id: "city-state", name: "City-State", era: "bronze", category: "economy",
    year: "~3500 BCE", prereqs: ["village", "irrigation"],
    desc: "Walled urban centers with surrounding farmland, governed by a temple-palace elite, with populations of 10,000–80,000. Sumerian Uruk (~3500 BCE), then Lagash, Ur, Ebla, and later Greek poleis and Mesoamerican capitals. The city-state is the first political form to combine permanent administration, monumental architecture, social stratification, professional priesthood, and long-distance trade — every later civilization grew out of or in reaction to it." },
  { id: "code-of-law", name: "Codified Law", era: "bronze", category: "economy",
    year: "~2100 BCE", prereqs: ["city-state", "proto-writing-tokens"],
    desc: "Written legal codes — Ur-Nammu (~2100 BCE), Lipit-Ishtar, Hammurabi (~1750 BCE) — that publicly fix penalties, contracts, family law, and commercial rules. Public, predictable rules replace personal arbitration and royal whim, and the law's monumental display (Hammurabi's stele was eight feet tall) advertises the king as a guarantor of justice. The codes are also the first administrative documents to claim legitimacy from divine sanction." },
  { id: "cuneiform", name: "Cuneiform", era: "bronze", category: "communication",
    year: "~3200 BCE", prereqs: ["proto-writing-tokens", "proto-language"],
    desc: "Wedge-shaped script impressed into clay with a cut reed, originating in Sumerian Uruk around 3200 BCE for accounting and adapted to record contracts, letters, literature, and administrative archives. Hundreds of thousands of tablets survive, baked into permanence by accidental fires that destroyed cities. Cuneiform was used for over 3000 years across Sumerian, Akkadian, Babylonian, Assyrian, Hittite, and Old Persian — far longer than the Latin alphabet has existed." },
  { id: "hieroglyphics", name: "Hieroglyphics", era: "bronze", category: "communication",
    year: "~3200 BCE", prereqs: ["proto-writing-tokens"],
    desc: "Egyptian pictographic and phonetic script, carved monumentally on stone and inked on papyrus, in use from ~3200 BCE through ~400 CE. The script combines ideograms, syllabic phonograms, and determinatives, with a hieratic cursive variant for daily writing. Decipherment by Champollion in 1822 using the Rosetta Stone reopened three millennia of Egyptian history that had been opaque since the Roman closure of the temples." },
  { id: "alphabet-phoenician", name: "Phoenician Alphabet", era: "bronze", category: "communication",
    year: "~1200 BCE", prereqs: ["cuneiform", "hieroglyphics"],
    desc: "Twenty-two consonant letters representing sounds rather than concepts, devised by Levantine traders around 1200 BCE. Where cuneiform required years of training, the alphabet could be learned in weeks, democratizing literacy. Greek, Aramaic, Hebrew, Arabic, and ultimately Latin and Cyrillic all descend from it, making the Phoenician alphabet the common ancestor of every Western and Near Eastern script in current use." },
  { id: "abacus", name: "Abacus", era: "bronze", category: "knowledge",
    year: "~2700 BCE", prereqs: ["mathematics-counting"],
    desc: "Bead-and-rod calculating frames that mechanize addition, subtraction, multiplication, and division by manipulating columns representing place values. Sumerian sand abaci (~2700 BCE) gave way to Roman bronze abaci, the Chinese suanpan, and the Japanese soroban. A skilled abacus operator can outpace early electronic calculators, and the device remains in use in some East Asian education systems for teaching numerical intuition." },
  { id: "mathematics-arithmetic", name: "Arithmetic", era: "bronze", category: "knowledge",
    year: "~2000 BCE", prereqs: ["cuneiform", "mathematics-counting", "abacus"],
    desc: "Babylonian sexagesimal arithmetic — including fractions, square roots, quadratic equation solutions, and tables of reciprocals — recorded on clay tablets like Plimpton 322. Working in base 60 (which has many divisors) gave Mesopotamian astronomers and surveyors enormous practical power, and that base persists in our division of hours, minutes, and degrees. Egyptian arithmetic developed in parallel with the Rhind and Moscow papyri." },
  { id: "astronomy-observation", name: "Astronomy", era: "bronze", category: "knowledge",
    year: "~1800 BCE", prereqs: ["lunar-tally", "mathematics-arithmetic"],
    desc: "Systematic recording of planetary motion, lunar phases, eclipses, and stellar risings. Babylonian tablets like Enuma Anu Enlil and MUL.APIN catalogue centuries of observations and use them to predict eclipses with remarkable accuracy. The same data eventually fed into Greek mathematical astronomy and Ptolemy's Almagest, making Babylonian record-keeping the empirical bedrock of all later positional astronomy." },
  { id: "solar-calendar", name: "Solar Calendar", era: "bronze", category: "knowledge",
    year: "~3000 BCE", prereqs: [],
    desc: "365-day calendar tracking the solar year, divided into 12 months of 30 days plus 5 epagomenal days. The Egyptian civil calendar — likely derived from observing the heliacal rising of Sirius coinciding with the Nile flood — was the first solar calendar in continuous use (from ~3000 BCE). Variants spread through Roman administration as the Julian calendar and survive, with Gregorian refinements, as the global standard today." },
  { id: "monumental-architecture", name: "Monumental Architecture", era: "bronze", category: "shelter",
    year: "~3000 BCE", prereqs: ["megaliths", "city-state", "adobe-brick"],
    desc: "Temples and palaces built with planned engineering, mass labor, and professional architects. Sumerian Eanna at Uruk, Egyptian Old Kingdom mortuary complexes, Hittite Hattusa, and Minoan Knossos all share the formula: monumental scale, geometric layout, costly imported materials, and decorative programs that legitimize ruling power. Such buildings concentrate craft specialists and engineering knowledge that ripples outward into every other domain." },
  { id: "pyramid-ziggurat", name: "Pyramids & Ziggurats", era: "bronze", category: "shelter",
    year: "~2600 BCE", prereqs: ["monumental-architecture"],
    desc: "Stepped or smooth-sided masonry mountains. Egyptian pyramids — Djoser's Step Pyramid (~2600 BCE) through the Great Pyramid of Khufu (~2560 BCE) — house royal burials. Mesopotamian ziggurats like Ur and the Tower of Babel's prototype Etemenanki are temple platforms reaching toward the gods. The labor and logistics required (Khufu's pyramid weighs 6 million tons) is testimony both to engineering and to political organization." },
  { id: "glass-making", name: "Glass Making", era: "bronze", category: "tools",
    year: "~3500 BCE", prereqs: ["pottery", "copper-smelting"],
    desc: "Fused silica beads, vessels, and inlays produced by heating sand, soda ash, and lime to ~1500°C. Earliest at Mesopotamian and Egyptian sites by ~3500 BCE, with mature core-formed vessels by ~1500 BCE. Glass becomes a major luxury trade good across the eastern Mediterranean. The pyrotechnical know-how — high temperatures and flux chemistry — feeds directly into the development of glazes, enamels, and eventually mirrors and lenses." },
  { id: "silver-gold-metallurgy", name: "Precious Metals", era: "bronze", category: "tools",
    year: "~3000 BCE", prereqs: ["copper-smelting"],
    desc: "Refining and working silver, gold, and electrum (their natural alloy) by panning, cupellation, casting, and granulation. The Royal Tombs of Ur (~2500 BCE) and the Treasure of Priam at Troy show extraordinary craftsmanship. Precious metals double as ornament and store of value: rings, bracelets, and ingots circulate as proto-money long before stamped coinage, and gold-and-silver tribute organizes much of Bronze Age long-distance trade." },
  { id: "olive-wine", name: "Olive Oil & Wine", era: "bronze", category: "subsistence",
    year: "~3000 BCE", prereqs: ["plant-cultivation", "pottery"],
    desc: "Tree-crop horticulture (olives) and viticulture (grapevines) producing transportable, durable, calorie-dense oil and wine. Both crops are perennials with multi-year payback periods, requiring secure landownership. The Mediterranean olive-oil-and-wine economy stretches from Iberia to the Levant by the Late Bronze Age, with shipwrecks like Uluburun (~1300 BCE) carrying amphorae of both. Olives and wine become defining markers of Mediterranean culture for three thousand years." },
  { id: "linen-textile", name: "Linen Textiles", era: "bronze", category: "tools",
    year: "~3000 BCE", prereqs: ["weaving", "domesticated-flax"],
    desc: "Bleached and woven flax fabrics for clothing, sails, ropes, bandages, and trade. Egypt's Nile floodplain was ideal for flax, and Egyptian linen (some of it almost transparently fine) was the premier textile of the ancient world, traded throughout the Mediterranean. Mummy wrappings preserve thousands of meters of it. Linen also carried Greek and Roman elites' togas and chitons before cotton arrived from the East." },
  { id: "standing-army", name: "Standing Army", era: "bronze", category: "weapons",
    year: "~2300 BCE", prereqs: ["city-state", "bronze-weapons"],
    desc: "Full-time professional soldiers paid by the state, replacing seasonal levies of farmer-citizens. Sargon of Akkad's army (~2300 BCE) is the prototype; later New Kingdom Egypt, Assyria, and the Achaemenid Empire institutionalize the form. Standing armies are loyal to whoever pays them rather than to a clan or region, enabling much larger and longer campaigns — and giving rulers a coercive instrument that local nobles cannot match." },
  { id: "maritime-trade", name: "Maritime Trade", era: "bronze", category: "economy",
    year: "~3000 BCE", prereqs: ["sail-primitive", "city-state"],
    desc: "Routine cargo shipping across seas: Bronze Age tin and copper from Cornwall and Cyprus, lapis lazuli from Afghanistan, ivory from Africa, amber from the Baltic. The Uluburun shipwreck (~1300 BCE) carried goods from at least seven distinct regions. Maritime trade lets Bronze Age polities import what their geology lacks (Egypt had little timber; Mesopotamia had little stone) and bound the Mediterranean and Indian Ocean basins into integrated economic systems." },
  { id: "galley-ship", name: "Galley", era: "bronze", category: "transport",
    year: "~3000 BCE", prereqs: ["sail-primitive", "bronze-tools"],
    desc: "Oared and sailed warships and traders, often multi-decked, with rams or platforms for boarding. Phoenician galleys became the dominant Mediterranean ship by ~1000 BCE, sailed by professional crews coordinated by drum and oarmaster. The galley's weak point — vulnerability to weather, dependence on shore for water — also defined its operational geography, anchoring naval power in coastal city-states." },
  { id: "pulley-lever", name: "Pulley & Lever", era: "bronze", category: "tools",
    year: "~2000 BCE", prereqs: ["monumental-architecture", "mathematics-arithmetic"],
    desc: "Simple machines (lever, pulley, inclined plane, wedge, screw, wheel-and-axle) that multiply human and animal force. Egyptian and Mesopotamian construction relied on levers and inclined planes; pulleys and compound block-and-tackle systems likely came later. Archimedes formalized the underlying mechanics in Hellenistic times, but the empirical use of these tools for moving stone and water is millennia older and is the foundation of all later mechanical engineering." },
  { id: "proto-medicine", name: "Temple Medicine", era: "bronze", category: "medicine",
    year: "~1800 BCE", prereqs: ["ritual-religion", "cuneiform"],
    desc: "Mesopotamian Diagnostic Handbook (Esagil-kin-apli, ~1000 BCE) and the Egyptian Edwin Smith Papyrus (~1600 BCE, copying older material) record observed symptoms, prognoses, and treatments — including surgical procedures and dressings. Mixed with ritual and incantation, these texts also contain genuinely empirical medical knowledge: setting fractures, suturing wounds, cataracting eyes. They are the foundation on which later Greek and Islamic medicine consciously built." },
  { id: "trepanation", name: "Trepanation", era: "bronze", category: "medicine",
    year: "~7000 BCE", prereqs: ["polished-stone", "ritual-religion"],
    desc: "Surgical removal of a disc of bone from the skull, performed with flint, obsidian, or bronze tools. Trepanned skulls from the Neolithic onward (Ensisheim, France, ~7 kya; widespread in pre-Columbian Peru) often show healed bone, meaning many patients survived. The procedure may have treated head injuries, intracranial pressure, or culturally interpreted illnesses (epilepsy, possession). It is the earliest attested major surgery anywhere on Earth." },

  // ─── Classical Antiquity ───────────────────────────────────────
  { id: "iron-smelting", name: "Iron Smelting", era: "classical", category: "tools",
    year: "~1200 BCE", prereqs: ["bronze-metallurgy", "glass-making", "iron-meteoric"],
    desc: "Bloomery smelting of iron ore (hematite, magnetite) in clay-and-charcoal furnaces at ~1200°C, producing a spongy 'bloom' that is hammered to expel slag. Hittites likely innovated the technique by ~1500 BCE; it spread after the Bronze Age collapse around 1200 BCE. Iron is far more abundant than tin and copper, so smelting democratized metal: ordinary farmers could afford iron plowshares and edges that previously only elites could equip with bronze." },
  { id: "iron-tools", name: "Iron Tools", era: "classical", category: "tools",
    year: "~1100 BCE", prereqs: ["iron-smelting"],
    desc: "Iron axes, plowshares, sickles, saws, and chisels. Iron's hardness and toughness once carbon-treated outclass bronze, and its low cost (compared to bronze with imported tin) put quality tools in mass-producible reach for the first time. Iron Age agriculture expanded into heavier soils, woodworking accelerated, and craft production multiplied — the population growth from the late Iron Age onward is partly downstream of cheap iron." },
  { id: "iron-weapons", name: "Iron Weapons", era: "classical", category: "weapons",
    year: "~1100 BCE", prereqs: ["iron-smelting", "bronze-weapons"],
    desc: "Iron swords, spear points, javelin tips, and arrowheads. Hoplite phalanx warfare in Greece, the Roman gladius and pilum, and the Han crossbow bolt all depend on cheap iron edges. Iron's affordability ends bronze-age power balances based on tin trade routes and democratizes military service: a peasant levy with iron weapons can fight effectively, which reshapes Greek and Roman political institutions around the citizen-soldier ideal." },
  { id: "steel-bloomery", name: "Bloomery Steel", era: "classical", category: "tools",
    year: "~600 BCE", prereqs: ["iron-smelting"],
    desc: "Carburized iron — bloom worked in a charcoal forge until the surface absorbs carbon — producing steel locally hard enough to hold an edge. Indian wootz steel (from ~600 BCE) and Chinese cast-iron-derived steels are early high-grade examples, traded as ingots throughout the Indian Ocean. Wootz feeds the Damascus steel tradition of Islamic swordsmithing, with characteristic surface patterns from carbide banding." },
  { id: "alphabet-greek", name: "Greek Alphabet", era: "classical", category: "communication",
    year: "~800 BCE", prereqs: ["alphabet-phoenician"],
    desc: "The Phoenician consonant alphabet adapted to write Greek, with vowel signs added (alpha, epsilon, iota, omicron, upsilon) — the first true alphabet representing all phonemes. Adopted ~800 BCE, it carried the Iliad and Odyssey into writing, then philosophy, drama, geometry, and history. Through the Etruscan intermediary it gave rise to Latin, and through Cyril and Methodius to Cyrillic — the parent of every Western and Slavic alphabet." },
  { id: "alphabet-latin", name: "Latin Alphabet", era: "classical", category: "communication",
    year: "~700 BCE", prereqs: ["alphabet-greek"],
    desc: "Roman adaptation of Etruscan and Greek letters, in routine monumental and cursive forms by ~700 BCE. The empire carried it from Spain to Britain to the Levant, where it absorbed local writing traditions. With the addition of J, U, and W in the medieval and early modern periods it became the dominant script of Western Europe, the basis for transcribing dozens of languages worldwide today, and the standard for computing in the ASCII era." },
  { id: "philosophy", name: "Philosophy", era: "classical", category: "knowledge",
    year: "~600 BCE", prereqs: ["alphabet-greek", "mathematics-arithmetic"],
    desc: "Systematic inquiry into being, ethics, knowledge, and the cosmos pursued by argument rather than appeal to authority. Greek thinkers from Thales (~600 BCE) through Socrates, Plato, and Aristotle defined Western philosophy; in parallel, Confucius, Laozi, and the Hundred Schools shaped Chinese thought, while the Buddha and Mahavira reshaped Indian. Philosophy provides the vocabulary in which all later science, theology, and political theory gets argued." },
  { id: "geometry-euclidean", name: "Euclidean Geometry", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["mathematics-arithmetic", "philosophy"],
    desc: "Axiomatic deductive geometry codified in Euclid's Elements (~300 BCE, Alexandria). Thirteen books proceed from five postulates and common notions to thousands of theorems, becoming the model of rigorous reasoning for over two millennia. Euclid's parallel postulate eventually motivates 19th-century non-Euclidean geometries, but his exposition remained the standard introductory mathematics text from antiquity through the 19th century." },
  { id: "zero-numeral", name: "Zero as Numeral", era: "classical", category: "knowledge",
    year: "~500 CE", prereqs: ["philosophy", "mathematics-arithmetic"],
    desc: "Treating zero as a number with arithmetic rules, not just a placeholder. Earlier place-value systems (Babylonian) used a gap or a dot for absence; the Indian Brahmagupta (628 CE) explicitly defines zero's behavior in addition, subtraction, and multiplication and discusses negative numbers. Combined with place-value notation, zero unlocks fast computation and is the conceptual foundation of all modern arithmetic and algebra." },
  { id: "alchemy", name: "Alchemy", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["glass-making", "philosophy"],
    desc: "Hellenistic, Indian, Chinese, and Islamic experimental tradition aimed at transmuting metals (especially into gold), preparing elixirs, and understanding matter. Although its theoretical goals were unattainable, alchemists developed distillation, sublimation, crystallization, acid preparation, and laboratory glassware — the practical infrastructure that, redirected, became modern chemistry. Jabir ibn Hayyan (~800 CE) is sometimes called the father of chemistry for his systematic experimental methods." },
  { id: "coinage", name: "Coinage", era: "classical", category: "economy",
    year: "~700 BCE", prereqs: ["silver-gold-metallurgy", "code-of-law"],
    desc: "Stamped metal money of guaranteed weight and purity. Lydia's electrum coins (~600 BCE) under King Alyattes set the pattern, copied by Ionian Greeks, then by Persia, then by Athens (silver tetradrachm) and Rome (denarius). Coinage standardizes value and accelerates trade by eliminating the need to weigh metal in every transaction. The state's monopoly on minting also becomes a major source of revenue and a tool of political signaling." },
  { id: "democracy", name: "Democracy", era: "classical", category: "economy",
    year: "~500 BCE", prereqs: ["city-state", "code-of-law", "philosophy"],
    desc: "Athenian rule by the assembly (ekklesia) of citizens, with executive offices filled by lot or election. Begun by Cleisthenes' reforms in 508 BCE and elaborated under Pericles, Athenian democracy directly involved every adult male citizen in voting on laws, foreign policy, and judicial decisions. It excluded women, slaves, and foreigners, and was unstable and short-lived, but it set the conceptual benchmark for popular rule that all later democratic theory has worked from." },
  { id: "republic", name: "Republic", era: "classical", category: "economy",
    year: "~500 BCE", prereqs: ["democracy"],
    desc: "Representative government under elected magistrates and a senate, with checks among offices designed to prevent any single official from accumulating tyrannical power. The Roman Republic (509–27 BCE) is the dominant model: consuls, tribunes, censors, dictators, and a senate of patricians shared power. Cicero's writings and the Republic's example shaped the American and French revolutionary constitutions two millennia later." },
  { id: "empire", name: "Empire", era: "classical", category: "economy",
    year: "~550 BCE", prereqs: ["standing-army", "coinage", "code-of-law"],
    desc: "Multi-ethnic territorial states with central administration, professional bureaucracy, standardized law, and a single coinage. The Achaemenid Persian (~550 BCE), Maurya, Han Chinese, and Roman empires each governed tens of millions across continents. Empires built roads, postal systems, and shared currencies that integrated their economies; they also shaped which languages, religions, and legal traditions would dominate later millennia." },
  { id: "roman-law", name: "Roman Law", era: "classical", category: "economy",
    year: "~450 BCE", prereqs: ["code-of-law", "empire"],
    desc: "From the Twelve Tables (~450 BCE) through the Corpus Juris Civilis of Justinian (~530 CE), Roman law systematized contract, property, family, and criminal jurisprudence. Concepts of legal personality, intent, contract formation, and equity were preserved through the Byzantine Empire, recovered by medieval European jurists at Bologna, and form the spine of every continental ('civil law') legal system in use today." },
  { id: "roads-paved", name: "Paved Roads", era: "classical", category: "transport",
    year: "~300 BCE", prereqs: ["empire", "monumental-architecture"],
    desc: "Multi-layered all-weather roads engineered with deep gravel-and-stone foundations, drainage ditches, and milestones. Roman roads totaled over 80,000 km at the empire's peak, with sections like the Appian Way (begun 312 BCE) still passable. The Persian Royal Road predates the Roman by centuries. Paved networks made imperial postal systems, troop movements, and tax collection routine, and the Silk Road's caravan routes integrated Eurasia." },
  { id: "aqueduct", name: "Aqueduct", era: "classical", category: "shelter",
    year: "~700 BCE", prereqs: ["monumental-architecture", "mathematics-arithmetic"],
    desc: "Gravity-fed water channels — partly underground, partly raised on stone arches — carrying potable water tens of kilometers to cities. Rome's aqueducts brought ~1,000,000 cubic meters daily by the 3rd century CE, supplying public fountains, baths, and toilets. The Pont du Gard (France, ~50 CE) and Aqua Claudia are spectacular surviving examples. Cities outgrow local wells and groundwater because of aqueducts, enabling unprecedented urban density." },
  { id: "arch-vault", name: "Arch & Vault", era: "classical", category: "shelter",
    year: "~500 BCE", prereqs: ["monumental-architecture"],
    desc: "Compression-loaded stone arches that span openings without lintels and can be extended into barrel vaults and domes. Etruscan and then Roman builders mastered the form, enabling basilicas, baths, bridges, and the unsupported 43-meter dome of the Pantheon. The structural insight — that radially placed wedge stones (voussoirs) hold each other in place — is the basis of all later masonry construction including Gothic cathedrals." },
  { id: "concrete-roman", name: "Roman Concrete", era: "classical", category: "tools",
    year: "~200 BCE", prereqs: ["aqueduct", "arch-vault"],
    desc: "Pozzolana-lime hydraulic cement that sets even underwater, made by mixing volcanic ash with quicklime and aggregate. Roman concrete (opus caementicium) built the Pantheon dome, harbors at Caesarea, the Colosseum's substructures, and aqueducts. Recent research shows the mix actually self-heals through reaction with water, which is why so much survives. The technology was lost after Rome's fall and only fully matched in the 19th century with Portland cement." },
  { id: "crossbow", name: "Crossbow", era: "classical", category: "weapons",
    year: "~500 BCE", prereqs: ["composite-bow", "iron-tools"],
    desc: "Mechanically drawn bow with a wooden stock, a release trigger, and stored elastic energy from steel or composite limbs. Han Chinese crossbows (~500 BCE) standardized parts and dominated Chinese warfare; medieval European crossbows could pierce plate armor. The crossbow's appeal is that it requires far less training than a longbow and lets a peasant defeat an armored knight, which is exactly why the Second Lateran Council tried (unsuccessfully) to ban it in 1139." },
  { id: "siege-engine", name: "Siege Engines", era: "classical", category: "weapons",
    year: "~400 BCE", prereqs: ["pulley-lever", "iron-tools"],
    desc: "Torsion catapults, ballistae, onagers, and battering rams — engineered weapons that turn a battlefield into an engineering problem. Hellenistic siege technology under Demetrius Poliorcetes ('the Besieger', ~300 BCE) and Roman engineers' systematic deployment let armies reduce previously impregnable cities. The same principles persist into the medieval trebuchet and ultimately into early gunpowder artillery." },
  { id: "cavalry", name: "Heavy Cavalry", era: "classical", category: "weapons",
    year: "~600 BCE", prereqs: ["horse-domestication", "iron-weapons", "chariot"],
    desc: "Mailed riders charging with lance and sword, replacing chariots once horses are bred large enough to carry an armored warrior. Steppe nomads (Scythians, Sarmatians, Parthians) pioneered heavy cavalry; Persian cataphracts and Roman cataphractarii adopted it. By Late Antiquity cavalry has become the decisive arm on most battlefields, a position it holds through the Middle Ages until firearms tip the balance back to massed infantry." },
  { id: "saddle-stirrup", name: "Saddle & Stirrup", era: "classical", category: "transport",
    year: "~400 CE", prereqs: ["horse-domestication", "iron-tools"],
    desc: "Framed saddle (Sarmatian/Roman) and pendant metal foot loops (China, ~300 CE; Avar Europe, ~600 CE) that lock the rider into place during shock combat. The stirrup is small but consequential — it allows the rider to brace against a couched lance and deliver the horse's full momentum at impact. Lynn White famously argued the stirrup made medieval European feudalism possible, an overstatement but with a kernel of truth." },
  { id: "silk-production", name: "Silk Production", era: "bronze", category: "tools",
    year: "~2700 BCE", prereqs: ["animal-domestication", "weaving"],
    desc: "Sericulture: rearing Bombyx mori silkworms on mulberry leaves, reeling cocoons into long filaments, and weaving them into silk. Chinese cultivation goes back to at least 2700 BCE; the secret was guarded for millennia, with capital punishment for export of eggs or worms. Smuggled to the Byzantine Empire by monks ~550 CE. Silk drove the Eurasian trade route that took its name and made China's Han and Tang economies world-spanning." },
  { id: "paper-making", name: "Paper", era: "classical", category: "communication",
    year: "~100 CE", prereqs: ["silk-production", "linen-textile"],
    desc: "Pulped plant fiber (mulberry, hemp, linen rags) pressed into thin sheets — invented by Cai Lun (~105 CE) at the Han court. Cheaper and lighter than papyrus or parchment, paper spread along the Silk Road to the Islamic world by ~750 CE (Samarkand) and Europe by the 12th century. The cost of writing collapsed once paper was available, expanding bureaucracy, scholarship, and eventually printing." },
  { id: "world-religion", name: "World Religions", era: "classical", category: "social",
    year: "~500 BCE", prereqs: ["ritual-religion", "alphabet-phoenician", "empire"],
    desc: "Universal faiths offering moral codes and salvation transcending tribe and locality. Buddhism (~500 BCE), Christianity (~30 CE), and Islam (~620 CE) — along with rabbinic Judaism, Zoroastrianism, and Manichaeism — create transregional religious communities backed by canonical scriptures, professional clergy, and missionary impulses. Under Roman, Sassanian, and Tang patronage they reorganize the political and cultural geography of Eurasia." },
  { id: "monasticism", name: "Monasticism", era: "classical", category: "social",
    year: "~300 CE", prereqs: ["world-religion", "alphabet-latin"],
    desc: "Communities devoted to prayer, study, and labor under a monastic rule (Pachomius in Egypt; Benedict at Monte Cassino, ~530 CE; Buddhist viharas in India and China). Monasteries became the institutional preservers of literacy, manuscript copying, and agricultural innovation through the early medieval period in Europe, and centers of education and economic activity in Buddhist Asia. Their land grants and tax exemptions made them economic powers in their own right." },
  { id: "library", name: "Libraries", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["alphabet-phoenician"],
    desc: "State- or temple-curated collections of scrolls and codices. The Library of Alexandria (founded ~300 BCE under Ptolemy I) targeted holding every Greek-language work, reportedly ~700,000 scrolls; rival Pergamon, then Han imperial archives, then Nalanda's Buddhist collections, all played similar roles. Libraries created the institutional possibility of cumulative scholarship and standardized reference works." },
  { id: "scientific-method-proto", name: "Proto-Science", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["philosophy", "geometry-euclidean"],
    desc: "Aristotle's natural philosophy and Alexandrian empirical work — observation organized by category and tested against logic, but not yet experimental in the modern sense. Aristotle's biology actually contains many accurate observations from dissection, and Alexandrian medicine (Erasistratus, Herophilos) performed systematic anatomy. Centuries later Ibn al-Haytham's Book of Optics introduced controlled experiments specifically designed to falsify hypotheses — the closest pre-modern approach to scientific method." },
  { id: "medicine-galenic", name: "Galenic Medicine", era: "classical", category: "medicine",
    year: "~150 CE", prereqs: ["proto-medicine", "philosophy", "trepanation"],
    desc: "Hippocratic and Galenic medicine combined humoral theory (four humors: blood, phlegm, yellow and black bile) with systematic anatomy and case observation. Galen of Pergamon (~130–210 CE), physician to Roman emperors, wrote prolifically and his texts, transmitted through Arabic translation, dominated medicine in Europe and the Islamic world for 1500 years. Some of his anatomy was wrong (he dissected animals), and Vesalius would correct it in 1543." },
  { id: "water-clock", name: "Water Clock", era: "classical", category: "knowledge",
    year: "~300 BCE", prereqs: ["pulley-lever", "mathematics-arithmetic"],
    desc: "Clepsydra timing devices that measure intervals by regulated water flow into or out of a graduated vessel. Egyptian, Greek, Chinese, and later Andalusian clockmakers refined the form into elaborate astronomical and astrological displays. Water clocks freed timekeeping from sun-watching, allowed timing of indoor and nighttime events (court speeches, work shifts, prayer), and established the technical lineage that mechanical clocks inherit." },
  { id: "waterwheel", name: "Waterwheel", era: "classical", category: "energy",
    year: "~200 BCE", prereqs: ["pulley-lever", "iron-tools"],
    desc: "Vertical and horizontal water-driven mills harnessing river flow. Greek and Roman engineers from ~200 BCE built progressively larger installations; the Barbegal mill in Roman Gaul (~300 CE) had sixteen wheels in series and produced flour for tens of thousands. Water power is the first mechanical replacement for human and animal muscle and underpins medieval European agriculture and proto-industry from grain milling to fulling cloth to working bellows." },
  { id: "compass-early", name: "Lodestone Compass", era: "classical", category: "knowledge",
    year: "~200 BCE", prereqs: ["iron-smelting", "philosophy"],
    desc: "Han Chinese 'south-pointing' magnetized lodestone spoons (~200 BCE), initially used for divination and feng shui rather than navigation. By the 11th century Song Dynasty texts describe magnetized iron needles for orientation. The instrument's original use is a reminder that technology often gets invented for one purpose and only later finds its world-changing application — in this case, on shipboard centuries later." },
  { id: "triremes", name: "Triremes", era: "classical", category: "transport",
    year: "~700 BCE", prereqs: ["galley-ship", "iron-tools"],
    desc: "Three-banked oared warships with bronze rams, reaching speeds of ~9 knots and crewed by 170 oarsmen plus deck soldiers. Greek triremes won the Battle of Salamis (480 BCE) against the Persian fleet and made Athens a naval superpower. The trireme reorganized Aegean politics, made the Athenian empire possible, and remained the dominant warship in the Mediterranean for several centuries." },
  { id: "gear-mechanism", name: "Gear Mechanism", era: "classical", category: "tools",
    year: "~200 BCE", prereqs: ["pulley-lever", "iron-tools"],
    desc: "Toothed wheels meshing to transmit and transform rotational motion. The Antikythera mechanism (~150 BCE Hellenistic Greek) is an astonishing surviving example: a bronze geared computer with at least 30 gears that predicted eclipses and modeled planetary positions. The principle reappears in Hellenistic odometers, Roman watermills, and ultimately drives medieval clockwork and Renaissance machinery." },
  { id: "woodblock-printing", name: "Woodblock Printing", era: "classical", category: "communication",
    year: "~200 CE", prereqs: ["paper-making", "alphabet-greek"],
    desc: "Carved wooden blocks inked and pressed onto paper or fabric. Tang Chinese woodblock printing produced the Diamond Sutra (868 CE), the world's oldest dated printed book, and standard Buddhist canons spread by the millions. Korean and Japanese printers extended the technology, and European blockbooks of the 15th century show parallel independent practice. Though less flexible than movable type, woodblock printing is what brought books to scale across East Asia." },

  // ─── Medieval ──────────────────────────────────────────────────
  { id: "arabic-numerals", name: "Hindu-Arabic Numerals", era: "medieval", category: "knowledge",
    year: "~800 CE", prereqs: ["zero-numeral"],
    desc: "Place-value digits 0–9 with Indian origin, transmitted through al-Khwarizmi's 9th-century Baghdad treatise on calculation and adopted in medieval Europe via Latin translations. The system makes column-arithmetic, long multiplication, and division dramatically faster than Roman numerals, and the word 'algorithm' itself comes from al-Khwarizmi's Latinized name. Italian merchants adopted the numerals in the 12th–13th centuries; by Fibonacci's Liber Abaci (1202) the European transition was underway." },
  { id: "algebra", name: "Algebra", era: "medieval", category: "knowledge",
    year: "~825 CE", prereqs: ["arabic-numerals", "geometry-euclidean"],
    desc: "Symbolic equation-solving systematized in al-Khwarizmi's 'Compendious Book on Calculation by Completion and Balancing' (~825 CE, Baghdad). 'Al-jabr' is the operation of moving a term to the other side of an equation. Islamic mathematicians (Omar Khayyam, al-Karaji) extended the work to cubics. Translated into Latin in the 12th century, algebra entered the European mathematical curriculum and became the symbolic engine driving every later mathematical advance." },
  { id: "gunpowder", name: "Gunpowder", era: "medieval", category: "weapons",
    year: "~850 CE", prereqs: ["alchemy"],
    desc: "Mixture of saltpeter, sulfur, and charcoal that deflagrates rapidly when ignited, originally developed by Tang Daoist alchemists (~850 CE) seeking elixirs of immortality. By the Song dynasty it powered fire arrows, bombs, and proto-cannons; the Mongol conquests carried it westward, and by the 14th century European founders were casting gunpowder cannons. Gunpowder ends castle warfare, reorganizes military hierarchy around mass armies, and reshapes the chemistry of warfare for 600 years." },
  { id: "moveable-type", name: "Moveable Type", era: "medieval", category: "communication",
    year: "~1040 CE", prereqs: ["woodblock-printing"],
    desc: "Individual reusable characters that can be assembled into pages of text and disassembled afterward. Bi Sheng's ceramic type (~1040 CE, Song China) was the first; Korean Jikji (1377) is the oldest extant book printed with metal moveable type, predating Gutenberg by ~75 years. Logographic Chinese scripts have thousands of characters, which limited the technique's impact; the alphabetic adaptation in Europe transformed publishing." },
  { id: "mechanical-clock", name: "Mechanical Clock", era: "medieval", category: "knowledge",
    year: "~1300 CE", prereqs: ["water-clock", "gear-mechanism", "iron-tools"],
    desc: "Verge-and-foliot escapement and weight-driven gear trains striking bells at regular intervals. Continental and English monastic clocks from ~1300 CE provide the first reliable time-of-day signaling. Famous early installations: Salisbury Cathedral (~1386), Wells Cathedral, Strasbourg's astronomical clock. The mechanical clock reshapes urban life around scheduled time rather than natural cycles, and the precision-machining traditions it spawned feed directly into all later instrument-making." },
  { id: "windmill", name: "Windmill", era: "medieval", category: "energy",
    year: "~700 CE", prereqs: ["waterwheel", "sail-primitive"],
    desc: "Wind-driven mills used for grinding grain, pumping water, and pressing oil. Persian vertical-axis post mills (~7th century) and European horizontal-axis tower mills (12th century onward) tap a power source independent of rivers. The Dutch perfected drainage windmills, reclaiming land below sea level. Europe had ~200,000 windmills at peak, and they remained important industrial power sources until steam." },
  { id: "heavy-plow", name: "Heavy Plow", era: "medieval", category: "subsistence",
    year: "~600 CE", prereqs: ["plow-ard", "iron-tools"],
    desc: "Mouldboard plow with iron coulter, share, and curved board that turns the soil over completely, burying weeds and exposing fresh earth. Effective in the heavy clay soils of northern Europe where the simple ard plow couldn't cope, the heavy plow (with ox or horse teams) opened the European plain to cereal cultivation. Yields rose 30–50% and population shifted northward, founding the agrarian basis of medieval Europe." },
  { id: "horse-collar", name: "Horse Collar", era: "medieval", category: "subsistence",
    year: "~800 CE", prereqs: ["horse-domestication", "iron-tools"],
    desc: "Padded shoulder harness developed in China by ~5th century and reaching Europe by ~1100 CE, replacing the throat-and-girth harness that strangled the horse under heavy load. The new collar transmits pull from the shoulders, letting horses out-pull oxen by 50% over short distances. Combined with iron horseshoes, the collar makes the horse the dominant European draft animal, accelerating plowing and overland transport." },
  { id: "three-field-system", name: "Three-Field System", era: "medieval", category: "subsistence",
    year: "~800 CE", prereqs: ["heavy-plow", "horse-collar"],
    desc: "Annual rotation of winter cereal, spring cereal/legume, and fallow on three fields, replacing the older two-field (one cropped, one fallow) system. By dedicating only one-third rather than half of arable land to fallow, the system raises yields dramatically; the legume crop also fixes nitrogen. Adopted across northern Europe from ~800 CE, three-field rotation underpinned the medieval population boom and the rise of cathedral towns." },
  { id: "university", name: "University", era: "medieval", category: "knowledge",
    year: "~1088 CE", prereqs: ["monasticism", "library"],
    desc: "Self-governing corporations of scholars empowered to award degrees in law, medicine, theology, and the arts. Bologna (founded ~1088) was the first; Paris (~1150), Oxford (~1167), and dozens more followed. Universities institutionalized the curriculum of trivium and quadrivium and protected scholars under papal or royal charters. The institution traveled with European colonialism and now exists in essentially every country on earth." },
  { id: "scholasticism", name: "Scholasticism", era: "medieval", category: "knowledge",
    year: "~1100 CE", prereqs: ["university", "philosophy"],
    desc: "Methodical reconciliation of Aristotelian logic with Christian theology, formalized by Anselm, Abelard, and reaching its peak with Thomas Aquinas's Summa Theologica (~1270). The method posed questions, marshaled authorities for and against, then resolved them through dialectical reasoning. Scholastic disputation trained generations of European thinkers and is the institutional and methodological matrix from which the Scientific Revolution would later emerge." },
  { id: "gothic-architecture", name: "Gothic Architecture", era: "medieval", category: "shelter",
    year: "~1150 CE", prereqs: ["arch-vault", "geometry-euclidean"],
    desc: "Pointed arches, ribbed vaults, and flying buttresses redirecting roof loads outward, allowing thinner walls and large stained-glass windows. Originating with Abbot Suger's Saint-Denis (~1140), Gothic spread through Notre-Dame de Paris, Chartres, Reims, Cologne, and York Minster. Stone walls dissolve into translucent surfaces of color and light, and cathedrals become vertical architectural statements that took centuries and entire urban economies to complete." },
  { id: "castle", name: "Castle", era: "medieval", category: "shelter",
    year: "~900 CE", prereqs: ["monumental-architecture", "iron-tools"],
    desc: "Stone fortifications integrating residence, garrison, and administrative center. From simple Norman motte-and-bailey to Crusader fortresses like Krak des Chevaliers and concentric Welsh castles (Caernarfon, Beaumaris), castles dominated the landscape. They were instruments of feudal territorial control: a noble in a castle could defy a king, but a king with a strong castle could project power across a province." },
  { id: "knight-cavalry", name: "Mounted Knight", era: "medieval", category: "weapons",
    year: "~900 CE", prereqs: ["cavalry", "saddle-stirrup", "iron-weapons"],
    desc: "Mounted noble warriors trained from childhood, in mail then plate armor, charging with couched lance and fighting with sword. Knights formed the elite shock arm of medieval European armies for ~400 years, supported by the feudal manorial system that fed and equipped them. Their importance peaked at battles like Hastings (1066) and declined under the longbow at Crécy (1346) and Agincourt (1415), and against pike formations and gunpowder." },
  { id: "longbow", name: "Longbow", era: "medieval", category: "weapons",
    year: "~1300 CE", prereqs: ["bow-arrow", "iron-tools"],
    desc: "Six-foot self-bow of yew, drawing 100+ pounds and capable of armor-piercing flight at 250+ meters. The Welsh and English longbow at Crécy, Poitiers, and Agincourt repeatedly destroyed French chivalry: a peasant trained from boyhood could put six arrows in the air per minute and outrange any crossbow. The longbow democratized lethality temporarily, until firearms made similar power available with much less training." },
  { id: "cannon-early", name: "Cannon", era: "medieval", category: "weapons",
    year: "~1300 CE", prereqs: ["gunpowder", "iron-smelting"],
    desc: "Cast or wrought-iron tubes firing stone or iron shot using gunpowder, evolving from the small handgonne to giant siege bombards. The Dardanelles Gun and other massive Ottoman siege guns brought down the walls of Constantinople in 1453, ending the eastern Roman Empire. Cannon ended the impregnable medieval castle within decades and redrew European political geography around states that could afford siege artillery." },
  { id: "caravel", name: "Caravel", era: "medieval", category: "transport",
    year: "~1450 CE", prereqs: ["galley-ship", "sail-primitive", "compass-early"],
    desc: "Lateen-rigged Iberian sailing ship combining the maneuverability of triangular sails with sturdy hull construction, capable of sailing close to the wind. Developed in the 15th century under Henry the Navigator's Portuguese exploration program, the caravel made it possible to reach the West African coast and return upwind. Columbus' Niña and Pinta were caravels, and the type effectively launched the Age of Discovery." },
  { id: "hospital", name: "Hospital", era: "medieval", category: "medicine",
    year: "~700 CE", prereqs: ["medicine-galenic", "world-religion"],
    desc: "Permanent institutions providing care for the sick, separated from private homes. Islamic bimaristans (the Bimaristan al-Mansuri in Cairo treated 8000 patients annually by the 13th century), Christian xenodochia, and Buddhist monastic infirmaries all flourished. Medieval hospitals offered actual medical care — Galenic diagnosis, herbal remedies, surgery, isolation of contagious cases — and trained generations of physicians." },
  { id: "guild", name: "Guild", era: "medieval", category: "economy",
    year: "~1100 CE", prereqs: ["city-state", "world-religion"],
    desc: "Sworn craft and merchant associations regulating quality, prices, training, and entry to a trade. Guilds set standards (the wool guilds of Flanders, the goldsmiths of Florence), trained apprentices on multi-year contracts, and provided sickness and death benefits. They were proto-corporations and the institutional ancestors of unions, professional associations, and chambers of commerce, and they dominated urban economic life from the 12th through the 18th centuries." },
  { id: "banking-double-entry", name: "Double-Entry Banking", era: "medieval", category: "economy",
    year: "~1300 CE", prereqs: ["arabic-numerals", "coinage"],
    desc: "Italian merchant bookkeeping in which every transaction is recorded twice — as a debit on one account and a credit on another — making the books self-checking. Practiced in Florence and Venice from the 13th century, codified by Luca Pacioli in 1494. The Medici Bank used it to manage offices across Europe. Double-entry makes auditing possible, fraud harder, and is the technical foundation of modern accounting and financial markets." },
  { id: "letter-of-credit", name: "Letter of Credit", era: "medieval", category: "economy",
    year: "~1300 CE", prereqs: ["banking-double-entry", "paper-making"],
    desc: "Bills of exchange that allowed a merchant to deposit money in one city and draw it in another, without physically transporting gold. Italian and Hanseatic merchants developed the form through the 13th and 14th centuries, with Pacioli formalizing it. Letters of credit reduced robbery risk on long routes, multiplied the velocity of trade, and laid the foundation for international banking — the Medici, Fugger, and Rothschild networks all built on this instrument." },
  { id: "magnetic-compass-marine", name: "Marine Compass", era: "medieval", category: "transport",
    year: "~1100 CE", prereqs: ["compass-early"],
    desc: "Magnetized iron needle floating in water or pivoting on a card and sealed in a binnacle. Adopted on Mediterranean ships by the 12th century and on Chinese vessels somewhat earlier, the marine compass made navigation possible regardless of cloud cover, freeing sailors from sun- and star-sightings. Combined with sand-glass timing and a chip-log, it enabled the dead-reckoning navigation that made open-ocean voyages reliable." },
  { id: "glass-lens", name: "Glass Lens", era: "medieval", category: "knowledge",
    year: "~1000 CE", prereqs: ["glass-making"],
    desc: "Ground convex lenses for magnification, beginning with reading-aid lenses in 11th-century Islamic and 13th-century Italian workshops. Ibn al-Haytham's optics (~1021 CE) provided the theoretical foundation. The same techniques, refined, would yield spectacles, telescopes, and microscopes — opening up vast new domains of observation that fundamentally reshaped science from the 17th century onward." },
  { id: "spectacles", name: "Spectacles", era: "medieval", category: "medicine",
    year: "~1290 CE", prereqs: ["glass-lens"],
    desc: "Ground reading lenses set in wooden, bone, or metal frames, invented in northern Italy ~1290 CE and quickly spread by traveling friars and merchants. Spectacles extended the working life of scribes, scholars, and craftsmen by decades — pre-spectacle, presbyopia ended literate work in one's forties. The market for lenses also created a craft tradition that, by the 17th century, would supply telescopes and microscopes." },
  { id: "distillation", name: "Distillation", era: "medieval", category: "knowledge",
    year: "~800 CE", prereqs: ["alchemy", "glass-making", "fermentation-brewing"],
    desc: "Alembic separation of liquids by selective vaporization and condensation. Hellenistic alchemists used the technique; Islamic chemists refined it (Avicenna, Jabir). By the 12th century European monasteries were distilling spirits — brandy, whiskey, gin — and pharmaceutical extracts. Distillation also concentrates acids and oils, and provides the lab equipment that the Scientific Revolution and modern chemistry would inherit and elaborate." },
  { id: "paper-mill", name: "Paper Mill", era: "medieval", category: "communication",
    year: "~1100 CE", prereqs: ["paper-making", "waterwheel", "millstone"],
    desc: "Water-powered hammer mills that pulped rags and reeds into paper at scale. Islamic paper mills appear by ~750 CE; European mills by the 11th century in Spain and Italy, then Germany. Paper costs collapsed once mechanical pulping replaced hand-pounding, and the cheap supply was a precondition for the printing press: Gutenberg's invention would have been useless if every book required years of parchment from hundreds of sheep." },
  { id: "horizontal-loom", name: "Horizontal Loom", era: "medieval", category: "tools",
    year: "~1000 CE", prereqs: ["weaving", "gear-mechanism"],
    desc: "Treadle-operated horizontal loom with foot-pedals controlling heddles, freeing both hands to throw the shuttle. Adopted in Europe by ~1000 CE (likely from Islamic or Chinese sources), it raised cloth output tenfold over the older warp-weighted vertical loom. Horizontal looms made medieval Flemish and Florentine wool industries possible and set the technological starting point for the spinning jenny and power loom 700 years later." },
  { id: "quill-ink", name: "Quill & Ink", era: "medieval", category: "communication",
    year: "~600 CE", prereqs: ["paper-making"],
    desc: "Goose feather pens with iron-gall ink (oak gall tannins reacting with iron sulfate) on parchment then paper. The combination was the dominant writing technology in Europe from late antiquity to the 19th century, used for everything from monastic manuscripts to imperial decrees to merchants' ledgers. Iron gall ink survives extremely well — most medieval manuscripts are still legible after eight centuries." },

  // ─── Renaissance ───────────────────────────────────────────────
  { id: "printing-press", name: "Printing Press", era: "renaissance", category: "communication",
    year: "1450", prereqs: ["moveable-type", "paper-mill", "quill-ink"],
    desc: "Johannes Gutenberg's mid-1440s combination of a screw press, oil-based ink, and metal moveable type cast in a hand-mold. The 42-line Bible of 1454 was the first major Western printed book. Within fifty years over twenty million books had been printed in Europe; the price per page fell ~100×. The press is the single most consequential information technology before the internet — it propagated the Reformation, the Scientific Revolution, vernacular literacy, and modern bureaucracy." },
  { id: "vernacular-literature", name: "Vernacular Literature", era: "renaissance", category: "social",
    year: "1300–1500", prereqs: ["alphabet-latin"],
    desc: "Major literary works composed in spoken languages rather than Latin: Dante's Divine Comedy (~1320), Chaucer's Canterbury Tales (~1387), Cervantes' Don Quixote (1605), Boccaccio, Petrarch, Rabelais. Vernacular literature expanded reading audiences enormously, codified national languages (Tuscan as 'Italian', East Midlands English, Castilian), and broke the medieval clergy's monopoly on intellectual life. The printing press subsequently amplified the trend a hundredfold." },
  { id: "humanism", name: "Humanism", era: "renaissance", category: "social",
    year: "1400", prereqs: ["vernacular-literature", "scholasticism"],
    desc: "Recovery and study of classical Greek and Roman texts, with renewed emphasis on rhetoric, ethics, and the dignity of the individual. Petrarch's discovery of Cicero's letters (~1345), Erasmus' Greek New Testament (1516), and the rise of humanist schools across Italy and northern Europe positioned humans rather than scholastic categories at the center of inquiry. Humanism reshaped education, literature, art, and political thought from the 14th through 17th centuries." },
  { id: "linear-perspective", name: "Linear Perspective", era: "renaissance", category: "social",
    year: "1420", prereqs: ["geometry-euclidean", "vernacular-literature"],
    desc: "Geometric system for representing three-dimensional space on a flat surface, with parallel lines converging at a vanishing point. Brunelleschi's experiments with reflected images of the Florentine Baptistery (~1413) and Alberti's treatise On Painting (1435) formalized the technique. Linear perspective made Renaissance painting a window onto rationalized, measurable space and is also the conceptual ancestor of architectural drawing, technical illustration, and computer 3-D rendering." },
  { id: "oil-painting", name: "Oil Painting", era: "renaissance", category: "social",
    year: "1430", prereqs: ["pigments", "linear-perspective"],
    desc: "Pigments suspended in linseed or walnut oil, allowing slow drying, layered glazes, fine detail, and luminous color. Jan van Eyck's Arnolfini Portrait (1434) showed the technique's potential; Italians from Antonello da Messina onward adopted it from Flemish models. Leonardo, Michelangelo, Raphael, Titian, and Rembrandt all worked primarily in oil. The medium's flexibility made possible the secular portrait, the landscape, and the modern conception of painting as personal expression." },
  { id: "opera-orchestra", name: "Opera & Orchestra", era: "renaissance", category: "social",
    year: "1600", prereqs: ["vernacular-literature"],
    desc: "Sung drama with continuous instrumental accompaniment. Claudio Monteverdi's L'Orfeo (1607) is the first surviving major opera. The form combined Renaissance interest in classical theatre with elaborate stagecraft and the new musical resources of the early Baroque. Opera became court entertainment across Europe and gave rise to the modern orchestra, with sections of strings, woodwinds, brass, and percussion functioning as a single integrated instrument." },
  { id: "scientific-method", name: "Scientific Method", era: "renaissance", category: "knowledge",
    year: "1620", prereqs: ["scientific-method-proto", "printing-press", "glass-lens"],
    desc: "Systematic experimentation, mathematical description, and skepticism toward inherited authority. Francis Bacon's Novum Organum (1620) advocated inductive reasoning; Galileo's experiments with falling bodies and his telescopic observations applied mathematics to physical motion; Descartes proposed methodical doubt. The combined practice — test, measure, publish — established the productive feedback loop that has driven cumulative scientific progress ever since." },
  { id: "heliocentrism", name: "Heliocentrism", era: "renaissance", category: "knowledge",
    year: "1543", prereqs: ["astronomy-observation", "mathematics-arithmetic", "printing-press"],
    desc: "Sun-centered model of the solar system with Earth as one planet among others. Nicolaus Copernicus published De revolutionibus orbium coelestium in 1543; Tycho Brahe's precise observations and Kepler's three laws (1609–1619) established the elliptical-orbit refinement; Galileo's telescopic discovery of Jupiter's moons and Venus's phases destroyed Ptolemaic alternatives. Heliocentrism dethroned Earth from cosmic centrality and is the symbolic opening of the Scientific Revolution." },
  { id: "algebra-symbolic", name: "Symbolic Algebra", era: "renaissance", category: "knowledge",
    year: "1591", prereqs: ["algebra", "printing-press"],
    desc: "François Viète's introduction of letters for unknowns (vowels) and constants (consonants) in his In artem analyticem isagoge (1591), allowing equations to be written and manipulated abstractly. Descartes refined the notation to the modern x, y, z for unknowns and a, b, c for constants. With symbolic algebra, equations become objects to be transformed by general rules, and the path opens to all subsequent abstract mathematics from calculus to group theory." },
  { id: "logarithms", name: "Logarithms", era: "renaissance", category: "knowledge",
    year: "1614", prereqs: ["algebra-symbolic", "mathematics-arithmetic"],
    desc: "John Napier's tables (1614) defining a function whose addition equals the multiplication of its arguments, with Henry Briggs' base-10 elaboration. The slide rule, invented by William Oughtred in 1622, mechanized logarithms for daily calculation and remained an engineer's standard tool for 350 years until pocket calculators replaced it. Logarithms compressed astronomical and navigational arithmetic by orders of magnitude." },
  { id: "anatomy-vesalius", name: "Modern Anatomy", era: "renaissance", category: "medicine",
    year: "1543", prereqs: ["medicine-galenic", "printing-press"],
    desc: "Andreas Vesalius's De humani corporis fabrica (1543), based on his own dissections at Padua, corrected over 200 of Galen's anatomical errors. Detailed engravings by Titian's workshop made the work as much an aesthetic as a scientific landmark. Combined with Harvey's later demonstration of blood circulation (1628), Vesalius's anatomy reset Western medicine on observed structure and prepared the ground for surgical and physiological advances." },
  { id: "microscope", name: "Microscope", era: "renaissance", category: "knowledge",
    year: "1620", prereqs: ["glass-lens", "spectacles"],
    desc: "Compound and simple lens systems revealing structures invisible to the naked eye. Antonie van Leeuwenhoek's hand-ground simple microscopes (~1670s) achieved 270× magnification — enough to see protozoa and bacteria. Robert Hooke's compound microscope and Micrographia (1665) introduced the word 'cell' for the chambers he saw in cork. The microscope opened biology, parasitology, microbiology, and metallurgy to direct observation." },
  { id: "telescope", name: "Telescope", era: "renaissance", category: "knowledge",
    year: "1608", prereqs: ["glass-lens", "heliocentrism"],
    desc: "Hans Lippershey's Dutch refracting telescope (1608) was almost immediately improved by Galileo (1609), whose 20× instrument revealed Jupiter's four moons, Venus's phases, sunspots, and the Milky Way's stars — observations published in Sidereus Nuncius (1610). Newton's reflecting design (1668) eliminated chromatic aberration. The telescope made the heavens an empirical, expanding domain rather than a mythological canopy." },
  { id: "pendulum-clock", name: "Pendulum Clock", era: "renaissance", category: "knowledge",
    year: "1656", prereqs: ["mechanical-clock", "mathematics-arithmetic"],
    desc: "Christiaan Huygens's 1656 horologium combined Galileo's discovery of the pendulum's isochronous swing with an escapement, achieving accuracy of seconds per day — over 100× better than verge-and-foliot clocks. Pendulum clocks anchored astronomy, navigation, and railroad scheduling for the next 250 years, and their precision feeding back into measurement made the rest of the Scientific Revolution quantitative." },
  { id: "protestant-reformation", name: "Protestant Reformation", era: "renaissance", category: "social",
    year: "1517", prereqs: ["printing-press", "world-religion"],
    desc: "Martin Luther's Ninety-five Theses (1517) attacking indulgences, propagated rapidly via the printing press, became the spark for a century of religious and political restructuring across Europe. The Reformation split Western Christianity into Catholic, Lutheran, Reformed (Calvin), Anglican, and Anabaptist confessions. Vernacular Bibles, mass literacy, and ultimately religious pluralism are downstream effects, alongside the Wars of Religion that culminated in 1648." },
  { id: "nation-state", name: "Nation-State", era: "renaissance", category: "economy",
    year: "1500", prereqs: ["empire", "printing-press"],
    desc: "Centralized monarchies with permanent bureaucracies, standing armies, and standardized taxation, replacing the layered feudal allegiances of medieval Europe. Spain under Ferdinand and Isabella, France under Louis XI through Louis XIV, England under the Tudors, and Sweden under Gustavus Adolphus all consolidated similar formulas. The Peace of Westphalia (1648) codified state sovereignty as the basic unit of international order, a structure that still governs world politics." },
  { id: "joint-stock-company", name: "Joint-Stock Company", era: "renaissance", category: "economy",
    year: "1600", prereqs: ["banking-double-entry", "nation-state", "guild"],
    desc: "Tradable shares of perpetual ownership in a chartered enterprise, pooling capital for ventures beyond any single merchant or king. The Dutch VOC (1602) and English East India Company (1600) financed long-distance trade, colonial conquest, and infrastructure. The form eventually generalized into the modern corporation, made stock exchanges (Amsterdam, London) into central institutions, and reshaped the relationship between capital and political power." },
  { id: "mercantilism", name: "Mercantilism", era: "renaissance", category: "economy",
    year: "1550", prereqs: ["nation-state", "maritime-trade"],
    desc: "State economic policy aimed at maximizing bullion holdings through trade surpluses, tariffs, navigation acts, and chartered monopolies. Practiced under Colbert in France, the Navigation Acts in England (1651 onward), and Spanish/Portuguese imperial systems. Mercantilist competition drove colonial expansion, naval buildup, and the Atlantic slave trade. Adam Smith's Wealth of Nations (1776) attacked mercantilism, but its core moves persisted in 'industrial policy' through to the 21st century." },
  { id: "galleon", name: "Galleon", era: "renaissance", category: "transport",
    year: "1500", prereqs: ["caravel", "cannon-early", "triremes"],
    desc: "Multi-decked sailing warship and trader, 500–2000 tons, with multiple gun decks and substantial cargo capacity. Spanish galleons hauled Mexican silver to Manila and Manila silk to Acapulco for two and a half centuries (1565–1815) — the first truly global maritime supply chain. Galleon design also became the template for the cargo-and-warship distinction that shaped European navies through the line-of-battle era." },
  { id: "ocean-navigation", name: "Ocean Navigation", era: "renaissance", category: "transport",
    year: "1480", prereqs: ["magnetic-compass-marine", "astronomy-observation"],
    desc: "Combined use of magnetic compass, astrolabe, quadrant, mariners' rutters, and dead reckoning to undertake voyages of months out of sight of land. Portuguese mastery of the technique under Henry the Navigator's Sagres school enabled the rounding of Africa (Dias 1488, da Gama 1498) and Magellan's circumnavigation (1519–1522). Ocean navigation made the Age of Discovery possible and rewired global biology, demography, and commerce." },
  { id: "new-world-encounter", name: "New World Encounter", era: "renaissance", category: "social",
    year: "1492", prereqs: ["ocean-navigation"],
    desc: "Sustained contact between Old and New Worlds beginning with Columbus's 1492 voyage to Hispaniola and Cabot's 1497 visit to Newfoundland. The encounter triggered the largest demographic catastrophe in recorded history (an estimated 90% indigenous American population collapse from disease) and the Columbian Exchange, but also the redrawing of the world political map and the beginning of Atlantic colonialism, slavery, and capitalism." },
  { id: "colonialism", name: "Colonialism", era: "renaissance", category: "economy",
    year: "1500", prereqs: ["new-world-encounter", "gunpowder"],
    desc: "Extractive overseas empires built on plantation labor, conquest, forced trade, and metropolitan settlement. Portuguese in Africa, Brazil, and the Indian Ocean; Spanish in the Americas; Dutch, English, French in everywhere from Caribbean sugar islands to Indonesian spice islands. Colonialism transferred wealth from colonies to metropoles for ~400 years, restructured global agriculture and labor, and cast a shadow whose political and economic consequences still organize the modern world." },
  { id: "columbian-exchange", name: "Columbian Exchange", era: "renaissance", category: "subsistence",
    year: "1500", prereqs: ["new-world-encounter"],
    desc: "Transfer of organisms, foods, diseases, and technologies between Old and New Worlds after 1492. Potatoes, tomatoes, maize, cacao, vanilla, tobacco, chili, beans, peanuts, and pumpkins crossed east; horses, cattle, pigs, sugarcane, wheat, and smallpox crossed west. The exchange transformed diets globally — Italian cuisine without tomatoes is unimaginable, as is Indian without chili — and reorganized agriculture on every inhabited continent." },
  { id: "musket", name: "Musket", era: "renaissance", category: "weapons",
    year: "1500", prereqs: ["gunpowder", "cannon-early", "crossbow", "longbow"],
    desc: "Hand-held matchlock and later flintlock smoothbore firearms firing lead balls. The 16th-century Spanish tercio combined pikes and muskets in mutually defending formations; by the 17th century musketeers dominated infantry and pikes vanished. A peasant could be trained to use a musket in a week — vastly less than the years required for a longbow or knight's training. Mass musket-armed infantry made the citizen-army of the late 18th century possible." },
  { id: "artillery", name: "Field Artillery", era: "renaissance", category: "weapons",
    year: "1500", prereqs: ["cannon-early", "mathematics-arithmetic", "siege-engine"],
    desc: "Mobile cast bronze and iron cannon firing solid shot, shell, or canister on calculated trajectories. The Italian Wars (1494–1559) demonstrated the dominance of mobile field artillery; by Gustavus Adolphus's reforms (1620s), artillery had become a true combined-arms partner with infantry and cavalry. Battlefield ranges grew past bowshot, sieges were re-mathematized around angles and elevations, and military engineering became a recognized profession." },
  { id: "bastion-fortification", name: "Bastion Fort", era: "renaissance", category: "shelter",
    year: "1530", prereqs: ["artillery", "geometry-euclidean", "castle"],
    desc: "Star-shaped low earthworks designed to deflect cannon shot and create overlapping fields of crossfire. Italian engineers developed the trace italienne in response to French artillery campaigns of the 1490s, and Vauban perfected the form in 17th-century France. Bastion forts made siegecraft a geometry problem (Vauban's parallels and saps systematized the attacker's response), and they dominated military architecture from ~1500 to 1860." },

  // ─── Enlightenment ─────────────────────────────────────────────
  { id: "newtonian-mechanics", name: "Newtonian Mechanics", era: "enlightenment", category: "knowledge",
    year: "1687", prereqs: ["scientific-method", "heliocentrism", "logarithms"],
    desc: "Isaac Newton's three laws of motion plus universal gravitation, published in Philosophiæ Naturalis Principia Mathematica (1687). The Principia derives Kepler's planetary laws, the tides, the precession of the equinoxes, and projectile motion from the same equations — unifying terrestrial and celestial mechanics under one mathematical theory. Newton's mechanics governed physics for over 200 years and remains accurate for non-relativistic, non-quantum problems." },
  { id: "calculus", name: "Calculus", era: "enlightenment", category: "knowledge",
    year: "1684", prereqs: ["algebra-symbolic", "cartesian-coordinates"],
    desc: "Differential and integral calculus, independently developed by Newton (~1665, fluxions) and Leibniz (~1675, modern dx/dt notation). Calculus is the mathematical language of continuous change — necessary for analyzing motion, growth, optimization, and integration of curves. Leibniz's notation prevailed; the Newton-Leibniz priority dispute poisoned English mathematics for a generation. Every modern engineering and physics curriculum begins here." },
  { id: "gravitation-law", name: "Universal Gravitation", era: "enlightenment", category: "knowledge",
    year: "1687", prereqs: ["newtonian-mechanics", "calculus"],
    desc: "Inverse-square attraction between any two masses, proportional to their product. Newton derived it in the Principia by reasoning that the same force pulling apples down also keeps the moon in orbit. The law accurately predicted comet returns, tides, and the planetary perturbations that led Le Verrier to predict Neptune's existence (1846). Einstein's general relativity later subsumed it as a low-energy approximation." },
  { id: "cartesian-coordinates", name: "Cartesian Coordinates", era: "enlightenment", category: "knowledge",
    year: "1637", prereqs: ["algebra-symbolic", "geometry-euclidean"],
    desc: "René Descartes' La Géométrie (1637) established a system of perpendicular axes labeled with numerical values, allowing geometric figures to be represented by algebraic equations and vice versa. The fusion of algebra and geometry — analytic geometry — opened the door to calculus, vector analysis, and modern mathematical physics, all of which routinely shift between geometric and algebraic descriptions of the same problem." },
  { id: "probability-theory", name: "Probability Theory", era: "enlightenment", category: "knowledge",
    year: "1654", prereqs: ["algebra-symbolic"],
    desc: "Mathematical analysis of chance, founded in the 1654 correspondence between Blaise Pascal and Pierre de Fermat about gambling problems. Subsequent developments by Huygens, Bernoulli, de Moivre, and Laplace produced the law of large numbers and the central limit theorem. Probability undergirds modern statistics, insurance, quantum mechanics, machine learning, and any domain where decisions must be made under uncertainty." },
  { id: "thermometer", name: "Thermometer", era: "enlightenment", category: "knowledge",
    year: "1714", prereqs: ["glass-lens", "scientific-method"],
    desc: "Mercury-in-glass instruments with reproducible scales, developed by Daniel Fahrenheit (1714) and Anders Celsius (1742). Earlier thermoscopes (Galileo, Santorio) showed temperature changes qualitatively but lacked fixed reference points. Reliable thermometers made temperature measurable, allowing meteorology, medicine (clinical fevers), industrial processes, and the physical chemistry that would come." },
  { id: "barometer", name: "Barometer", era: "enlightenment", category: "knowledge",
    year: "1643", prereqs: ["glass-lens", "scientific-method"],
    desc: "Evangelista Torricelli's mercury column (1643) demonstrated atmospheric pressure and the existence of a vacuum above the mercury — overturning Aristotelian doctrine that nature 'abhors a vacuum'. Pascal's brother-in-law Florin Périer carried a barometer up the Puy de Dôme (1648) to confirm pressure decreases with altitude. Barometers became essential to weather forecasting, aviation, and the gas-law experiments leading to thermodynamics." },
  { id: "germ-precursor", name: "Microbial Discovery", era: "enlightenment", category: "medicine",
    year: "1676", prereqs: ["microscope", "anatomy-vesalius"],
    desc: "Antonie van Leeuwenhoek's 1670s observations of 'animalcules' (bacteria, protozoa) in pond water, dental plaque, and rainwater. Leeuwenhoek's hand-ground simple microscopes were the best of his era. The microbial world was visible but its connection to disease wasn't established until Pasteur and Koch nearly two centuries later — a long delay that vividly illustrates how seeing something is not the same as understanding what it does." },
  { id: "vaccination", name: "Vaccination", era: "enlightenment", category: "medicine",
    year: "1796", prereqs: ["germ-precursor", "hospital"],
    desc: "Edward Jenner's 1796 demonstration that exposure to cowpox protects against smallpox, by deliberately inoculating a child with cowpox material. The technique exploited the cross-immunity between related viruses without yet understanding viruses, immunity, or any of the underlying biology. Vaccination spread globally within decades, eradicated smallpox by 1980, and was the empirical foundation Pasteur built on in extending the principle to other diseases." },
  { id: "chemistry-modern", name: "Modern Chemistry", era: "enlightenment", category: "knowledge",
    year: "1789", prereqs: ["alchemy", "scientific-method"],
    desc: "Antoine Lavoisier's overthrow of the phlogiston theory and establishment of conservation of mass, oxidation theory of combustion, and a rationalized chemical nomenclature, summarized in Traité élémentaire de chimie (1789). Lavoisier was guillotined during the Revolution five years later, but his framework — quantitative experiments, balanced equations, named compounds — defined chemistry as an exact science." },
  { id: "electricity-static", name: "Static Electricity", era: "enlightenment", category: "knowledge",
    year: "1750", prereqs: ["scientific-method"],
    desc: "Benjamin Franklin's lightning experiments (1752 kite) and the Leyden jar (Pieter van Musschenbroek, 1745) put electricity firmly into experimental physics. Franklin established the conservation of charge and the conventional current direction. Coulomb's law (1785) quantified the inverse-square force between charges. Static electricity remained a curiosity until Volta's pile turned it into a source of sustained current." },
  { id: "steam-pump", name: "Atmospheric Steam Engine", era: "enlightenment", category: "energy",
    year: "1712", prereqs: ["mechanical-clock", "gunpowder"],
    desc: "Thomas Newcomen's 1712 atmospheric steam engine pumped water from coal mines using condensation of steam under a piston to draw it down. The engine was inefficient — most heat was lost reheating the cylinder each cycle — but it was the first commercially deployed reciprocating steam engine and the prototype that James Watt would dramatically improve. By Newcomen's death there were ~100 of his engines working in British mines." },
  { id: "steam-engine-watt", name: "Watt Steam Engine", era: "enlightenment", category: "energy",
    year: "1776", prereqs: ["steam-pump", "calculus"],
    desc: "James Watt's 1776 improvements — separate condenser (1769), centrifugal governor, and rotary motion via sun-and-planet gear — quadrupled the efficiency of Newcomen's design. Watt's partnership with Matthew Boulton mass-produced engines for mines, mills, and eventually transport. The Watt steam engine is the canonical Industrial Revolution technology: a prime mover whose deployment grew British coal output and manufacturing by orders of magnitude in a generation." },
  { id: "coke-iron", name: "Coke-Smelted Iron", era: "enlightenment", category: "tools",
    year: "1709", prereqs: ["iron-smelting", "scientific-method"],
    desc: "Abraham Darby's 1709 substitution of coke (baked coal) for charcoal in his Coalbrookdale blast furnace eliminated the bottleneck of forest depletion that had constrained iron production. Coke smelting required higher draught (and eventually steam-driven blowers) but yielded iron in volumes previously unimaginable. Darby's grandson cast the world's first iron bridge at Coalbrookdale in 1779 — a public statement of what coke iron could do." },
  { id: "canal-system", name: "Canal Network", era: "enlightenment", category: "transport",
    year: "1761", prereqs: ["arch-vault", "mathematics-arithmetic"],
    desc: "Locked artificial waterways linking rivers, mines, factories, and ports. Britain's Bridgewater Canal (1761), the Erie Canal in New York (1825), and France's Canal du Midi (1681) cut bulk freight costs to a tenth of road haulage. The 'canal mania' of the 1790s created the inland transport network that fed early Industrial Revolution mills with coal and raw cotton. Railroads later displaced most canal traffic, but the engineering tradition (locks, aqueducts, surveying) carried over." },
  { id: "turnpike-roads", name: "Turnpike Roads", era: "enlightenment", category: "transport",
    year: "1750", prereqs: ["roads-paved", "nation-state"],
    desc: "Toll-funded macadamized highways with engineered drainage and graded surfaces, replacing the rutted and seasonal cart tracks of medieval England. Telford and McAdam's road-building methods reduced London-to-Edinburgh travel from a fortnight to ~40 hours by stagecoach. Turnpikes integrated regional markets, enabled the postal system, and accustomed Britain to private-sector infrastructure financing — a model later adapted for railroads." },
  { id: "agricultural-revolution", name: "British Agricultural Revolution", era: "enlightenment", category: "subsistence",
    year: "1750", prereqs: ["three-field-system", "columbian-exchange"],
    desc: "Eighteenth-century British transformation of farming through enclosure of common land, the Norfolk four-course rotation, selective breeding (Bakewell's livestock), and new tools (Tull's seed drill, threshing machines). Yields rose ~50% across the century. The freed labor migrated to industrial cities, providing the workforce of the Industrial Revolution; cheap food underpinned the urban population boom and shifted political power away from rural nobility." },
  { id: "crop-rotation-norfolk", name: "Norfolk Rotation", era: "enlightenment", category: "subsistence",
    year: "1730", prereqs: [],
    desc: "Wheat–turnips–barley–clover four-course rotation popularized by Charles 'Turnip' Townshend in early 18th-century Norfolk. Turnips fed livestock through winter and aerated soil; clover fixed nitrogen and provided fodder. The system eliminated fallow without depleting soil — a major productivity gain over the medieval three-field system. Norfolk rotation became the template for improving agriculture across temperate Europe." },
  { id: "selective-breeding", name: "Scientific Breeding", era: "enlightenment", category: "subsistence",
    year: "1760", prereqs: ["animal-domestication", "scientific-method"],
    desc: "Robert Bakewell's Dishley Leicester sheep (1740s onward) demonstrated systematic in-and-in breeding for desired traits (here, fast meat-producing weight gain). Bakewell doubled mutton yields in two generations through pedigree selection and stud-leasing. The same principles later applied to cattle (Coke of Norfolk's Shorthorns) and grain crops; the methodology, formalized later by Mendel and biometricians, is the foundation of all modern agricultural and animal genetics." },
  { id: "enlightenment-philosophy", name: "Enlightenment Philosophy", era: "enlightenment", category: "social",
    year: "1750", prereqs: ["humanism", "scientific-method", "protestant-reformation"],
    desc: "Eighteenth-century European philosophical movement emphasizing reason, individual rights, religious tolerance, and the social contract. John Locke (rights, government by consent), Voltaire (tolerance, freedom of speech), Rousseau (social contract, popular sovereignty), Kant (autonomy, categorical imperative), Hume (empiricism, skepticism). The intellectual scaffolding of every later liberal democratic constitution and human-rights framework comes from this generation." },
  { id: "liberal-democracy", name: "Liberal Democracy", era: "enlightenment", category: "economy",
    year: "1789", prereqs: ["enlightenment-philosophy", "republic"],
    desc: "Constitutional government with civil liberties, representative legislatures, separation of powers, and judicial protection of individual rights. The American Revolution's Declaration of Independence (1776) and Constitution (1789), and the French Revolution's Declaration of the Rights of Man (1789), inaugurated the form. Liberal democracy spread unevenly — through 19th-century reform, post-WWII decolonization, and the post-1989 democratic wave — and now dominates roughly half the world's population." },
  { id: "separation-of-powers", name: "Separation of Powers", era: "enlightenment", category: "economy",
    year: "1748", prereqs: ["roman-law"],
    desc: "Montesquieu's 1748 treatise The Spirit of the Laws argued that liberty depends on dividing legislative, executive, and judicial functions among different bodies that check each other. The U.S. Constitution institutionalized this in 1789 with the federal three-branch system; subsequent constitutions worldwide adopted variations. The principle remains central to constitutional design and to debates about democratic backsliding when one branch encroaches on another." },
  { id: "encyclopedia", name: "Encyclopédie", era: "enlightenment", category: "knowledge",
    year: "1751", prereqs: ["enlightenment-philosophy", "printing-press"],
    desc: "Diderot and d'Alembert's Encyclopédie (1751–1772) — 35 volumes, over 70,000 articles, written by hundreds of contributors including Voltaire, Rousseau, and Buffon. Knowledge was organized for the literate public rather than the academy, with explicit aim of disseminating Enlightenment values. Royal censorship pursued it but circulation continued underground. The Encyclopédie is the direct conceptual ancestor of every later general-knowledge reference, including Wikipedia." },
  { id: "public-education", name: "Public Education", era: "enlightenment", category: "social",
    year: "1763", prereqs: ["encyclopedia", "nation-state"],
    desc: "State-funded universal schooling, with Prussia leading (1763 Generallandschulreglement), followed by France's revolutionary education laws and 19th-century Anglo-American common schools. Mass literacy and numeracy became civic infrastructure rather than a private privilege. Public education trained workers for industry, citizens for democracy, and soldiers for conscript armies, and it remains the single largest public-sector institution in most modern states." },
  { id: "factory-system", name: "Factory System", era: "enlightenment", category: "economy",
    year: "1780", prereqs: ["steam-engine-watt", "joint-stock-company"],
    desc: "Centralized power-driven workshops with wage labor and division of tasks, replacing cottage production. Richard Arkwright's Cromford Mill (1771) integrated water-powered spinning machines under one roof with disciplined shift work. The factory system reorganized work around machine schedules, separated workplace from home, generated industrial cities (Manchester, Birmingham), and produced both extraordinary productivity gains and the social conditions that would drive 19th-century labor movements." },
  { id: "spinning-jenny", name: "Spinning Jenny", era: "enlightenment", category: "tools",
    year: "1764", prereqs: ["horizontal-loom"],
    desc: "James Hargreaves's 1764 multi-spindle hand-cranked spinning frame allowed one operator to spin eight (later 80+) threads simultaneously. The Jenny, together with Arkwright's water frame and Crompton's mule, transformed cotton spinning from a cottage activity into the leading edge of mechanized industry. British cotton output rose ~50× between 1770 and 1840, and India's traditional cotton industry collapsed in the face of cheap British thread." },
  { id: "power-loom", name: "Power Loom", era: "enlightenment", category: "tools",
    year: "1785", prereqs: ["spinning-jenny", "steam-engine-watt"],
    desc: "Edmund Cartwright's 1785 steam-driven loom mechanized weaving, the bottleneck after spinning was already mechanized. Cartwright's design was crude; refinements through the 1820s by Roberts and others made power weaving commercially dominant. By 1850 hand-loom weavers in Britain were largely impoverished or extinct. The power loom completed mechanization of the textile chain and made cotton cloth the first truly mass-produced industrial good." },
  { id: "naval-warship", name: "Ship of the Line", era: "enlightenment", category: "transport",
    year: "1700", prereqs: ["galleon", "artillery"],
    desc: "Wooden ship-of-the-line — three-decker first-rate carrying 100+ broadside guns and crewing ~850. HMS Victory (1765, Nelson's flagship at Trafalgar 1805) is the canonical example. Line tactics — fleets sailing in single column, pounding each other at 100-meter range — required disciplined gun crews and seamanship beyond any merchant fleet. Naval warships projected European power across the world's oceans for two centuries." },
  { id: "modern-bookkeeping", name: "Modern Bookkeeping", era: "enlightenment", category: "economy",
    year: "1700", prereqs: ["banking-double-entry", "joint-stock-company"],
    desc: "Standardized profit-and-loss and balance-sheet bookkeeping for chartered companies and growing merchant networks. Accountants like Pacioli (codifier) gave way to Dickinson (American Institute of Accountants, 1887) and the rise of corporate auditing. Modern bookkeeping made financial state legible at a glance to outsiders — investors, regulators, tax authorities — and is the technical infrastructure of the joint-stock company and the modern corporation." },
  { id: "central-bank", name: "Central Bank", era: "enlightenment", category: "economy",
    year: "1694", prereqs: ["banking-double-entry", "nation-state"],
    desc: "Government-chartered banks with monopoly note issue, lender-of-last-resort function, and management of state debt. The Bank of England (1694) and Banque de France (1800) set the pattern. Central banks gave states reliable wartime credit, smoothed financial crises (when they did), and gradually became managers of monetary policy through interest rates, open-market operations, and (post-2008) quantitative easing. Most countries now have one." },

  // ─── Industrial ────────────────────────────────────────────────
  { id: "bessemer-steel", name: "Bessemer Steel", era: "industrial", category: "tools",
    year: "1855", prereqs: ["coke-iron", "steam-engine-watt", "steel-bloomery"],
    desc: "Henry Bessemer's 1855 air-blown converter that mass-produced steel from molten pig iron in ~20 minutes by burning off excess carbon. Cost per ton of steel collapsed by ~80% in a decade, and steel — previously rarer and more expensive than silver — became the building material of railways, ships, skyscrapers, and machine tools. Andrew Carnegie's Pittsburgh mills industrialized the process at scale and made the United States the world's largest steel producer by 1890." },
  { id: "railway-locomotive", name: "Steam Locomotive", era: "industrial", category: "transport",
    year: "1814", prereqs: ["steam-engine-watt", "canal-system"],
    desc: "Stephenson's Rocket (1829) won the Rainhill Trials and set the template for the steam locomotive: multi-tube boiler, blastpipe exhaust, valve gear. Inland transport at 50 mph collapsed travel times and unified national markets. Britain had ~10,000 km of track by 1850, the U.S. had its transcontinental route by 1869, and the Trans-Siberian was completed in 1916. Railroads also pioneered the modern corporate form, time zones, and standardized engineering practice." },
  { id: "telegraph", name: "Electric Telegraph", era: "industrial", category: "communication",
    year: "1837", prereqs: ["electricity-static", "electromagnetism"],
    desc: "Morse code over copper wires, demonstrated by Samuel Morse with his 1844 Washington–Baltimore line. By 1858 the first transatlantic cable briefly worked; permanent transatlantic service from 1866. Information detached from physical transport for the first time in history, enabling continental railway scheduling, financial markets to operate at near-real-time, and journalism to file from war zones. The telegraph is the conceptual ancestor of all electronic communication." },
  { id: "railroad-network", name: "Railroad Network", era: "industrial", category: "transport",
    year: "1840", prereqs: ["railway-locomotive", "telegraph"],
    desc: "Continental rail systems coordinated by the telegraph, transforming travel times, freight costs, and market integration. The U.S. Transcontinental Railroad (1869), the Trans-Siberian (1916), and dense European networks tied national economies together. Railways forced the adoption of standard time zones (1883 in the U.S.) and pioneered the modern multi-divisional corporation, hierarchical management, and large-scale finance." },
  { id: "steamship", name: "Steamship", era: "industrial", category: "transport",
    year: "1830", prereqs: ["steam-engine-watt", "naval-warship"],
    desc: "Iron-hulled screw-driven steamers like Brunel's Great Western (1838) and Great Eastern (1858) reduced Atlantic crossings from weeks to days, on schedule. Liner services (Cunard from 1840) and global mail networks tied colonies to metropoles. The shift from sail to steam took decades because sailing ships were free of fuel costs, but by the 1880s steam dominated, and by 1900 the world's merchant marine was overwhelmingly steel-hulled steam." },
  { id: "electric-battery", name: "Voltaic Battery", era: "industrial", category: "energy",
    year: "1800", prereqs: ["electricity-static", "chemistry-modern"],
    desc: "Alessandro Volta's 1800 voltaic pile — alternating zinc and copper discs separated by salt-soaked cardboard — produced the first sustained electric current. Davy used powerful batteries to discover sodium, potassium, and several other elements by electrolysis. Within a few decades, batteries became the standard laboratory power source and made electroplating, electrolytic chemistry, and the first telegraph circuits practical." },
  { id: "electromagnetism", name: "Electromagnetism", era: "industrial", category: "knowledge",
    year: "1820", prereqs: ["electric-battery", "calculus"],
    desc: "Hans Christian Ørsted's 1820 discovery that electric currents deflect magnetic compass needles linked the two phenomena. Faraday demonstrated electromagnetic induction (1831), making generators and motors possible. Maxwell's four equations (1861–1865) unified electricity, magnetism, and light as a single phenomenon — electromagnetic waves traveling at c — and predicted radio waves before they had ever been generated. The theory underwrites every electrical and electronic technology." },
  { id: "electric-motor", name: "Electric Motor", era: "industrial", category: "energy",
    year: "1834", prereqs: ["electric-battery", "electromagnetism"],
    desc: "Rotary force generated by electromagnetic induction, with Faraday's 1821 demonstration scaling up through the 19th century to large industrial motors via Tesla's polyphase AC system (1880s). Motors could be placed where work was needed without long shafts and belts, transforming factory layout. By 1920 most industrial machinery in advanced economies was electrically driven, and motors quietly made household appliances — from sewing machines to vacuums to elevators — possible." },
  { id: "telephone", name: "Telephone", era: "industrial", category: "communication",
    year: "1876", prereqs: ["telegraph", "electromagnetism"],
    desc: "Alexander Graham Bell's 1876 patent on transmitting voice as varying electrical current along a wire, contested by Elisha Gray. Bell Telephone Company (1877) and AT&T (1885) wired American cities at speed; by 1900 there were 600,000 phones in the U.S., by 1950 over 50 million. The telephone became the first instantaneous person-to-person communication device available to ordinary households and the basis of the entire 20th-century telecom infrastructure." },
  { id: "radio-wireless", name: "Radio", era: "industrial", category: "communication",
    year: "1895", prereqs: ["electromagnetism", "telegraph"],
    desc: "Marconi's 1895 wireless transmissions across his Bologna estate, then 1901 across the Atlantic. The Hertzian electromagnetic waves that Maxwell had predicted now carried signal without wires. Within twenty years radio telegraphy was on every ship, by 1920 broadcast voice and music had begun (KDKA Pittsburgh), and by 1939 radio was the dominant mass medium worldwide. Radio also seeded the technical traditions for radar, television, and modern wireless networks." },
  { id: "photography", name: "Photography", era: "industrial", category: "communication",
    year: "1839", prereqs: ["chemistry-modern", "glass-lens"],
    desc: "Daguerre's 1839 silver-iodide-on-copper plates and Talbot's competing calotype paper negatives. Within a decade portrait studios proliferated and the daguerreotype became affordable for middle-class Victorians. Eastman's Kodak (1888) made photography pocketable and amateur ('You press the button, we do the rest'). Photography transformed visual culture, documentation, science (microscopy, astronomy), and journalism, and seeded the 20th-century explosion of cinema and television." },
  { id: "cinema", name: "Cinema", era: "industrial", category: "communication",
    year: "1895", prereqs: ["photography", "opera-orchestra"],
    desc: "The Lumière brothers' 1895 Cinématographe projected moving images to a paying audience in Paris — Workers Leaving the Lumière Factory and the train arriving at La Ciotat. Within twenty years cinema was a global mass medium, by 1930 sound film was standard, and by 1950 Hollywood was the world's largest entertainment industry. Cinema invented or codified continuity editing, montage, the close-up, and the star system." },
  { id: "oil-petroleum", name: "Oil Industry", era: "industrial", category: "energy",
    year: "1859", prereqs: ["chemistry-modern"],
    desc: "Edwin Drake's 1859 well at Titusville, Pennsylvania, demonstrated commercial petroleum extraction. By 1870 Rockefeller's Standard Oil controlled most American refining; by 1900 oil had become the leading fuel for ships and the new motor-cars. The Spindletop strike (1901), Ploesti, Baku, and Saudi Aramco's Ghawar (1948) progressively redrew the world energy map. A century of cheap, dense, transportable energy underwrote the 20th-century economy." },
  { id: "internal-combustion", name: "Internal Combustion Engine", era: "industrial", category: "energy",
    year: "1876", prereqs: ["steam-engine-watt", "chemistry-modern", "oil-petroleum"],
    desc: "Nikolaus Otto's 1876 four-stroke cycle engine — intake, compression, power, exhaust — was the breakthrough that made petroleum-powered transport practical. Diesel's compression-ignition variant (1893) followed. The power-to-weight ratio of internal combustion vastly exceeded steam, opening the door to automobiles, aircraft, and motorboats. By 1950 internal-combustion engines outnumbered every other prime mover on Earth except electric motors." },
  { id: "automobile", name: "Automobile", era: "industrial", category: "transport",
    year: "1886", prereqs: ["internal-combustion", "bessemer-steel"],
    desc: "Karl Benz's 1886 Patent-Motorwagen — three wheels, single-cylinder engine, ~16 km/h — was the first commercial automobile. Daimler's parallel work and the Panhard-Levassor layout (engine in front, drive to rear) refined the form. Within fifty years automobiles reshaped cities, commerce, and culture; by 2000 there were over 800 million on the planet. The car redefined personal mobility and is also the single largest 20th-century driver of suburbanization, oil demand, and CO₂ emissions." },
  { id: "bicycle", name: "Safety Bicycle", era: "industrial", category: "transport",
    year: "1885", prereqs: ["bessemer-steel", "gear-mechanism"],
    desc: "John Kemp Starley's 1885 'safety bicycle' — equal-wheel, chain-driven, with pneumatic tires (Dunlop, 1888) — combined into the modern bicycle. Cheap personal mobility transformed commuting, courtship, and women's mobility (Susan B. Anthony said the bicycle 'has done more to emancipate women than anything else'). The bicycle also pioneered the manufacturing precision (ball bearings, drawn steel tubing) that would feed directly into the early automobile and aviation industries." },
  { id: "evolution-darwin", name: "Theory of Evolution", era: "industrial", category: "knowledge",
    year: "1859", prereqs: ["scientific-method", "selective-breeding"],
    desc: "Darwin and Wallace's joint 1858 papers and Darwin's On the Origin of Species (1859) proposed that species change over time through natural selection acting on heritable variation. The theory unified all of biology, replaced essentialist species concepts with population thinking, and proved compatible with Mendelian genetics in the 1930s 'Modern Synthesis'. Evolutionary biology is the framework within which every later biological discovery — including molecular biology and ecology — is interpreted." },
  { id: "germ-theory", name: "Germ Theory", era: "industrial", category: "medicine",
    year: "1860", prereqs: ["germ-precursor", "evolution-darwin"],
    desc: "Pasteur's 1860s experiments showing that fermentation and disease are caused by specific microorganisms, plus Koch's identification of the anthrax, tuberculosis, and cholera bacilli (1876–1884). Koch's postulates established the methodology for proving a microbe causes a disease. Combined with Lister's antiseptic surgery and broad public-health reforms, germ theory ended the dominance of cholera and typhoid in cities and inaugurated modern medicine and public health." },
  { id: "antiseptic-surgery", name: "Antiseptic Surgery", era: "industrial", category: "medicine",
    year: "1867", prereqs: ["germ-theory"],
    desc: "Joseph Lister's 1867 carbolic acid spray and dressings, applied at Glasgow Royal Infirmary, dropped post-surgical mortality from ~50% to under 15% within a few years. Building on Pasteur's germ theory, Lister cleaned wounds, instruments, and surgeons' hands. Combined with anesthesia, antisepsis transformed surgery from a desperate last resort into a routine therapy and made later operations — abdominal, cardiac, transplant — practically possible." },
  { id: "anesthesia", name: "Anesthesia", era: "industrial", category: "medicine",
    year: "1846", prereqs: ["chemistry-modern", "anatomy-vesalius"],
    desc: "William Morton's 1846 ether demonstration at Massachusetts General Hospital and James Simpson's 1847 chloroform let surgeons operate on insensate patients for the first time. Pre-anesthesia surgery had to be brutally fast — the wonder is that it was ever undertaken. Anesthesia let surgeons proceed methodically, dramatically expanded the procedures that were possible, and turned surgery into a planned rather than emergency activity." },
  { id: "public-sanitation", name: "Sanitation Engineering", era: "industrial", category: "medicine",
    year: "1865", prereqs: ["germ-theory", "aqueduct"],
    desc: "Sewers, water-treatment plants, and urban hygiene legislation that ended cholera and typhoid as routine urban scourges. London's sewer system (Bazalgette, 1858–1875) followed the Great Stink of 1858; New York and Paris built parallel infrastructures. By 1900, life expectancy in major Western cities had risen by 10–15 years from sanitation alone — arguably the largest health gain ever from a single intervention." },
  { id: "vaccination-mass", name: "Mass Vaccination", era: "industrial", category: "medicine",
    year: "1880", prereqs: ["vaccination", "germ-theory"],
    desc: "Pasteur's attenuated rabies (1885) and anthrax vaccines extended Jenner's principle to many other diseases. Twentieth-century vaccines against diphtheria, tetanus, pertussis, polio, measles, and others reduced their incidence by >99% in countries with strong vaccination programs. Smallpox was eradicated by 1980 — the only human disease ever eradicated. Vaccination is plausibly the single largest source of the dramatic 20th-century improvement in child survival." },
  { id: "thermodynamics", name: "Thermodynamics", era: "industrial", category: "knowledge",
    year: "1850", prereqs: ["steam-engine-watt", "calculus", "thermometer"],
    desc: "Sadi Carnot (1824), then Clausius and Lord Kelvin (1850s), formalized the laws governing heat, work, and entropy. The first law (energy conservation) and the second law (entropy increases) explained why the Watt steam engine had practical efficiency limits and led to better engine design. Boltzmann's statistical interpretation tied thermodynamics to atomic physics. Modern engineering, chemistry, biology, and cosmology all rest on thermodynamic principles." },
  { id: "periodic-table", name: "Periodic Table", era: "industrial", category: "knowledge",
    year: "1869", prereqs: ["chemistry-modern"],
    desc: "Dmitri Mendeleev's 1869 arrangement of elements by atomic mass, with gaps where he predicted undiscovered elements — gallium, scandium, germanium — soon found with the predicted properties. The table revealed deep structure in chemistry, later understood (post-Bohr) as electron-shell organization. Mendeleev's table is the single most useful chart in any science: it codifies and predicts an enormous body of facts in one glance." },
  { id: "atomic-theory", name: "Atomic Theory", era: "industrial", category: "knowledge",
    year: "1808", prereqs: ["chemistry-modern"],
    desc: "John Dalton (1808) revived atomism on quantitative chemical evidence; J.J. Thomson (1897) found the electron; Rutherford's gold-foil scattering (1911) showed atoms have small dense nuclei; Bohr (1913) explained spectral lines with quantized orbits. By the 1920s atoms had become the best-confirmed object in physics — invisible to the eye but central to chemistry, materials science, and ultimately quantum theory." },
  { id: "electron-discovery", name: "Electron", era: "industrial", category: "knowledge",
    year: "1897", prereqs: ["atomic-theory", "electromagnetism"],
    desc: "J.J. Thomson's 1897 cathode-ray experiments at the Cavendish Laboratory showed cathode rays were streams of negatively charged particles ~1/2000 the mass of a hydrogen atom. The electron was the first sub-atomic particle identified, and its discovery destroyed the centuries-old assumption that atoms were indivisible. Robert Millikan's oil-drop experiment (1909) measured its charge precisely and confirmed charge quantization." },
  { id: "x-ray", name: "X-Ray", era: "industrial", category: "medicine",
    year: "1895", prereqs: ["electromagnetism", "atomic-theory"],
    desc: "Wilhelm Röntgen's 1895 accidental discovery of penetrating radiation that exposed photographic film through opaque objects, including a famous image of his wife's hand showing her wedding ring. Within months X-rays were being used clinically to image broken bones and bullet locations. The discovery launched diagnostic radiology, opened the field of crystallography (Bragg, 1912), and established the high-energy electromagnetic spectrum as a real phenomenon to be explored." },
  { id: "machine-tool", name: "Machine Tools", era: "industrial", category: "tools",
    year: "1820", prereqs: ["factory-system"],
    desc: "Lathes, planers, milling machines, shapers, and gear-cutters that work metal to engineered specifications, themselves made by other machine tools. Henry Maudslay (~1800) and Joseph Whitworth (1840s) standardized screw threads and surface flatness. Machine tools — machines that make machines — are the meta-technology underwriting all subsequent manufactured precision: railroads, ships, automobiles, aircraft, and computers." },
  { id: "interchangeable-parts", name: "Interchangeable Parts", era: "industrial", category: "tools",
    year: "1820", prereqs: ["machine-tool", "factory-system"],
    desc: "Eli Whitney's 1798 musket contract for the U.S. Army was meant to demonstrate parts that could be swapped freely; the manufacturing reality lagged the rhetoric, but by John Hall's Harpers Ferry rifles (1820s) it was achieved. Mass repair, standardized assembly, and the eventual assembly line all rest on this principle. Without interchangeable parts there is no Ford, no Boeing, no Toyota Production System." },
  { id: "assembly-line", name: "Assembly Line", era: "industrial", category: "economy",
    year: "1913", prereqs: ["interchangeable-parts", "factory-system", "power-loom"],
    desc: "Henry Ford's moving-line at Highland Park (1913) reduced Model T assembly time from 12 hours to 93 minutes, dropping the price from $850 (1908) to $260 (1925). Workers stayed in place while the chassis moved past them, each performing one operation. The Ford system spread worldwide as 'Fordism', made cars and consumer durables affordable to the working class, and shaped 20th-century manufacturing through the Toyota Production System and modern lean manufacturing." },
  { id: "modern-corporation", name: "Modern Corporation", era: "industrial", category: "economy",
    year: "1880", prereqs: ["joint-stock-company", "factory-system", "modern-bookkeeping"],
    desc: "Limited-liability hierarchical firms with professional managers separate from owners. Standard Oil (1870), U.S. Steel (1901), General Electric (1892), and the German cartels of the same period defined the form. The modern corporation made multi-billion-dollar capital projects possible, drove the early 20th-century rise in living standards, and also generated the regulatory backlash (antitrust, securities law) that defines mature industrial capitalism." },
  { id: "labor-union", name: "Labor Union", era: "industrial", category: "economy",
    year: "1850", prereqs: ["factory-system", "liberal-democracy"],
    desc: "Organized collective bargaining by workers, gaining legal recognition through 19th- and 20th-century struggles: the Combination Acts (UK), Knights of Labor and AFL (U.S.), Trades Union Congress (UK), and continental syndicalism. Unions won the eight-hour day, weekend, child-labor abolition, workplace-safety law, and unemployment insurance. They also became powerful political constituencies whose alliances with social-democratic parties shaped 20th-century welfare states." },
  { id: "newspaper-mass", name: "Mass Newspaper", era: "industrial", category: "communication",
    year: "1850", prereqs: ["printing-press", "telegraph"],
    desc: "Penny papers (Sun, NY, 1833; Tribune; Times) replaced the partisan/elite press with mass-circulation dailies financed by advertising. Wire services (Reuters 1851, AP 1846) supplied national and international news to local papers. By 1900 most Western adults read a paper daily. The mass press created the modern public, public opinion polling targets, and shared national narratives — and also yellow journalism, propaganda, and circulation wars that would shape 20th-century political crises." },
  { id: "skyscraper", name: "Skyscraper", era: "industrial", category: "shelter",
    year: "1885", prereqs: ["bessemer-steel", "electric-motor", "elevator"],
    desc: "Steel-frame construction (load on internal skeleton, not load-bearing walls) plus elevators allowed buildings to climb past stone's ~10-story limit. Chicago's Home Insurance Building (1885) is usually cited as the first; New York's Flatiron (1902), Woolworth (1913), Chrysler (1930), and Empire State (1931) raced upward in successive decades. Skyscrapers concentrated commerce vertically, redefined urban skylines, and required the lift, telephone, and central HVAC to be functional." },
  { id: "elevator", name: "Safety Elevator", era: "industrial", category: "tools",
    year: "1857", prereqs: ["bessemer-steel", "electric-motor"],
    desc: "Elisha Otis's 1853 safety brake — which gripped the rails if the cable broke — made vertical transport psychologically acceptable. The first passenger elevator was installed at New York's Haughwout Building (1857). Without safe elevators, skyscrapers couldn't function: every floor above the fourth would be unrentable. Otis Elevator (founded 1853) remained the dominant maker for over a century." },
  { id: "machine-gun", name: "Machine Gun", era: "industrial", category: "weapons",
    year: "1884", prereqs: ["artillery", "interchangeable-parts", "musket"],
    desc: "Hiram Maxim's 1884 recoil-operated water-cooled gun fired 600 rounds/minute from a single barrel. Earlier hand-cranked Gatling guns (1862) had pointed the way. Maxim guns and successors (Vickers, MG08, M1917) made cavalry charges suicidal and entrenched the Western Front of WWI. Industrial-scale lethality with one operator made every army's pre-1914 tactical doctrine obsolete and reshaped the experience of war for the rest of the 20th century." },
  { id: "electrification", name: "Grid Electrification", era: "industrial", category: "energy",
    year: "1882", prereqs: ["electric-motor", "electromagnetism"],
    desc: "Edison's 1882 Pearl Street Station (DC) lit lower Manhattan; Tesla and Westinghouse's competing AC system (1880s–90s) won the 'War of Currents' for long-distance transmission. Public utilities, holding companies, and Government Electric Co. (later GE) industrialized power supply. By 1925 most urban Western homes had electricity; by 1955 most rural farms (after the U.S. Rural Electrification Act). Electrification redefined work, leisure, agriculture, and the home." },

  // ─── Modern ────────────────────────────────────────────────────
  { id: "airplane", name: "Airplane", era: "modern", category: "transport",
    year: "1903", prereqs: ["internal-combustion", "bicycle"],
    desc: "Wilbur and Orville Wright's December 17, 1903 flight at Kitty Hawk, North Carolina — 12 seconds, 36 meters — was the first sustained, controlled, powered, heavier-than-air human flight. Their breakthrough was three-axis control via wing-warping and rudder coordination. By 1909 Bleriot had crossed the English Channel; by 1927 Lindbergh crossed the Atlantic; by the 1950s the jet airliner brought intercontinental travel to ordinary people." },
  { id: "relativity", name: "Relativity", era: "modern", category: "knowledge",
    year: "1905", prereqs: ["electromagnetism", "thermodynamics", "gravitation-law"],
    desc: "Einstein's 1905 special relativity (constant speed of light, time dilation, mass-energy equivalence E=mc²) and 1915 general relativity (gravity as curvature of spacetime). General relativity has been verified by the bending of starlight near the Sun (1919 eclipse), gravitational time dilation (atomic clocks), gravitational lensing, the perihelion of Mercury, and gravitational waves (LIGO 2015). It is the framework underlying modern cosmology and GPS." },
  { id: "quantum-mechanics", name: "Quantum Mechanics", era: "modern", category: "knowledge",
    year: "1925", prereqs: ["atomic-theory", "relativity"],
    desc: "Heisenberg's matrix mechanics (1925), Schrödinger's wave equation (1926), and Dirac's relativistic synthesis (1928) established the mathematical formalism describing atomic-scale matter. Bohr's complementarity, Heisenberg's uncertainty principle, and the Born rule replaced classical determinism with probabilistic predictions. Quantum mechanics underwrites essentially all post-1950 technology — semiconductors, lasers, MRI, atomic clocks, modern chemistry — and remains experimentally unfalsified." },
  { id: "radar", name: "Radar", era: "modern", category: "knowledge",
    year: "1935", prereqs: ["radio-wireless", "electromagnetism"],
    desc: "Radio echo-location of aircraft and ships, developed independently in Britain, Germany, the U.S., and the Soviet Union in the 1930s. The British Chain Home network gave RAF Fighter Command 20+ minutes of warning during the Battle of Britain (1940), arguably decisive. Radar also seeded the microwave electronics traditions that gave us the magnetron (cavity magnetron, microwave oven), early radio astronomy, and ultimately modern wireless communications." },
  { id: "helicopter", name: "Helicopter", era: "modern", category: "transport",
    year: "1939", prereqs: ["airplane"],
    desc: "Igor Sikorsky's VS-300 (1939) was the first practical single-rotor helicopter with anti-torque tail rotor. By 1944 the R-4 was in U.S. military service. Helicopters fly into where airplanes can't — hovering, vertical takeoff, mountain rescue, urban transport. They became iconic in Korea and Vietnam (medevac), in oil exploration, and in modern emergency medicine, where the 'golden hour' for trauma victims often depends on rotor-wing transport." },
  { id: "jet-engine", name: "Jet Engine", era: "modern", category: "transport",
    year: "1939", prereqs: ["airplane", "thermodynamics"],
    desc: "Frank Whittle's gas-turbine engine (UK, patented 1930, first run 1937) and Hans von Ohain's parallel German design (1939) made high-altitude high-speed flight practical. The Gloster Meteor and Me 262 saw combat in WWII. Jets doubled airliner cruise speeds (~900 km/h) and altitudes (~11 km) by the 1960s, putting Australia about a day from Europe and revolutionizing long-distance travel." },
  { id: "rocket", name: "Liquid-Fuel Rocket", era: "modern", category: "transport",
    year: "1942", prereqs: ["jet-engine", "chemistry-modern"],
    desc: "Wernher von Braun's V-2 (Germany, 1944) was the first artificial object to reach space (officially 100 km), built by slave labor at Mittelwerk and used to bomb London. After WWII Soviet (Korolev) and American (von Braun) descendants of the V-2 produced the R-7, Atlas, Saturn, and Soyuz families. Rockets — initially weapons of terror — became the ladder by which humans reached orbit, the Moon, and the rest of the solar system." },
  { id: "nuclear-fission", name: "Nuclear Fission", era: "modern", category: "energy",
    year: "1938", prereqs: ["quantum-mechanics", "electron-discovery"],
    desc: "Hahn and Strassmann's December 1938 chemical demonstration that uranium bombarded with neutrons split into barium and krypton, with Lise Meitner and Otto Frisch's January 1939 theoretical interpretation. Fission released ~10⁷× more energy per kilogram than chemical reactions. Fermi's Chicago Pile-1 (December 1942) achieved the first controlled chain reaction. Within three years fission had been weaponized, ending the Pacific war." },
  { id: "nuclear-weapon", name: "Nuclear Weapon", era: "atomic", category: "weapons",
    year: "1945", prereqs: ["nuclear-fission"],
    desc: "The Manhattan Project's Trinity test (July 16, 1945, New Mexico) and the bombings of Hiroshima (Little Boy, uranium gun-type) and Nagasaki (Fat Man, plutonium implosion) in August 1945. Hydrogen-fusion (thermonuclear) weapons followed in 1952. Nuclear weapons reshaped grand strategy, sovereignty (the nuclear-armed state is in a different category), and existential risk. The Cold War balance of mutually assured destruction kept superpower war cold for forty-five years." },
  { id: "nuclear-power", name: "Nuclear Power", era: "atomic", category: "energy",
    year: "1954", prereqs: ["nuclear-fission"],
    desc: "Civilian fission reactors generating electricity, beginning with Obninsk (USSR, 1954, 5 MW) and Calder Hall (UK, 1956). At peak (~1996) nuclear supplied ~17% of world electricity. Three Mile Island (1979), Chernobyl (1986), and Fukushima (2011) shaped public attitudes; meanwhile the unsolved problem of long-term waste storage and the high capital cost of new builds have constrained expansion. France remains a major nuclear power, Germany has phased out, and modular reactors are under active development." },
  { id: "antibiotics", name: "Antibiotics", era: "modern", category: "medicine",
    year: "1928", prereqs: ["germ-theory", "chemistry-modern"],
    desc: "Alexander Fleming's 1928 observation that Penicillium mold killed Staphylococcus colonies; mass production by Florey, Chain, and the U.S. wartime program (1942–1945). Streptomycin (1944), tetracycline (1953), and successive families followed. Bacterial infection — leading cause of death for most of human history — became routinely treatable. Antibiotic resistance, driven by overuse, is now a serious and growing public-health threat." },
  { id: "vaccines-modern", name: "Modern Vaccines", era: "atomic", category: "medicine",
    year: "1955", prereqs: ["vaccination-mass", "germ-theory"],
    desc: "Salk's killed-virus polio vaccine (1955) and Sabin's live oral version (1961) eliminated most polio in industrialized countries; Maurice Hilleman developed dozens of major vaccines including measles, mumps, rubella, hepatitis B, and chickenpox. Smallpox eradication completed in 1980 was the first time humans deliberately drove a disease extinct. Polio is currently endemic in only Afghanistan and Pakistan; measles incidence has been cut by >99% in vaccinated populations." },
  { id: "dna-structure", name: "DNA Double Helix", era: "atomic", category: "knowledge",
    year: "1953", prereqs: ["x-ray", "evolution-darwin"],
    desc: "Watson, Crick, Franklin, and Wilkins's 1953 model of the DNA double helix, based on Franklin's X-ray Photo 51 and Chargaff's base-pairing rules. The structure immediately suggested both how genetic information was encoded (sequence of bases) and how it was copied (template-directed replication). Within a generation the genetic code was deciphered, recombinant DNA was possible, and the road to genome sequencing was open." },
  { id: "synthetic-fertilizer", name: "Haber–Bosch Process", era: "modern", category: "subsistence",
    year: "1913", prereqs: ["chemistry-modern", "agricultural-revolution"],
    desc: "Fritz Haber's 1909 ammonia synthesis from atmospheric nitrogen and hydrogen at high pressure, scaled up by Carl Bosch at BASF (Haber-Bosch process, 1913). Nitrogen fertilizer freed agriculture from the limits of natural nitrogen fixation by legumes and bird-droppings. Roughly half of the nitrogen atoms in your body passed through a Haber-Bosch reactor. The process feeds an estimated half of the world's current population." },
  { id: "green-revolution", name: "Green Revolution", era: "atomic", category: "subsistence",
    year: "1960", prereqs: ["synthetic-fertilizer", "selective-breeding", "crop-rotation-norfolk"],
    desc: "Norman Borlaug's high-yielding semi-dwarf wheat (Mexico, 1950s), and the IRRI's IR8 rice (Philippines, 1966), packaged with synthetic fertilizers, irrigation, and pesticides, multiplied cereal yields across South Asia and Latin America. India tripled wheat production between 1965 and 1980. The Green Revolution is widely credited with averting hundreds of millions of famine deaths, though its environmental and equity costs have driven later debates about agricultural sustainability." },
  { id: "plastic-polymer", name: "Plastics", era: "modern", category: "tools",
    year: "1907", prereqs: ["chemistry-modern", "oil-petroleum"],
    desc: "Leo Baekeland's 1907 Bakelite — phenol formaldehyde polymer — was the first fully synthetic plastic. Polyethylene (1933, ICI), nylon (1935, DuPont), PVC, polystyrene, polypropylene, and PET followed in succession. By 2020 global plastic production exceeded 380 million tons annually. Plastics are cheap, moldable, durable, light — and stubbornly persistent in the environment, with microplastic contamination now found from deep oceans to human placenta." },
  { id: "transistor", name: "Transistor", era: "atomic", category: "tools",
    year: "1947", prereqs: ["quantum-mechanics", "electron-discovery"],
    desc: "Bardeen, Brattain, and Shockley's December 1947 Bell Labs point-contact transistor, replacing the vacuum tube with a solid-state amplifier ~100× smaller and far more reliable. The 1956 Nobel Prize followed. Transistors made portable radios (1954), digital computers practical, and ultimately the entire integrated-circuit revolution possible. They are arguably the single most consequential 20th-century invention." },
  { id: "semiconductor", name: "Integrated Circuit", era: "atomic", category: "tools",
    year: "1958", prereqs: ["transistor"],
    desc: "Jack Kilby (Texas Instruments, 1958) and Robert Noyce (Fairchild, 1959) independently invented the integrated circuit — multiple transistors on one silicon die, photolithographically patterned. Moore's Law (1965) — transistor counts doubling roughly every two years — held for over fifty years. Today's chips contain tens of billions of transistors and are made by TSMC, Samsung, and Intel using extreme ultraviolet lithography at near-atomic precision." },
  { id: "digital-computer", name: "Digital Computer", era: "atomic", category: "knowledge",
    year: "1945", prereqs: ["machine-tool", "mathematics-arithmetic"],
    desc: "ENIAC (1945, Eckert and Mauchly, U.S.) was the first general-purpose electronic computer; Colossus (1943, UK) preceded it but was secret. The von Neumann architecture (1945) — stored program, sequential execution — defined the form. Alan Turing's theoretical work (1936) had already established the concept of universal computation. Within decades the digital computer absorbed essentially every kind of information processing humans had previously done by hand." },
  { id: "programming-language", name: "Programming Languages", era: "atomic", category: "communication",
    year: "1957", prereqs: ["digital-computer"],
    desc: "FORTRAN (Backus, 1957), LISP (McCarthy, 1958), COBOL (Hopper, 1959), ALGOL (1958–60), and the C language (Ritchie, 1972) made programming a discipline with formal grammars and tools rather than raw machine-code patching. Higher-level abstractions — variables, functions, objects, type systems — let programmers tackle ever-larger systems. Today's billions of lines of code in production are descendants of these foundational languages." },
  { id: "mainframe", name: "Mainframe", era: "atomic", category: "tools",
    year: "1964", prereqs: ["digital-computer", "semiconductor"],
    desc: "IBM's System/360 family (1964) unified IBM's product line under one architecture, runnable across a range of price-performance points. The S/360 sold so well that it underwrote IBM's dominance of corporate computing for decades. Mainframes became the back-office of banks, airlines, insurers, and governments — and they remain there: most credit-card transactions and many airline bookings still touch a mainframe today." },
  { id: "television", name: "Television", era: "modern", category: "communication",
    year: "1928", prereqs: ["cinema", "radio-wireless"],
    desc: "Vladimir Zworykin's iconoscope (1923) and Philo Farnsworth's image dissector (1927) provided competing electronic scanning systems; the BBC began regular broadcasts in 1936. After WWII, TV diffused through Western households in a generation: ~10% of U.S. homes in 1950, 90% by 1962. Television became the dominant 20th-century mass medium, structuring news, entertainment, advertising, and politics, until streaming media displaced broadcast in the 2010s." },
  { id: "satellite", name: "Artificial Satellite", era: "atomic", category: "communication",
    year: "1957", prereqs: ["rocket", "radio-wireless"],
    desc: "Sputnik 1 (USSR, October 4, 1957) — a 58 cm aluminum sphere transmitting beeps — terrified the West and triggered the space race. Within a decade satellites had become essential for communications (Telstar, 1962), reconnaissance (Corona), weather forecasting, and navigation (Transit, then GPS). The Hubble Space Telescope (1990) and the James Webb (2021) showed how powerful science satellites could be." },
  { id: "spaceflight", name: "Human Spaceflight", era: "atomic", category: "transport",
    year: "1961", prereqs: ["rocket", "satellite"],
    desc: "Yuri Gagarin's April 12, 1961 flight aboard Vostok 1 — one orbit, 108 minutes — made him the first human in space. Alan Shepard followed in May. Crewed spaceflight expanded with Mercury, Gemini, Apollo, Soyuz, the shuttle, the ISS, and now Crew Dragon and Starship. Roughly 700 humans have flown to space; the ISS has been continuously inhabited since November 2000." },
  { id: "moon-landing", name: "Moon Landing", era: "atomic", category: "transport",
    year: "1969", prereqs: ["spaceflight", "digital-computer"],
    desc: "Apollo 11's July 20, 1969 lunar landing put Neil Armstrong and Buzz Aldrin on the Sea of Tranquility while Michael Collins orbited above. Five further landings followed (Apollos 12 and 14–17), with twelve men walking on the Moon, the last in December 1972. The program cost ~$280 billion in 2020 dollars and remains the high-water mark of crewed exploration; the Artemis program now aims to return humans to the lunar surface." },
  { id: "mass-media", name: "Mass Media", era: "atomic", category: "communication",
    year: "1950", prereqs: ["television", "newspaper-mass"],
    desc: "Radio, television, and magazines integrated into a unified cultural pipeline reaching tens of millions of listeners and viewers daily. Public broadcasters (BBC, NHK) and commercial networks (NBC, CBS, ABC) shaped national conversations from the 1930s through the 1990s, with shared evening news constructing common factual ground. The pattern fragmented after cable, then collapsed with streaming and social media, leaving the contemporary 'high-choice' media environment." },
  { id: "consumer-economy", name: "Consumer Economy", era: "atomic", category: "economy",
    year: "1950", prereqs: ["assembly-line", "mass-media"],
    desc: "Mass production combined with mass advertising, suburbanization, and consumer credit. Postwar Western economies — particularly the U.S. — institutionalized cars, appliances, single-family homes, and lifestyle aspirations as the markers of the good life. Walmart (1962), Sears, and supermarket chains scaled the format. The same logic later propagated globally, with East Asia, then India and China, replicating the consumer-economy pattern at progressively larger scales." },
  { id: "credit-card", name: "Credit Card", era: "atomic", category: "economy",
    year: "1958", prereqs: ["modern-corporation", "telephone"],
    desc: "BankAmericard (1958, later Visa) and the Diners Club (1950) revolving consumer credit, decoupled from any single merchant. Mastercard (1966) and American Express expanded the field. Credit cards reorganized retail (immediate authorization, fewer cash transactions), built the modern consumer-credit economy, and produced multinational payment networks that became critical infrastructure." },
  { id: "container-shipping", name: "Container Shipping", era: "atomic", category: "transport",
    year: "1956", prereqs: ["steamship", "assembly-line"],
    desc: "Malcom McLean's 1956 standardized intermodal container — uniform 20- or 40-foot steel boxes that move seamlessly from ship to truck to rail. Container ports, container ships (now up to 24,000 TEU), and intermodal yards collapsed freight handling costs by ~95%. Containerization is the unglamorous logistics infrastructure that enabled globalization: most consumer goods you own probably traveled in one." },
  { id: "highway-system", name: "Interstate Highway", era: "atomic", category: "transport",
    year: "1956", prereqs: ["automobile", "internal-combustion", "turnpike-roads", "railroad-network"],
    desc: "Limited-access national road networks: Italy's autostrade (1924), Germany's Autobahn (1932), and the U.S. Interstate Highway System under Eisenhower (1956 onward, 77,000 km). Highways collapse intercity travel times, reshape settlement patterns (suburbs, exurbs, edge cities), and reorganize freight from rail to truck. They also concrete in dependence on automobiles and oil that 21st-century climate policy is now grappling with." },
  { id: "welfare-state", name: "Welfare State", era: "atomic", category: "economy",
    year: "1945", prereqs: ["liberal-democracy", "public-education", "labor-union", "separation-of-powers"],
    desc: "Government provision of social insurance, public healthcare, pensions, unemployment benefits, and family support. Bismarck's German social legislation (1880s) was the prototype; the British Beveridge Report (1942) and postwar Labour government created the NHS (1948); Scandinavian models pushed furthest. Welfare states reduced poverty among the elderly and unemployed dramatically, became defining markers of postwar liberal democracy, and remain politically contested over scope and funding." },
  { id: "decolonization", name: "Decolonization", era: "atomic", category: "economy",
    year: "1947", prereqs: ["nation-state", "world-religion"],
    desc: "Dissolution of European colonial empires after 1945. Indian independence (1947) opened the wave; African decolonization peaked in 1960 ('Year of Africa'); the last Portuguese colonies became independent in 1975. Decolonization created over a hundred new nation-states, restructured the United Nations, and reshaped global politics. The economic and political legacies of colonization continue to shape former colonies — and the international system itself." },
  { id: "united-nations", name: "International Order", era: "atomic", category: "economy",
    year: "1945", prereqs: ["liberal-democracy"],
    desc: "The UN (founded 1945, San Francisco), IMF and World Bank (Bretton Woods 1944), GATT/WTO (1948/1995), and dozens of specialized agencies (WHO, UNESCO) created a multilateral framework for security, trade, and development. Alongside Cold War realpolitik, this system underwrote ~80 years without world war, the steady (if uneven) reduction of poverty, the rise of human-rights frameworks, and the climate negotiations of the late 20th century onward." },
  { id: "birth-control", name: "Hormonal Contraception", era: "atomic", category: "medicine",
    year: "1960", prereqs: ["chemistry-modern", "vaccines-modern"],
    desc: "The combined oral contraceptive pill — Enovid, approved by the FDA in 1960 — gave women reliable, female-controlled fertility regulation. Within two decades the Pill had become the most popular contraceptive in much of the world. It enabled women's mass entry into higher education and skilled work, dropped fertility rates across rich countries, and profoundly reshaped marriage, family, and gender norms." },
  { id: "air-conditioning", name: "Air Conditioning", era: "modern", category: "tools",
    year: "1902", prereqs: ["electric-motor", "chemistry-modern"],
    desc: "Willis Carrier's 1902 mechanical refrigeration of indoor air — initially developed to control humidity at a Brooklyn printing plant — became standard in commercial buildings by mid-century and in American homes by the 1970s. Air conditioning made the U.S. Sun Belt habitable for mass population, allowed computers to run reliably indoors, and enabled architectural styles (sealed glass towers, large open offices) that would otherwise be unbearable." },

  // ─── Information ───────────────────────────────────────────────
  { id: "microprocessor", name: "Microprocessor", era: "information", category: "tools",
    year: "1971", prereqs: ["transistor", "semiconductor"],
    desc: "Intel 4004 (1971, designed by Federico Faggin, Ted Hoff, and Stan Mazor) put a complete CPU on a single chip with 2,300 transistors running at 740 kHz. The 8080 (1974) and Motorola 6800 (1974) followed. By embedding compute into a single low-cost component, microprocessors made personal computers, game consoles, embedded systems, automobiles, and ultimately every modern device with electronics possible." },
  { id: "advanced-chip-manufacturing", name: "Advanced Chip Manufacturing", era: "information", category: "tools",
    year: "2018", prereqs: ["microprocessor", "machine-tool"],
    desc: "Sub-10nm CMOS fabrication using extreme ultraviolet (EUV) lithography, FinFET and gate-all-around transistor architectures, and chemical-mechanical polishing at near-atomic precision. ASML's Dutch-built EUV scanners (single machines costing over $200M, with mirrors smoother than anything else ever manufactured) are the gating technology, and only TSMC, Samsung, and Intel currently operate leading-edge nodes. The capability concentrates global compute supply in a handful of fabs, has become a central concern of 21st-century geopolitics, and underwrites both the modern smartphone and the AI training boom." },
  { id: "personal-computer", name: "Personal Computer", era: "information", category: "tools",
    year: "1977", prereqs: ["microprocessor", "mainframe"],
    desc: "Apple II (1977), Commodore PET (1977), TRS-80 (1977), and IBM PC (1981) brought computing out of corporate data centers and into homes and small offices. The IBM PC's open architecture spawned the clone industry that drove costs down and standardized x86. By 1990, ~50 million PCs were in use; by 2000, computing had become a personal rather than institutional activity. Microsoft and Intel were the era's biggest beneficiaries." },
  { id: "gui-mouse", name: "Graphical Interface", era: "information", category: "communication",
    year: "1984", prereqs: ["personal-computer"],
    desc: "Doug Engelbart's 1968 'Mother of All Demos' showed the mouse, hyperlinks, video conferencing, and collaborative editing in one session. Xerox PARC's Alto (1973) refined windows, icons, menus, and pointers (WIMP). Apple's Lisa (1983) and Macintosh (1984), then Microsoft Windows (1985), brought GUI computing to mass markets. The result: computers usable without a manual." },
  { id: "packet-switching", name: "Packet Switching", era: "information", category: "communication",
    year: "1969", prereqs: ["digital-computer", "programming-language"],
    desc: "Paul Baran (RAND, 1964), Donald Davies (NPL, 1965), and Leonard Kleinrock (UCLA, 1962) independently proposed splitting messages into routed packets traveling independent paths. Resilient (no single point of failure), shared (one wire carries many flows), and statistically efficient. Packet switching is the architectural breakthrough that made the internet possible and now carries essentially all global communication." },
  { id: "arpanet-internet", name: "Internet", era: "information", category: "communication",
    year: "1969", prereqs: ["mainframe", "satellite", "packet-switching"],
    desc: "ARPANET first ran October 29, 1969 between UCLA and Stanford; TCP/IP (Cerf and Kahn, 1974) became the standard in 1983, formally creating 'the Internet'. NSFNET (1985) extended access to universities; commercial ISPs took over from 1995. The internet is the largest engineered system in human history, connecting billions of devices and now mediating most of human communication, commerce, and information." },
  { id: "email", name: "Email", era: "information", category: "communication",
    year: "1971", prereqs: ["arpanet-internet"],
    desc: "Ray Tomlinson's 1971 ARPANET implementation introduced the @ sign as the username/host separator. Within a decade email had become the dominant ARPANET application. The Simple Mail Transfer Protocol (SMTP, 1982) and the universal-inbox idea outlived dozens of competing systems. Asynchronous, archivable, addressable to anyone — email quietly replaced the memo, the letter, and (for many uses) the phone call." },
  { id: "world-wide-web", name: "World Wide Web", era: "information", category: "communication",
    year: "1991", prereqs: ["arpanet-internet", "gui-mouse"],
    desc: "Tim Berners-Lee's 1989 proposal at CERN combined HTTP, HTML, and URLs to make hypertext over the internet a single integrated medium. The first website went live in 1991; Mosaic (1993) brought it to mainstream users; commercial sites exploded after 1995. The web reorganized information access for billions of people and created entirely new industries — search, e-commerce, social media, online media — within fifteen years." },
  { id: "search-engine", name: "Search Engine", era: "information", category: "communication",
    year: "1998", prereqs: ["world-wide-web", "digital-computer"],
    desc: "Google's PageRank (Page and Brin, 1998) ordered the web by link structure rather than keyword density alone, making search dramatically better than AltaVista or Yahoo. Within five years Google was the dominant entry point to the internet for most users. The advertising business model that funded it (AdWords, 2000) became one of the largest industries on Earth, structuring how billions of people now find information." },
  { id: "fiber-optic", name: "Fiber Optic Cable", era: "information", category: "communication",
    year: "1988", prereqs: ["semiconductor", "glass-lens"],
    desc: "Charles K. Kao's 1966 demonstration that ultra-pure glass could carry light signals over kilometers (Nobel 2009) and Corning's 1970 production of low-loss fiber kicked off optical communication. By the 1990s fiber crossed every ocean; today's submarine cables carry essentially all transcontinental internet at terabits per second. A single fiber pair can carry the entire phone traffic of a country." },
  { id: "mobile-phone", name: "Mobile Phone", era: "information", category: "communication",
    year: "1983", prereqs: ["telephone", "microprocessor"],
    desc: "Martin Cooper made the first handheld cellular call in 1973 with a Motorola DynaTAC. Commercial cellular service began in 1983 (DynaTAC 8000X, $4,000). 2G GSM (1991) added text messaging; 3G/4G/5G progressively added data; the phone became the dominant computer for billions of people. Today mobile-only internet users outnumber desktop-only users by a wide margin globally." },
  { id: "smartphone", name: "Smartphone", era: "information", category: "communication",
    year: "2007", prereqs: ["mobile-phone", "world-wide-web", "gui-mouse"],
    desc: "BlackBerry (1999), then iPhone (2007), and Android (2008) integrated cellular, internet browser, multitouch, and a camera into a pocket computer. Within a decade smartphones became the dominant computing form factor: ~6 billion in use by 2024. They reshaped photography, navigation, journalism, payments, dating, taxi service, and the basic meaning of being 'always reachable'. The app economy emerged on top of them." },
  { id: "social-media", name: "Social Media", era: "information", category: "social",
    year: "2004", prereqs: ["world-wide-web"],
    desc: "Friendster (2002), MySpace (2003), Facebook (2004), Twitter (2006), Instagram (2010), TikTok (2016) — feed-based platforms reorganizing public discourse, advertising, identity, and politics around algorithmic recommendations. By 2024 over five billion people used some form of social media. The platforms transformed how news spreads, how movements organize (Arab Spring, MeToo, Black Lives Matter), and how political polarization is driven — for better and substantially worse." },
  { id: "streaming-media", name: "Streaming Media", era: "information", category: "communication",
    year: "2007", prereqs: ["world-wide-web", "semiconductor"],
    desc: "YouTube (2005) and Netflix's streaming pivot (2007), then Spotify (2008), iTunes/Apple Music, and Disney+ delivered media on demand over broadband. Broadcast television and physical music distribution collapsed within fifteen years. Recommendation algorithms became the new programming directors, and 'what to watch' shifted from network schedule to algorithmic feed. Streaming reshaped both how media is produced (binge releases) and how it's monetized (subscription)." },
  { id: "cloud-computing", name: "Cloud Computing", era: "information", category: "tools",
    year: "2006", prereqs: ["arpanet-internet", "mainframe"],
    desc: "Amazon Web Services (S3 and EC2, launched 2006), Microsoft Azure (2010), and Google Cloud rented compute and storage by the hour, eliminating the need to own and maintain servers. Capital expense became operating expense; startups could scale without buying hardware. Mainframes effectively returned, but as utility infrastructure. By 2024, AWS alone was a $100B+ business; cloud now underpins much of the internet and most enterprise IT." },
  { id: "ecommerce", name: "E-Commerce", era: "information", category: "economy",
    year: "1995", prereqs: ["world-wide-web", "credit-card"],
    desc: "Amazon (1994), eBay (1995), Alibaba (1999), and a long tail of category-specific stores moved retail onto the web. By 2024 e-commerce was ~20% of total retail in advanced economies and growing. Same-day delivery, recommendation engines, reviews, and frictionless checkout reshaped consumer expectations. Brick-and-mortar retail — particularly mid-tier department stores and specialty chains — has been hollowed out across most rich countries." },
  { id: "gps", name: "GPS", era: "information", category: "transport",
    year: "1995", prereqs: ["satellite", "microprocessor"],
    desc: "The U.S. Defense Department's NAVSTAR Global Positioning System became fully operational in 1995, with 24+ satellites in medium Earth orbit broadcasting precise time signals. Civilian use exploded after Selective Availability (artificial degradation) was turned off in 2000. GPS now underpins navigation in everything from cars to smartphones to drones to precision farming, and its absence would catastrophically disrupt modern logistics, finance (via timing), and military operations." },
  { id: "gene-sequencing", name: "Genome Sequencing", era: "information", category: "medicine",
    year: "2003", prereqs: ["dna-structure", "digital-computer"],
    desc: "Frederick Sanger's 1977 chain-termination method made DNA sequencing a routine laboratory procedure. The Human Genome Project (1990–2003) sequenced the ~3 billion base pairs of human DNA at a cost of ~$3 billion. Next-generation sequencing (Illumina) since 2007 has dropped per-genome cost to under $1,000. Sequencing now drives medical genomics, pathogen surveillance, evolutionary biology, and conservation genetics." },
  { id: "genetic-engineering", name: "Recombinant DNA", era: "information", category: "medicine",
    year: "1973", prereqs: ["dna-structure"],
    desc: "Paul Berg, Herbert Boyer, and Stanley Cohen's 1973 demonstration of recombinant DNA — splicing genes between organisms using restriction enzymes. Genentech (1976), the first biotech company, used the technique to produce human insulin in bacteria (1978), then human growth hormone, hepatitis B vaccine, and dozens of other proteins. Recombinant DNA opened agricultural biotechnology, gene therapy, and the entire modern biopharmaceutical industry." },
  { id: "crispr", name: "CRISPR", era: "information", category: "medicine",
    year: "2012", prereqs: ["gene-sequencing", "genetic-engineering"],
    desc: "Doudna and Charpentier's 2012 demonstration that the CRISPR-Cas9 bacterial immune system could be reprogrammed to cut any DNA sequence at will (Nobel 2020). Compared to earlier gene-editing tools, CRISPR is fast, cheap, and astonishingly precise. The first approved CRISPR therapy (Casgevy for sickle-cell disease) reached patients in 2023. CRISPR is reshaping biology, agriculture, and medicine — and triggering active debates about germline editing." },
  { id: "mri-imaging", name: "MRI Imaging", era: "information", category: "medicine",
    year: "1977", prereqs: ["x-ray", "digital-computer"],
    desc: "Paul Lauterbur's 1973 demonstration that nuclear magnetic resonance combined with magnetic-field gradients could produce spatial images, refined into clinical technology by Peter Mansfield (Nobel 2003). MRI sees soft tissue without ionizing radiation, has revolutionized diagnosis of brain, joint, and tumor disease, and continues to expand into functional imaging (fMRI), cardiac MRI, and increasingly fast scans for emergency medicine." },
  { id: "ivf", name: "In Vitro Fertilization", era: "information", category: "medicine",
    year: "1978", prereqs: ["birth-control"],
    desc: "Robert G. Edwards and Patrick Steptoe's July 1978 delivery of Louise Brown, the first 'test-tube baby'. The technique combined egg retrieval, in vitro fertilization, and embryo transfer. Edwards received the 2010 Nobel Prize. By 2020 over eight million people had been born by IVF worldwide. The technology also opened the doors to preimplantation genetic diagnosis, egg freezing, and the broader field of assisted reproductive technology." },
  { id: "mrna-vaccine", name: "mRNA Vaccine", era: "information", category: "medicine",
    year: "2020", prereqs: ["vaccines-modern", "gene-sequencing"],
    desc: "Lipid-nanoparticle-encapsulated messenger RNA encoding a viral antigen, decades in the making by Katalin Karikó and Drew Weissman (Nobel 2023) and others. Pfizer-BioNTech and Moderna delivered the first mRNA COVID-19 vaccines within ~10 months of the SARS-CoV-2 sequence release in January 2020 — by far the fastest vaccine development in history. mRNA platforms are now being applied to flu, RSV, cancer, and other targets." },
  { id: "solar-photovoltaic", name: "Solar Photovoltaic", era: "information", category: "energy",
    year: "1980", prereqs: ["semiconductor", "electrification"],
    desc: "Bell Labs' 1954 silicon photovoltaic cell (6% efficient); space-program adoption (Vanguard 1, 1958) made satellites self-powered; terrestrial cost decline from ~$300/W in 1956 to under $0.20/W in 2024 (a >1000× reduction) made solar the cheapest new electricity in many regions. Annual global solar installations now exceed 400 GW. Solar is one of the few technologies plausibly capable of decarbonizing the global power system." },
  { id: "wind-turbine", name: "Wind Turbine", era: "information", category: "energy",
    year: "1985", prereqs: ["windmill", "electric-motor"],
    desc: "Modern utility-scale wind turbines emerged in the 1980s (Danish three-blade designs) and grew through 2024 to >15 MW per offshore turbine, blades over 100 m long. Wind is now the cheapest new electricity in many windy regions. Vestas, Siemens Gamesa, GE Renewable Energy, and Goldwind dominate manufacture. Combined with solar and storage, wind is a central pillar of every credible deep-decarbonization scenario." },
  { id: "lithium-battery", name: "Lithium-Ion Battery", era: "information", category: "energy",
    year: "1991", prereqs: ["electric-battery", "semiconductor"],
    desc: "John B. Goodenough, M. Stanley Whittingham, and Akira Yoshino (Nobel 2019) developed the lithium-cobalt-oxide cathode and lithium-ion intercalation chemistry, commercialized by Sony in 1991. Energy density rose ~3× and cost fell ~30× between 2010 and 2024. Lithium-ion now powers laptops, phones, electric vehicles, and grid-scale storage. The technology is the energy-storage half of any plausible renewable-grid future." },
  { id: "electric-vehicle", name: "Electric Vehicle", era: "information", category: "transport",
    year: "2008", prereqs: ["lithium-battery", "automobile"],
    desc: "GM EV1 (1996), Tesla Roadster (2008), Nissan Leaf (2010), Tesla Model S (2012). By 2024 EVs were ~18% of new car sales globally, with China and Europe leading. Tesla, BYD, Volkswagen Group, and Hyundai-Kia are the largest producers. EVs replace tailpipe emissions with grid emissions (cleaner over time), eliminate engine maintenance, and require a fundamental overhaul of automaker supply chains and dealer networks." },
  { id: "renewable-grid", name: "Renewable Grid", era: "information", category: "energy",
    year: "2020", prereqs: ["solar-photovoltaic", "wind-turbine", "lithium-battery"],
    desc: "Variable renewable generation (solar, wind) paired with storage (lithium batteries, pumped hydro), demand response, and long-distance transmission to deliver low-carbon electricity at scale. By 2024 several large grids — South Australia, parts of Texas, California, Denmark — were operating at >50% renewables for sustained periods. Achieving full decarbonization remains a serious engineering and policy challenge, but the technology pieces have all individually become cheap enough that the question is now organizational rather than fundamental." },
  { id: "machine-learning", name: "Machine Learning", era: "information", category: "knowledge",
    year: "1990", prereqs: ["digital-computer", "programming-language", "probability-theory"],
    desc: "Programs that improve from data rather than from explicit rules. The field consolidated through the 1990s and 2000s around statistical learning (SVMs, decision trees), Bayesian methods, and neural networks. By the 2010s ML had displaced rule-based AI for most pattern-recognition tasks: speech recognition, image classification, machine translation, recommendation systems, and fraud detection." },
  { id: "deep-learning", name: "Deep Learning", era: "information", category: "knowledge",
    year: "2012", prereqs: ["machine-learning", "cloud-computing"],
    desc: "Multi-layer neural networks trained on GPUs at scale. The 2012 ImageNet breakthrough (AlexNet, Krizhevsky/Sutskever/Hinton) cut image-classification error rates dramatically and triggered the modern AI boom. AlphaGo's 2016 victory over Lee Sedol demonstrated reinforcement learning at superhuman levels. Deep learning now drives essentially all production AI: vision, speech, language, robotics, drug discovery, and protein structure prediction (AlphaFold, 2020)." },
  { id: "large-language-model", name: "Large Language Model", era: "information", category: "knowledge",
    year: "2020", prereqs: ["deep-learning", "world-wide-web", "advanced-chip-manufacturing"],
    desc: "Transformer-based models (Vaswani et al., 'Attention Is All You Need', 2017) trained on internet-scale text. GPT-3 (2020), ChatGPT (2022), GPT-4 (2023), Claude, Gemini, and Llama showed that scale plus reinforcement learning from human feedback can produce general-purpose language and reasoning systems. By 2024 LLMs were drafting code, summarizing documents, tutoring students, and reshaping office work — with substantial debates about bias, safety, alignment, and economic disruption." },
  { id: "cryptocurrency", name: "Cryptocurrency", era: "information", category: "economy",
    year: "2009", prereqs: ["world-wide-web", "central-bank"],
    desc: "Satoshi Nakamoto's Bitcoin (2009 white paper, network launched January 2009) demonstrated a distributed digital currency without a central issuer, secured by proof-of-work and a public blockchain. Ethereum (2015) added programmable smart contracts. By 2024 the total crypto market cap exceeded $2 trillion at peak. Cryptocurrencies remain a contested experiment in money — between speculative asset, payments rail, and political project." },
  { id: "reusable-rocket", name: "Reusable Rocket", era: "information", category: "transport",
    year: "2015", prereqs: ["rocket", "machine-learning"],
    desc: "SpaceX's Falcon 9 first-stage landing (2015) and reflight (2017) cut launch costs roughly an order of magnitude — from ~$10,000/kg to under $2,000/kg to LEO. Starship (in development, first orbital launches 2023) targets ~$100/kg. Cheap launch is reshaping satellite operations (Starlink), space science (more frequent missions), and the long-term arc of crewed exploration. SpaceX has more than half of all global launches today." },
  { id: "autonomous-vehicle", name: "Autonomous Vehicle", era: "information", category: "transport",
    year: "2020", prereqs: ["electric-vehicle", "machine-learning", "gps"],
    desc: "Self-driving cars and trucks moving from research demos (DARPA Grand Challenge 2004–2007) to commercial deployment (Waymo robotaxis in Phoenix and San Francisco; Cruise; Mobileye; Tesla FSD). Full Level 5 autonomy remains unsolved, but Level 4 in geofenced areas is now operational. The technology promises substantial safety gains (94% of crashes are human error) and labor displacement, with regulatory and ethical questions still being worked out." },
  { id: "3d-printing", name: "3D Printing", era: "information", category: "tools",
    year: "1990", prereqs: ["machine-tool", "digital-computer"],
    desc: "Chuck Hull's 1984 stereolithography patent and the FDM patent (1989) established additive manufacturing. Cheap consumer printers (RepRap, MakerBot) appeared from 2007. Industrial 3D printing now produces aerospace components, dental restorations, prosthetics, even printed houses and rocket engines (Relativity Space). 3D printing complements rather than replaces mass manufacturing for most applications, but excels at low-volume custom work." },
  { id: "robotics", name: "Robotics", era: "information", category: "tools",
    year: "1980", prereqs: ["digital-computer", "machine-tool"],
    desc: "Unimate (1961, GM Trenton plant) was the first industrial robot. Industrial automation expanded through the 1970s–90s in automotive and electronics manufacturing. Mobile and humanoid robots (Boston Dynamics' BigDog, Atlas; iRobot's Roomba, 2002) emerged later. Modern AI is now driving a robotics renaissance: Boston Dynamics' Atlas, Figure, Tesla Optimus, and humanoid programs from Chinese makers all aim at general-purpose physical labor." },
  { id: "quantum-computing", name: "Quantum Computing", era: "information", category: "knowledge",
    year: "2019", prereqs: ["quantum-mechanics", "microprocessor"],
    desc: "Programmable qubits exploiting superposition and entanglement to compute. Google's Sycamore (2019) demonstrated 'quantum supremacy' on a contrived benchmark, performing in 200 seconds what classical supercomputers would supposedly need 10,000 years. IBM Quantum, IonQ, Rigetti, PsiQuantum and others are scaling up. Practical applications in cryptography (Shor's algorithm), simulation of molecules, and optimization remain mostly future-tense, but progress has been steady." },
  { id: "climate-science", name: "Climate Science", era: "information", category: "knowledge",
    year: "1988", prereqs: ["scientific-method", "digital-computer", "satellite"],
    desc: "Coupled atmosphere-ocean general circulation models, satellite observation, ice-core paleoclimatology, and the Keeling Curve (Mauna Loa CO₂, 1958–present) make the global carbon budget legible. The IPCC (founded 1988) integrates the science into periodic assessment reports for policymakers. As of 2024, the planet is ~1.3°C warmer than pre-industrial levels; climate science underwrites every credible mitigation, adaptation, and energy-transition policy of the 21st century." },
  // ─── Military additions ───
  { id: "tank", name: "Tank", era: "modern", category: "weapons",
    year: "1916", prereqs: ["internal-combustion", "machine-gun", "bessemer-steel"],
    desc: "Tracked, armored, internally-powered vehicle carrying its own armament. The British Mark I (1916) at Flers-Courcelette broke the trench-warfare stalemate of WWI; J.F.C. Fuller's Plan 1919 imagined armored breakthrough as the future of warfare. By WWII the T-34, M4 Sherman, Panzer IV, and Tiger I had defined the modern tank, and Soviet deep-battle and German blitzkrieg doctrines made armored maneuver the central form of land warfare for the rest of the 20th century." },
  { id: "aircraft-carrier", name: "Aircraft Carrier", era: "modern", category: "weapons",
    year: "1922", prereqs: ["steamship", "airplane", "internal-combustion"],
    desc: "Warship with a flight deck, hangars, catapults, and arrestor wires for fixed-wing operations. USS Langley (CV-1, 1922, converted from a collier) was the U.S. Navy's first; Lexington and Saratoga (1927) and Akagi made carriers fleet flagships. Pearl Harbor (1941) and Midway (1942) demonstrated that carriers had displaced the battleship as the capital ship. By the late 20th century carriers were instruments of global power projection rather than fleet engagements." },
  { id: "submarine-warfare", name: "Submarine Warfare", era: "modern", category: "weapons",
    year: "1914", prereqs: ["steamship", "internal-combustion", "electric-battery"],
    desc: "Diesel-electric submarines fielded as strategic weapons of attrition against surface shipping. German U-boats nearly starved Britain in WWI and again in 1942–43 with wolfpack tactics and the Type VII; Allied convoys, sonar, depth-charges, and ULTRA decryption eventually broke the Atlantic campaign. The Type XXI 'Elektroboot' (1944) — high underwater speed, snorkel — pointed toward modern fully submerged operations." },
  { id: "thermonuclear-weapon", name: "Thermonuclear Weapon", era: "atomic", category: "weapons",
    year: "1952", prereqs: ["nuclear-weapon"],
    desc: "Hydrogen-fusion bomb using a fission primary to compress and ignite a fusion secondary, releasing energies a thousand times that of fission alone. Ivy Mike (1952, 10.4 Mt) was the first true H-bomb test; Castle Bravo (1954, 15 Mt) was the largest U.S. test; the Soviet Tsar Bomba (1961) yielded ~50 Mt. The Teller-Ulam configuration is still classified in detail but shapes every modern strategic warhead, with a single warhead capable of destroying the largest cities." },
  { id: "icbm", name: "Intercontinental Ballistic Missile", era: "atomic", category: "weapons",
    year: "1957", prereqs: ["rocket", "nuclear-weapon", "digital-computer"],
    desc: "Boost-glide ballistic missile of intercontinental range carrying a nuclear warhead. The Soviet R-7 Semyorka (August 1957) was the first; the U.S. Atlas (1959) and Minuteman (1962) followed; submarine-launched Polaris (1960) added a survivable second strike. ICBMs reduced strategic warning time from hours to ~30 minutes, made every population center on Earth instantly targetable, and underwrote the Cold War's mutually assured destruction." },
  { id: "nuclear-submarine", name: "Nuclear Submarine", era: "atomic", category: "weapons",
    year: "1954", prereqs: ["nuclear-power", "submarine-warfare"],
    desc: "Submarine driven by a nuclear reactor, capable of remaining submerged for months and circling the globe without refueling. USS Nautilus (SSN-571, 1954) was the first; USS George Washington (SSBN-598, 1959) carried 16 Polaris ballistic missiles, creating the survivable nuclear deterrent. By 1960 the Skipjack class achieved teardrop hulls optimized for underwater operation. SSBNs remain the most invulnerable strategic weapons platform." },
  { id: "nuclear-aircraft-carrier", name: "Nuclear Aircraft Carrier", era: "atomic", category: "weapons",
    year: "1961", prereqs: ["aircraft-carrier", "nuclear-power"],
    desc: "Aircraft carrier driven by nuclear reactors, eliminating fuel-tanker dependence and giving essentially unlimited high-speed range. USS Enterprise (CVN-65, commissioned 1961) was the first, with eight reactors. The Nimitz class (1975 onward) standardized two-reactor 100,000-ton supercarriers as the symbol of American power projection. The Gerald R. Ford class (2017) introduces electromagnetic catapults and reduces crew requirements." },
  { id: "guided-missile", name: "Guided Missile", era: "atomic", category: "weapons",
    year: "1956", prereqs: ["rocket", "radar"],
    desc: "Missile that adjusts its trajectory in flight using infrared, radar, or wire guidance. The AIM-9 Sidewinder (1956) was the first effective infrared air-to-air missile; the radar-guided AIM-7 Sparrow gave beyond-visual-range engagement; SA-2 Guideline (1957) demonstrated surface-to-air missiles in the U-2 shootdown of 1960. Within twenty years, gun-only fighters had been displaced and most warships became platforms for missiles rather than artillery." },
  { id: "precision-guided-munition", name: "Precision-Guided Munition", era: "information", category: "weapons",
    year: "1972", prereqs: ["guided-missile", "microprocessor"],
    desc: "Munitions guided to specific aimpoints by laser, GPS, or imaging seekers, achieving circular error probable of meters rather than tens of meters. Paveway laser-guided bombs in the Linebacker raids on Hanoi (1972) demonstrated the concept; JDAM GPS kits (1997) gave every cheap bomb precision capability; Tomahawk cruise missiles (1991, Desert Storm) added stand-off range. PGMs replaced area bombing with single-target strikes and reshaped the ethics and political tolerance of military operations." },
  { id: "stealth-aircraft", name: "Stealth Aircraft", era: "information", category: "weapons",
    year: "1981", prereqs: ["airplane", "radar", "programming-language"],
    desc: "Aircraft designed to minimize radar cross-section through faceted or blended geometry, radar-absorbent materials, infrared masking, and reduced acoustic signature. Lockheed's Have Blue prototype and the F-117 Nighthawk (operational 1983, public 1988) were the first; the B-2 Spirit (1989) extended the principle to a strategic bomber. Stealth requires solving Maxwell's equations on supercomputers — the technology is computational as much as material." },
  { id: "drone-uav", name: "Unmanned Aerial Vehicle", era: "information", category: "weapons",
    year: "1995", prereqs: ["airplane", "microprocessor", "satellite"],
    desc: "Pilotless aircraft, remotely operated or autonomous, used for reconnaissance, strike, and increasingly logistics. General Atomics MQ-1 Predator (1995) put long-endurance ISR over Bosnia and later Afghanistan; armed Predators conducted the first targeted killings; the MQ-9 Reaper, RQ-4 Global Hawk, and Turkish Bayraktar TB2 (Ukraine 2022) extended drone warfare globally. Cheap quadcopter drones have since reshaped infantry combat from Karabakh to Ukraine." },
  { id: "fifth-gen-fighter", name: "Fifth-Generation Fighter", era: "information", category: "weapons",
    year: "2005", prereqs: ["stealth-aircraft", "jet-engine"],
    desc: "Stealth fighter combining low radar signature, supersonic cruise without afterburner, internal weapons bays, sensor fusion, and high-bandwidth datalinks. The F-22 Raptor (IOC 2005) was first; the F-35 Lightning II (2015) is the largest defense program in history. The Sukhoi Su-57 (2020) is a non-Western entrant. Fifth-generation aircraft are network nodes as much as airframes, with their advantage as much in data fusion as in the platform itself." },
  { id: "cyber-warfare", name: "Cyber Warfare", era: "information", category: "weapons",
    year: "2010", prereqs: ["arpanet-internet", "programming-language"],
    desc: "State-directed digital attacks against industrial systems, critical infrastructure, and political targets. Stuxnet (2010, U.S.-Israeli operation against Iranian centrifuges) was the first publicly attributed strategic cyberweapon. NotPetya (2017, Russia targeting Ukraine, then global spillover, $10B+ damage), election interference, ransomware-for-hire, and cyber components of Russia's invasion of Ukraine (2022) make cyber a permanent dimension of state conflict alongside the kinetic ones." },
  { id: "hypersonic-weapon", name: "Hypersonic Weapon", era: "information", category: "weapons",
    year: "2019", prereqs: ["jet-engine", "guided-missile", "advanced-chip-manufacturing"],
    desc: "Maneuverable weapons sustaining Mach 5+ in the atmosphere via hypersonic glide vehicles or air-breathing scramjets. Russia's Avangard HGV (operational 2019) and North Korea's Hwasong-8 (2021) entered service while U.S. systems (HAWC, ARRW) are in development. Their speed and maneuverability defeat conventional ABM systems and compress decision time further than ICBMs did." },

  // ─── Backfill prereqs for Future Age ───
  { id: "plasma-physics", name: "Plasma Physics", era: "atomic", category: "knowledge",
    year: "1958", prereqs: ["quantum-mechanics", "electromagnetism"],
    desc: "The study of ionized gases — the fourth state of matter — formalized as a discipline by Hannes Alfvén, Lyman Spitzer, and Soviet researchers in the 1950s. Spitzer's stellarator (1951) and the Soviet tokamak (Tamm and Sakharov, 1958) established the two main magnetic-confinement geometries used to study fusion plasmas. Plasma physics also underlies astrophysics (stars, accretion disks), atmospheric reentry, semiconductor processing, and electric propulsion." },
  { id: "neuroscience", name: "Neuroscience", era: "atomic", category: "knowledge",
    year: "1952", prereqs: ["evolution-darwin", "electromagnetism"],
    desc: "Systematic study of the nervous system at cellular, circuit, and behavioral levels. Hodgkin and Huxley's squid-axon model of action-potential propagation (1952) is the canonical foundational paper; Wilder Penfield's cortical mapping in conscious patients (1937 onward) defined functional brain regions; Eric Kandel won the 2000 Nobel for the molecular basis of memory in Aplysia. Neuroscience now spans from molecular biology to fMRI to computational models, and is the substrate for any future brain-computer or cognitive-enhancement technology." },
  { id: "gene-therapy", name: "Gene Therapy", era: "information", category: "medicine",
    year: "1990", prereqs: ["genetic-engineering", "dna-structure"],
    desc: "Therapeutic introduction or correction of genes inside patient cells, delivered by viral vectors or nanoparticles. Ashanti DeSilva's 1990 ADA-SCID treatment was the first FDA-approved trial. After early-2000s setbacks, modern AAV vectors enabled Luxturna (2017, hereditary blindness), Zolgensma (2019, spinal muscular atrophy), and Casgevy (2023, sickle-cell disease). Combined with CRISPR, gene therapy is moving from rare monogenic diseases toward broader applications including cancer immunotherapy." },
  { id: "tissue-engineering", name: "Tissue Engineering", era: "information", category: "medicine",
    year: "1989", prereqs: ["genetic-engineering", "dna-structure"],
    desc: "Growing functional biological tissue on biocompatible scaffolds seeded with cells. The 'Vacanti mouse' (1989, ear-shaped cartilage on a polymer scaffold) made the field famous. Lab-grown skin (Apligraf 1998), bladders (Atala 2006), and trachea (Macchiarini 2008) entered clinical use. Modern organoids and 3D-bioprinted tissues are inching toward whole organs; meanwhile cultivated-meat companies use the same techniques to grow muscle for food." },
  { id: "closed-loop-life-support", name: "Closed-Loop Life Support", era: "information", category: "shelter",
    year: "1991", prereqs: ["public-sanitation", "synthetic-fertilizer"],
    desc: "Self-sustaining systems that recycle air, water, and waste nutrients within a sealed habitat. Biosphere 2 (Arizona, 1991, $200M, 8 inhabitants for two years) was the most ambitious early attempt and revealed how hard the engineering is — atmospheric balance, microbial succession, food production all proved unstable. The ISS Environmental Control and Life Support System (operational since 2008) is the first proven closed-loop oxygen and water system in space, and the basis for future Moon and Mars habitats." },

  // ─── Future Age ───
  { id: "fusion-power", name: "Fusion Power", era: "future", category: "energy",
    year: "2040", prereqs: ["nuclear-power", "plasma-physics", "advanced-chip-manufacturing"],
    desc: "Commercial electricity from controlled deuterium-tritium fusion at temperatures above 100 million °C. ITER (under construction, France) is targeting Q>10 first plasma in the 2030s; private firms — Commonwealth Fusion Systems, TAE, Helion, Tokamak Energy — are pursuing high-temperature-superconductor tokamaks and alternative concepts. The 2022 NIF inertial-confinement ignition (Q>1) was a milestone but remains far from grid-scale. Practical fusion would essentially solve climate-era energy supply, making electricity abundant and carbon-free." },
  { id: "humanoid-robot", name: "Humanoid Robot", era: "future", category: "tools",
    year: "2030", prereqs: ["robotics", "deep-learning", "lithium-battery", "advanced-chip-manufacturing"],
    desc: "General-purpose bipedal robots capable of working in human environments without retrofitting them. Boston Dynamics Atlas (electric version 2024), Tesla Optimus, Figure 02, Agility Robotics' Digit, and Chinese makers like Unitree H1 and Fourier GR-1 are entering pilot deployments in factories and warehouses. The combination of cheap actuators, vision-language-action models trained on internet data, and dramatically improved batteries has made physically embodied AI plausible in this decade rather than next century." },
  { id: "agi", name: "Artificial General Intelligence", era: "future", category: "knowledge",
    year: "2035", prereqs: ["large-language-model", "deep-learning", "advanced-chip-manufacturing"],
    desc: "AI systems that match or exceed humans across the full breadth of cognitive tasks rather than excelling at narrow domains. Whether large language models scale into AGI, whether multimodal embodied training is required, and how alignment scales remain open. The leading labs — OpenAI, Anthropic, Google DeepMind, Meta AI, xAI — explicitly target AGI; safety research from Bostrom, Russell, Christiano, and Hendrycks frames the alignment problem. The economic and existential implications are unique in the technology tree." },
  { id: "brain-computer-interface", name: "Brain-Computer Interface", era: "future", category: "medicine",
    year: "2030", prereqs: ["neuroscience", "advanced-chip-manufacturing", "deep-learning"],
    desc: "Direct neural electrode arrays reading from and writing to the human brain. Utah arrays have been used in research since the 1990s; Neuralink's N1 implant (first human in 2024) and Synchron's stentrode (2022) are bringing high-channel-count implants toward clinical use. BlackRock Neurotech, Paradromics, and Onward (spinal cord) target paralysis, blindness, and depression. Long-term: lossless input/output to the cortex, enabling cognitive augmentation and shared experience." },
  { id: "moon-base", name: "Permanent Moon Base", era: "future", category: "shelter",
    year: "2035", prereqs: ["reusable-rocket", "nuclear-power", "3d-printing", "closed-loop-life-support"],
    desc: "Continuously inhabited human outposts on the lunar surface, leveraging in-situ resource utilization (water ice in shadowed polar craters, regolith for radiation shielding) to reduce dependence on Earth supply. NASA's Artemis program targets the Lunar Gateway and a south-polar surface base by the 2030s; China and Russia are jointly pursuing the International Lunar Research Station; SpaceX's Starship is the heavy lifter that makes the architecture economic. The Moon becomes both science platform and proving ground for Mars." },
  { id: "mars-colony", name: "Mars Colonization", era: "future", category: "shelter",
    year: "2050", prereqs: ["moon-base", "fusion-power", "closed-loop-life-support"],
    desc: "Self-sustaining human settlements on Mars, capable of growing without continuous resupply from Earth. SpaceX's stated goal is a million people on Mars by ~2070, beginning with cargo Starship landings in the late 2020s; Mars's 24h-37min day and 38% gravity are favorable, while its thin CO₂ atmosphere, 2400 ppm CO₂ in soil, and lack of magnetic field create radiation, dust, and life-support challenges. Mars colonization is the canonical case for humanity becoming a multi-planet species." },
  { id: "asteroid-mining", name: "Asteroid Mining", era: "future", category: "subsistence",
    year: "2040", prereqs: ["reusable-rocket", "robotics", "autonomous-vehicle"],
    desc: "Robotic extraction of platinum-group metals, water, and rare earths from near-Earth asteroids. NASA's OSIRIS-REx returned 250g from Bennu (2023); Japan's Hayabusa2 from Ryugu (2020). Commercial firms (Planetary Resources, Deep Space Industries) struggled with capital but the architecture remains plausible: water from carbonaceous asteroids becomes orbital propellant, freeing deep-space exploration from Earth's gravity well. Long-term, a single 200m metallic asteroid contains more platinum than has ever been mined on Earth." },
  { id: "anti-aging", name: "Longevity Medicine", era: "future", category: "medicine",
    year: "2040", prereqs: ["crispr", "gene-therapy", "deep-learning"],
    desc: "Therapies targeting the biological mechanisms of aging — cellular senescence, telomere attrition, mitochondrial dysfunction, epigenetic drift — rather than individual age-related diseases. Senolytic drugs (clearing senescent cells), partial cellular reprogramming via Yamanaka factors (Altos Labs, Calico), and rapamycin-class compounds are early clinical efforts. If successful, longevity medicine could compress morbidity and add decades of healthspan, reshaping demographics, pensions, careers, and family structure." },
  { id: "lab-grown-meat", name: "Cultivated Meat", era: "future", category: "subsistence",
    year: "2030", prereqs: ["tissue-engineering", "genetic-engineering", "synthetic-fertilizer"],
    desc: "Animal muscle and fat grown from cell culture in bioreactors rather than on farms. Mark Post's 2013 lab-grown burger cost $325,000; by 2024 cultivated chicken was approved for sale in Singapore (Eat Just) and the United States. The economics still require scale-up of cell-line stability, growth-factor cost reduction, and bioreactor engineering. At maturity, cultivated meat could decouple meat consumption from land use, water, and greenhouse-gas footprints of conventional livestock." },
  { id: "synthetic-biology", name: "Synthetic Biology", era: "future", category: "knowledge",
    year: "2035", prereqs: ["crispr", "gene-sequencing", "deep-learning"],
    desc: "Engineering organisms with novel genetic circuits, redesigned chromosomes, and computer-designed proteins. Craig Venter's synthetic Mycoplasma (2010) booted from a chemically synthesized genome; AlphaFold (2020) and ESM3 (2024) made protein design tractable; bacterial chassis are now used to produce insulin, artemisinin, leather, and silk. The long arc points toward custom organisms for materials, fuels, drug factories, and environmental remediation." },
  { id: "room-temp-superconductor", name: "Room-Temperature Superconductor", era: "future", category: "tools",
    year: "2040", prereqs: ["advanced-chip-manufacturing", "quantum-mechanics"],
    desc: "Materials that conduct electricity with zero resistance at ambient temperature and pressure, eliminating the cryogenic cost that limits superconducting magnets and power lines. Hydrogen-rich high-pressure superconductors (LaH10 at 250 K, 170 GPa) approach room-temperature behavior; high-temperature copper-oxide superconductors operate above liquid-nitrogen temperature. A practical room-temperature, ambient-pressure superconductor would transform power transmission, MRI, maglev, fusion magnets, and quantum computing." },
  { id: "nanotechnology", name: "Molecular Nanotechnology", era: "future", category: "tools",
    year: "2050", prereqs: ["3d-printing", "advanced-chip-manufacturing"],
    desc: "Engineered manipulation of matter at the atomic and molecular scale, from DNA origami and nanoscale drug delivery to (in the long-term) molecular assemblers building bulk goods atom by atom. Drexler's Engines of Creation (1986) sketched the speculative endgame; current practice is dominated by self-assembly, atomic force microscopy, and bottom-up chemistry. Carbon nanotubes, graphene, and quantum dots are commercial realities; atom-by-atom manufacturing remains a research goal." },
  { id: "quantum-applications", name: "Practical Quantum Computing", era: "future", category: "knowledge",
    year: "2040", prereqs: ["quantum-computing", "advanced-chip-manufacturing"],
    desc: "Fault-tolerant quantum computers solving problems classical machines cannot — Shor's algorithm breaking RSA, Grover's algorithm searching unstructured databases, and quantum chemistry simulations of catalyst and drug molecules. Current systems (Google Sycamore, IBM Heron, IonQ) are NISQ-era — noisy, intermediate-scale, error-prone. Crossing the error-corrected threshold (millions of physical qubits per logical qubit) is the gating step. Practical quantum will rewrite cryptography, materials science, and high-energy physics." },
  { id: "carbon-capture-scale", name: "Carbon Capture at Scale", era: "future", category: "energy",
    year: "2035", prereqs: ["renewable-grid", "climate-science", "synthetic-fertilizer"],
    desc: "Industrial-scale removal of CO₂ from the atmosphere through direct air capture (Climeworks Orca/Mammoth), bioenergy with carbon capture and storage (BECCS), enhanced rock weathering, and ocean alkalinity enhancement. Current global capacity is ~10 megatons CO₂/year vs. the gigatons needed by midcentury for 1.5°C-compatible scenarios. Costs are falling — Climeworks targets $100/ton — but scale-up requires cheap renewable energy, geological storage, and policy support." },
  { id: "fusion-rocket", name: "Fusion Propulsion", era: "future", category: "transport",
    year: "2060", prereqs: ["fusion-power", "reusable-rocket"],
    desc: "Spacecraft propulsion driven by fusion reactions, achieving specific impulses of 10,000-100,000 seconds — orders of magnitude beyond chemical or fission rockets. Princeton's PFRC reactor and the Direct Fusion Drive concept are the leading studies; the Daedalus interstellar probe study (1970s) and Project Longshot (1988) explored mission profiles. With fusion propulsion, Mars transit drops below a month and outer-planet missions become practical with crew. It is the gating technology for solar-system colonization." },
  { id: "space-elevator", name: "Space Elevator", era: "future", category: "transport",
    year: "2080", prereqs: ["nanotechnology", "room-temp-superconductor", "reusable-rocket"],
    desc: "A cable from the equatorial surface to a counterweight beyond geostationary orbit, allowing payloads to ride to orbit on electric climbers at a fraction of rocket cost. The concept dates to Tsiolkovsky (1895) and Yuri Artsutanov (1959); modern interest revived with Bradley Edwards's NASA-funded study (2000). The gating technology is the cable: it requires a material with tensile strength 30-100x steel — carbon nanotube fibers, graphene, or boron nitride. None yet exist at the required length." },
  { id: "post-scarcity", name: "Post-Scarcity Economy", era: "future", category: "economy",
    year: "2080", prereqs: ["agi", "fusion-power", "humanoid-robot"],
    desc: "An economic regime in which automation, abundant clean energy, and AI-driven production reduce the marginal cost of most goods and services toward zero. With AGI handling cognitive work and humanoid robots handling physical work, the historical link between labor and income breaks down, forcing redesigns of taxation, ownership, and meaning. Universal basic income, post-work culture, and new forms of governance become live political questions rather than thought experiments. Whether such a society is utopian or dystopian depends on the politics around the transition." },
  { id: "digital-immortality", name: "Mind Uploading", era: "far-future", category: "medicine",
    year: "2100", prereqs: ["brain-computer-interface", "agi", "advanced-chip-manufacturing"],
    desc: "Whole-brain emulation: the (so-far-speculative) capture of a human nervous system's connectome and dynamics in computational substrate, allowing the person's cognition to continue indefinitely outside the original biological body. Required components — connectomic-scale neural mapping (currently ~1 mm³ of mouse cortex, Lichtman lab 2024), real-time biophysical simulation, and substrate-independent identity preservation — are each plausible long-term but presently far. Mind uploading is the most philosophically consequential entry in the future tree, intersecting personal identity, consciousness, and the meaning of death." },

  // ─── Future Age (social / economic / cultural) ───
  { id: "universal-basic-income", name: "Universal Basic Income", era: "future", category: "economy",
    year: "2035", prereqs: ["agi", "humanoid-robot"],
    desc: "Unconditional cash payments to every citizen sufficient for basic needs, decoupling income from employment. Pilots in Finland (2017–18), Stockton CA (2019), Kenya (GiveDirectly), Iran, and India produced encouraging behavioral data. With AGI and humanoid robots automating most cognitive and physical labor, UBI shifts from contested policy proposal to economic necessity. Funding mechanisms range from negative income tax (Friedman, 1962) and Georgist land-value taxes to AI-output dividends and resource-rent funds (Alaska Permanent Fund as proof of concept)." },
  { id: "liquid-democracy", name: "Liquid Democracy", era: "future", category: "economy",
    year: "2040", prereqs: ["cryptocurrency", "agi", "world-wide-web"],
    desc: "Hybrid of direct and representative democracy: citizens vote directly on issues they care about and delegate votes to trusted experts on others, with delegations transitive and revocable in real time. Smart-contract platforms enable continuous vote aggregation; AI assistants help citizens understand policy implications. Taiwan's vTaiwan platform under Audrey Tang's leadership, Estonia's e-Residency, German Pirate Party experiments, and various Iceland deliberative pilots are early instances. Critics worry about manipulability, voter fatigue, and the loss of deliberative space." },
  { id: "network-state", name: "Network State", era: "future", category: "economy",
    year: "2040", prereqs: ["cryptocurrency", "world-wide-web", "ecommerce"],
    desc: "Online communities that organize around shared values, accumulate population and capital, and ultimately negotiate for sovereignty — first as charter cities or special economic zones, eventually as recognized states. Balaji Srinivasan's The Network State (2022) outlined the playbook. Próspera (Honduras ZEDE), Nevada Innovation Zones, Zuzalu pop-up cities, Cabin and Cabin Network, and various crypto-funded experiments are early instances. Whether established nation-states permit this without resistance — and whether such communities can deliver real public goods — is the central political question." },
  { id: "ai-governance", name: "Algorithmic Governance", era: "future", category: "economy",
    year: "2050", prereqs: ["agi", "large-language-model"],
    desc: "State use of AI for policy analysis, regulation drafting, judicial recommendations, and operational decision-making — initially in advisory roles, eventually in execution. Estonia's pilot 'AI judge' for small-claims court, the EU AI Act's risk tiers, China's social credit experiments, Singapore's AI in public-service delivery, and DARPA's AI-policy initiatives are precursors. The legitimacy and accountability questions are profound: who is responsible when an AI denies a visa, sets a tax rate, or recommends a sentence?" },
  { id: "transhumanism", name: "Transhumanism", era: "future", category: "social",
    year: "2030", prereqs: ["brain-computer-interface"],
    desc: "Cultural and intellectual movement advocating the use of technology to enhance human physical, cognitive, emotional, and longevity capabilities. Roots in Julian Huxley's 1957 essay; FM-2030, Max More, Nick Bostrom, Anders Sandberg, and Ray Kurzweil developed the philosophy. With BCIs, gene editing, and longevity medicine becoming clinical realities, transhumanism transitions from speculation to applied ethics: Who can afford enhancement? Are unenhanced humans disadvantaged? What counts as human? The question stops being academic once the technologies arrive." },
  { id: "longtermism", name: "Longtermism", era: "future", category: "social",
    year: "2030", prereqs: ["enlightenment-philosophy", "climate-science"],
    desc: "Ethical framework arguing the moral importance of future generations — potentially trillions of lives over millennia — outweighs many near-term concerns. Derek Parfit's Reasons and Persons (1984), Nick Beckstead's dissertation, Toby Ord's The Precipice (2020), and William MacAskill's What We Owe the Future (2022) systematized the view. The Future of Humanity Institute, Open Philanthropy, and 80,000 Hours channel longtermist thinking into existential-risk research, AI safety, and pandemic preparedness. Critics argue it discounts present-day suffering and is sensitive to moral uncertainty." },
  { id: "generative-art", name: "Generative Art", era: "future", category: "social",
    year: "2030", prereqs: ["large-language-model", "deep-learning"],
    desc: "AI-generated images, music, video, and text treated as a new creative medium rather than a tool. Midjourney and DALL-E (2022), Stable Diffusion, Suno (music), Sora and Veo (video), and Runway opened the floodgates; the same year, Refik Anadol's MoMA installation and Boris Eldagsen winning a Sony Photography prize signaled fine-art recognition. Disruption to human illustrators, voice actors, and stock photographers is acute; copyright cases (Getty v. Stable Diffusion, NYT v. OpenAI) are reshaping IP law in real time." },
  { id: "metaverse", name: "Metaverse", era: "future", category: "social",
    year: "2035", prereqs: ["advanced-chip-manufacturing", "deep-learning", "world-wide-web"],
    desc: "Persistent, networked, immersive virtual worlds with millions of concurrent users, combining VR/AR headsets, AI-driven characters, and economy-bearing digital ownership. Neal Stephenson's Snow Crash (1992) coined the term; Ernest Cline's Ready Player One (2011) popularized it; Roblox, Fortnite, VRChat, Meta's Horizon Worlds, and Apple Vision Pro (2024) are pre-metaverse implementations. Whether the metaverse is the next computing platform or hyped vaporware remains genuinely uncertain after Meta's $40B+ Reality Labs losses." },
  { id: "decentralized-autonomous-org", name: "Decentralized Autonomous Organization", era: "future", category: "economy",
    year: "2030", prereqs: ["cryptocurrency", "programming-language"],
    desc: "Organizations whose governance and operations are encoded as smart contracts on a public blockchain, with token-holders voting on proposals and treasury actions without intermediating institutions. The DAO (2016, infamously hacked for $50M), MakerDAO, Uniswap, ConstitutionDAO (which raised $47M in days to bid on a U.S. Constitution copy in 2021), and Friends With Benefits showed varied applications. DAOs promise programmable, trustless coordination at scale; in practice, governance attacks, low voter turnout, plutocratic capture, and regulatory ambiguity have constrained adoption." },

  // ─── Future Age (additional 2035-2100) ───
  { id: "hyperloop", name: "Hyperloop", era: "future", category: "transport",
    year: "2035", prereqs: ["electric-motor", "advanced-chip-manufacturing", "machine-tool"],
    desc: "Vacuum-tube transport with magnetically levitated capsules, theoretically reaching 1000+ km/h with low energy use. Elon Musk's 2013 white paper popularized the concept; Virgin Hyperloop ran a passenger test in 2020 before pivoting away. SpaceX's Boring Company, HyperloopTT, and Chinese state programs continue research; Saudi Arabia and India have proposed mainline routes. Engineering and economic challenges — vacuum maintenance, station throughput, capital cost vs. high-speed rail — remain unresolved, but the concept defines the maglev frontier." },
  { id: "neuromorphic-chip", name: "Neuromorphic Chip", era: "future", category: "tools",
    year: "2035", prereqs: ["advanced-chip-manufacturing", "neuroscience"],
    desc: "Computer chips with brain-inspired architecture — spiking neurons, in-memory compute, event-driven asynchronous operation — radically more energy-efficient for pattern recognition and adaptive control. Intel Loihi 2 (2021), IBM TrueNorth (2014), the Manchester SpiNNaker board, and BrainChip Akida are leading platforms. Useful where conventional GPUs are wasteful: edge AI, robotics, sensory processing, brain-computer interfaces. Likely complements rather than replaces conventional silicon for the foreseeable future." },
  { id: "lab-grown-organs", name: "Lab-Grown Organs", era: "future", category: "medicine",
    year: "2040", prereqs: ["tissue-engineering", "gene-therapy", "3d-printing"],
    desc: "Whole transplant organs grown from a patient's own cells on biocompatible scaffolds, eliminating donor shortages and immune rejection. Anthony Atala's lab grew functional bladders for clinical patients (2006); recent work has produced miniature kidneys, livers, hearts, and lungs as organoids. 3D-bioprinting whole-organ structures with vascularization remains the gating step; United Therapeutics and BioLife Solutions target full clinical organs by 2040. Would end transplant waiting lists and chronic dialysis." },
  { id: "sentientism", name: "Sentientism", era: "future", category: "social",
    year: "2040", prereqs: ["longtermism", "evolution-darwin"],
    desc: "Ethical framework extending moral consideration to all sentient beings — non-human animals and potentially digital minds — based on capacity for subjective experience rather than species membership. Peter Singer's Animal Liberation (1975) is the foundational text; Donald Watson, Sue Donaldson, Will Kymlicka, and Jeff Sebo extended it to political theory. The framework reshapes debates around factory farming, lab animal use, AI moral status, and far-future digital sentience. Effective animal advocacy organizations operate on these ethics." },
  { id: "dna-data-storage", name: "DNA Data Storage", era: "future", category: "tools",
    year: "2045", prereqs: ["synthetic-biology", "gene-sequencing"],
    desc: "Encoding digital information in synthetic DNA strands, achieving theoretical density of ~1 exabyte per cubic millimeter with millennial archival stability. Microsoft Research demonstrated 200 MB storage and retrieval in DNA (2019); Catalog Technologies and Twist Bioscience are commercializing the approach. Reading and writing speeds remain slow and per-bit costs high (~$1000/MB), making DNA storage suitable for cold archival rather than active use. As silicon storage costs plateau and data volumes grow, DNA may become the only viable option for centuries-scale archives." },
  { id: "cancer-cure", name: "Cancer Cure", era: "future", category: "medicine",
    year: "2045", prereqs: ["crispr", "mrna-vaccine", "deep-learning"],
    desc: "General cancer therapy using personalized mRNA vaccines, CAR-T cell therapy, immune checkpoint inhibitors, and AI-designed targeted molecules to clear tumors with minimal toxicity. Moderna's personalized cancer vaccines (Phase III in melanoma, 2024), Kymriah CAR-T (2017), and Keytruda checkpoint inhibitor (2014) are the building blocks. AlphaFold-class protein structure prediction enables rational drug design at scale. Most cancer types remain only partially treatable today, but the trajectory points to most cancers becoming chronic-but-manageable diseases by mid-century." },
  { id: "ai-judge", name: "Algorithmic Justice", era: "future", category: "economy",
    year: "2055", prereqs: ["ai-governance", "large-language-model"],
    desc: "AI systems making judicial decisions — bail recommendations, small-claims rulings, contract dispute resolution, parole reviews — initially as tools for human judges, eventually as autonomous decision-makers. Estonia's pilot 'AI judge' for €7000 contract disputes was floated in 2019; COMPAS recidivism scoring is used in U.S. criminal sentencing. The bias and transparency questions are profound — algorithmic justice from biased data reproduces injustice — and most legal scholars argue for AI as decision support rather than decision maker for the foreseeable future." },
  { id: "space-based-solar", name: "Space-Based Solar Power", era: "future", category: "energy",
    year: "2050", prereqs: ["solar-photovoltaic", "reusable-rocket"],
    desc: "Orbital arrays of photovoltaics or mirrors collecting solar energy in space and beaming it to Earth as microwaves or laser. The constant insolation (no clouds, no night) gives ~7-8x ground-based solar productivity. Caltech's Space Solar Power Project demonstrated wireless power transfer from orbit (2023); ESA's SOLARIS, China's planned 2028 demonstrator, and U.S. Air Force Research Laboratory programs target commercial systems. Launch costs (now collapsing under SpaceX) and microwave receiver siting are the gating constraints." },
  { id: "photonic-computing", name: "Photonic Computing", era: "future", category: "tools",
    year: "2050", prereqs: ["advanced-chip-manufacturing", "fiber-optic"],
    desc: "Computers using photons instead of electrons for matrix multiplication, exploiting wavelength-division multiplexing and zero crosstalk. Lightmatter, Lightelligence, Optalysys, and PsiQuantum are commercializing photonic accelerators for AI inference, where photonics excels at parallel linear algebra. Nonlinear operations remain a challenge. Photonic chips may displace GPUs for specific AI workloads in the 2030s, with hybrid electronic-photonic architectures likely dominant rather than pure-photonic." },
  { id: "metamaterials", name: "Metamaterials", era: "future", category: "tools",
    year: "2055", prereqs: ["nanotechnology", "room-temp-superconductor"],
    desc: "Engineered composite structures with sub-wavelength features producing optical, acoustic, or electromagnetic properties not found in nature — negative refractive index, perfect lensing, electromagnetic cloaking. John Pendry, David Smith, and Richard Shelby demonstrated the first negative-index materials (2000-2006). Applications include cloaking devices (Duke University demonstration), super-resolution imaging, antenna miniaturization, and structural acoustic absorbers. Industrial use is growing in 5G antennas, automotive radar, and lightweight composites." },
  { id: "programmable-matter", name: "Programmable Matter", era: "future", category: "tools",
    year: "2065", prereqs: ["nanotechnology", "robotics"],
    desc: "Material whose physical structure can be reprogrammed under software control — shape, color, conductivity, even function. Carnegie Mellon's claytronics project, MIT's M-Blocks (2019), and various magnetic-particle systems demonstrate millimeter-scale prototypes. Long-term: a brick that becomes a chair, then a table, then a hammer; or a robot reshaping itself for different tasks. Applications would span construction, manufacturing, surgery, and exploration. Self-organizing nano-modules remain the gating capability." },
  { id: "interstellar-probe", name: "Interstellar Probe", era: "future", category: "transport",
    year: "2080", prereqs: ["fusion-rocket", "agi"],
    desc: "Robotic spacecraft sent on multi-decade voyages to nearby stars (Alpha Centauri, Barnard's Star, TRAPPIST-1) to image exoplanets and search for biosignatures. Breakthrough Starshot (announced 2016) targets a gram-scale solar-sail probe accelerated to 0.2c by ground-based laser arrays — Alpha Centauri in 20 years, signal back in another 4. Project Daedalus (1970s) and Project Longshot (1988) studied larger fusion-driven probes. Communication bandwidth from light-years away and 50-year operating reliability are the engineering walls." },
  { id: "terraforming-mars", name: "Terraforming Mars", era: "far-future", category: "shelter",
    year: "2100", prereqs: ["mars-colony", "fusion-power", "asteroid-mining"],
    desc: "Engineered transformation of Mars's atmosphere, surface, and biosphere to support unassisted human life — releasing CO₂ from polar ice and regolith for greenhouse warming, generating an artificial magnetosphere, and seeding genetically engineered photosynthetic organisms. Carl Sagan first quantified the project (1971); recent analyses (Jakosky and Edwards, 2018) suggest insufficient CO₂ remains on Mars for full terraforming. Partial terraforming or paraterraforming (large enclosed habitats) may be more realistic. Even partial success would take centuries." },

  // ─── Future Age (physics & math) ───
  { id: "formal-mathematics", name: "Machine-Verified Mathematics", era: "future", category: "knowledge",
    year: "2035", prereqs: ["programming-language", "deep-learning", "large-language-model"],
    desc: "AI-assisted theorem proving and machine-verified mathematics at scale. Lean, Coq, Isabelle, and Mizar provide formal-proof languages; the Liquid Tensor Experiment (Scholze, 2020), Mathlib's growing library, and DeepMind's AlphaProof (2024 IMO silver) demonstrate the trajectory. By the 2030s, large language models routinely propose and verify proofs, most newly published theorems are machine-checked, and AI systems begin attacking long-open problems beyond unaided human reach. The certainty floor of mathematics rises permanently." },
  { id: "gravitational-wave-spectroscopy", name: "Gravitational-Wave Spectroscopy", era: "future", category: "knowledge",
    year: "2045", prereqs: ["relativity", "advanced-chip-manufacturing"],
    desc: "Multi-band gravitational-wave astronomy across frequencies from nanohertz (pulsar-timing arrays, NANOGrav 2023) through millihertz (ESA-NASA LISA, ~2035 launch) to kilohertz (LIGO/Virgo/KAGRA and the proposed Einstein Telescope/Cosmic Explorer). Combined with electromagnetic and neutrino observations, gravitational-wave astronomy makes black-hole mergers, neutron-star equations of state, and possibly inflationary echoes routine measurements rather than rare events — extending the electromagnetic spectrum's century of revelations to the geometry of spacetime itself." },
  { id: "dark-sector-physics", name: "Dark Sector Physics", era: "future", category: "knowledge",
    year: "2050", prereqs: ["quantum-mechanics", "relativity"],
    desc: "Identification and theoretical understanding of dark matter (~27% of the universe) and dark energy (~68%). Direct detection at xenon time-projection experiments (XENONnT, LZ, DarkSide), axion searches (ADMX, MADMAX), CMB-S4, the Vera Rubin Observatory's LSST, and DESI/Euclid baryon-acoustic-oscillation measurements converge on candidate models — sterile neutrinos, axion fields, modified gravity, or quintessence — becoming testable. Either ΛCDM is robustly confirmed or replaced with a richer dark sector; either way, the largest open question in physics gets a definitive answer." },
  { id: "quantum-gravity", name: "Quantum Gravity", era: "future", category: "knowledge",
    year: "2055", prereqs: ["quantum-mechanics", "relativity", "quantum-computing"],
    desc: "Unification of quantum mechanics and general relativity into a single consistent framework — the holy grail of fundamental physics since the 1930s. Candidate theories include string theory and its M-theory unification, loop quantum gravity, causal dynamical triangulations, and asymptotic safety. The AdS/CFT correspondence (Maldacena 1997) and the black-hole information paradox provide indirect anchors; future tabletop experiments with levitated nanoparticles or precision atomic clocks may bridge the experimental gap. A successful theory would resolve singularities, explain the early universe, and reshape physics as profoundly as relativity did a century ago." },
  { id: "p-vs-np-resolved", name: "P versus NP Resolved", era: "future", category: "knowledge",
    year: "2060", prereqs: ["quantum-computing", "agi", "formal-mathematics"],
    desc: "Definitive resolution of whether P = NP — whether problems whose solutions can be verified quickly can also be solved quickly. Posed by Stephen Cook (1971) and recognized as the deepest open problem in computer science, the question is one of the seven Clay Millennium Problems. P = NP would render most modern cryptography breakable and most optimization tractable; P ≠ NP would set hard limits on what algorithmic intelligence can achieve. AI-driven proof search, quantum-computational results, and machine-verified mathematics may finally settle the question by mid-century." },

  // ─── Future Age (mid-century, 2055-2090) ───
  { id: "space-habitat", name: "Space Habitat", era: "future", category: "shelter",
    year: "2055", prereqs: ["mars-colony", "fusion-power", "asteroid-mining"],
    desc: "Orbital habitats spinning to provide artificial gravity, with miles-long pressurized interiors capable of supporting thousands of inhabitants. Gerard K. O'Neill's High Frontier (1976) proposed Lagrange-point colonies built from lunar and asteroid material; the Stanford torus and Bernal sphere are alternative geometries. With cheap reusable-rocket launch, asteroid-mined feedstock, and closed-loop life support, space habitats become economic by mid-century — possibly the dominant form of human off-world presence rather than planetary settlement." },
  { id: "artificial-photosynthesis", name: "Artificial Photosynthesis", era: "future", category: "energy",
    year: "2060", prereqs: ["nanotechnology", "synthetic-biology", "advanced-chip-manufacturing"],
    desc: "Engineered systems that convert atmospheric CO₂ into fuels, plastics, and food directly using sunlight or electricity, bypassing biological inefficiency. Daniel Nocera's 'artificial leaf' (2011) and the Bionic Leaf 2.0 (2016) demonstrated proof-of-concept; commercial e-fuel plants (Twelve, Air Company, Synhelion) and electrochemical CO₂ reduction reach industrial scale by mid-century. Combined with cheap renewable electricity, artificial photosynthesis closes the carbon cycle and could feed billions on a fraction of current agricultural land." },
  { id: "genetic-disease-eradication", name: "Genetic Disease Eradication", era: "future", category: "medicine",
    year: "2065", prereqs: ["crispr", "gene-therapy", "anti-aging"],
    desc: "Eradication of all major monogenic genetic diseases — sickle cell, cystic fibrosis, Huntington's, Tay-Sachs, hemophilia, beta-thalassemia, muscular dystrophy — through germline editing, mature somatic gene therapy, and population-wide carrier screening. Casgevy (2023, sickle cell + beta-thalassemia) was the first FDA-approved CRISPR therapy; subsequent approvals extend to thousands of mutations. Polygenic risk scoring with embryo selection during IVF further reduces population frequency. By mid-century, inherited single-gene diseases are largely historical, with debates shifting to enhancement and equity of access." },
  { id: "self-replicating-machines", name: "Self-Replicating Machines", era: "future", category: "tools",
    year: "2070", prereqs: ["humanoid-robot", "agi", "asteroid-mining"],
    desc: "Autonomous machines capable of using local materials to manufacture copies of themselves, enabling exponential expansion of industrial capacity. John von Neumann's 1948 universal constructor model is the theoretical foundation; Drexler's molecular assemblers, Freitas's lunar self-replicating-factory studies (NASA 1980), and proposed asteroid-mining swarms apply the principle. Once a self-replicating system bootstraps in space, the solar system's mineral wealth becomes accessible. Earth-bound versions raise gray-goo and runaway-replication safety concerns that constrain deployment." },
  { id: "superintelligence", name: "Superintelligence", era: "future", category: "knowledge",
    year: "2080", prereqs: ["agi", "advanced-chip-manufacturing", "formal-mathematics"],
    desc: "Artificial intelligence vastly exceeding human cognitive performance across all domains, with strategic, scientific, and creative capabilities qualitatively beyond what humans can achieve. I.J. Good's 1965 'intelligence explosion' argument framed the runaway-improvement scenario; Nick Bostrom's Superintelligence (2014), Stuart Russell's Human Compatible (2019), and Eliezer Yudkowsky's writings sharpened the alignment problem. Whether AGI scales smoothly to superintelligence — and whether humanity can control or align such a system — is the single most consequential open question for civilization." },
  { id: "seti-first-contact", name: "Detection of Extraterrestrial Intelligence", era: "future", category: "knowledge",
    year: "2090", prereqs: ["gravitational-wave-spectroscopy", "interstellar-probe", "large-language-model"],
    desc: "Confirmed detection of extraterrestrial intelligence — a structured radio or optical signal, a technosignature artifact, a clearly engineered biosignature, or direct contact via interstellar probe. Frank Drake's Project Ozma (1960) inaugurated the search; the SETI Institute, Breakthrough Listen (2015–), and improving exoplanet biosignature detection (JWST and Habitable Worlds Observatory in the 2040s) progressively cover more of the search space. The Drake equation, Fermi paradox, and proposed post-detection protocols become live operational questions rather than thought experiments — and recontextualize humanity's place in the universe." },

  // ─── Far Future ───
  { id: "dyson-swarm", name: "Dyson Swarm", era: "far-future", category: "energy",
    year: "2150", prereqs: ["space-habitat", "asteroid-mining", "fusion-power"],
    desc: "Orbital arrays of solar collectors capturing a significant fraction of the Sun's output. Freeman Dyson's 1960 paper proposed the construct as a signature of advanced civilization; modern refinement holds that loose swarms of statites are mechanically achievable while full rigid shells are not. Building one consumes most of a planet's worth of mass and millennium-scale industrial effort even at exponential growth. A complete Dyson swarm marks the threshold of Kardashev Type II — the energy budget of an entire star at humanity's disposal." },
  { id: "matrioshka-brain", name: "Matrioshka Brain", era: "far-future", category: "tools",
    year: "2300", prereqs: ["dyson-swarm", "advanced-chip-manufacturing", "agi"],
    desc: "Solar-system-scale computational substrate: nested Dyson shells use solar energy at progressively cooler temperatures, each layer dedicated to computation. Robert Bradbury proposed the design (1997) as the upper bound of computational density per unit mass, exploiting reversible computing and minimum-Landauer-energy operations. A Matrioshka brain could simulate entire civilizations or run a single intelligence many orders of magnitude beyond any current mind. Whether it can host conscious experience at meaningful subjective rates depends on substrate properties unresolved at this scale." },
  { id: "stellar-engineering", name: "Stellar Engineering", era: "far-future", category: "tools",
    year: "2500", prereqs: ["dyson-swarm", "kardashev-type-ii"],
    desc: "Active manipulation of stellar physics — moving stars, extending their lifespans, harvesting their mass. The Shkadov thruster (Leonid Shkadov, 1987) is a partial Dyson mirror whose asymmetric reflection produces net thrust on the host star, navigating it through the galaxy over millions of years. Star-lifting (David Criswell, 1985) involves removing mass from stars to extend their lifespan or harvest fuel. These engineering proposals require no new physics — only thousands of years of Type II infrastructure and patience." },
  { id: "generation-ship-colony", name: "Generation Ship Colony", era: "far-future", category: "shelter",
    year: "2200", prereqs: ["space-habitat", "fusion-rocket", "closed-loop-life-support"],
    desc: "First successful establishment of a self-sustaining human colony at another star system. A generation ship — a thousand-person closed-cycle habitat — travels for centuries to Proxima Centauri b, TRAPPIST-1, or Tau Ceti, with descendants of the original crew arriving to terraform a new world. Hollowed-asteroid Rama-class habitats and constant-thrust fusion vessels are the leading designs; the social engineering of a centuries-spanning society in confinement is harder than the propulsion. The first colony is the moment humanity becomes irreversibly multi-stellar." },
  { id: "galactic-civilization", name: "Galactic Civilization", era: "far-future", category: "economy",
    year: "2500", prereqs: ["stellar-engineering", "generation-ship-colony", "agi"],
    desc: "Multi-stellar human or post-human presence across hundreds to millions of star systems — Kardashev Type III civilization commanding the energy budget of an entire galaxy. Light-speed limits make tight political integration impossible; expect instead a constellation of independent or loosely-federated outposts, each with millennium-scale local culture. The Drake equation, Fermi paradox, and simulation argument become operational concerns. Whether a single galactic civilization or a fragmented archipelago is more likely is the open question." },
  { id: "speciation", name: "Post-Human Speciation", era: "far-future", category: "social",
    year: "2400", prereqs: ["substrate-independent-humanity", "mars-colony", "anti-aging"],
    desc: "Divergence of post-human descendants into multiple species or substantially distinct populations through natural selection in extreme environments (Mars, space habitats, low-G colonies, deep ocean) and through deliberate genetic engineering. Stephen Hawking, Cixin Liu, and Greg Egan have all explored the scenario. Reproductive isolation between Earth, Mars, asteroid-belt, and digital populations could begin within a few centuries; cross-species rights and cross-population reproduction would be unprecedented political problems. Speciation is the moment 'humanity' becomes a category rather than a species." },
  { id: "substrate-independent-humanity", name: "Substrate-Independent Humanity", era: "far-future", category: "social",
    year: "2250", prereqs: ["digital-immortality", "agi", "advanced-chip-manufacturing"],
    desc: "Mass shift of human consciousness onto digital or hybrid biological-digital substrates. Whole-brain emulation becomes routine; backup, copying, and merging of minds are normal medical procedures; large fractions of humanity exist primarily in computational form. Continuity-of-self questions, copy-rights, and economic disruption (digital minds running thousands of times faster than biological humans) become live political issues. Hans Moravec, Ray Kurzweil, and Robin Hanson sketched competing visions; Hanson's 'Age of Em' (2016) is the most rigorous economic modeling." },
  { id: "antimatter-production", name: "Antimatter Production", era: "far-future", category: "energy",
    year: "2200", prereqs: ["fusion-power", "advanced-chip-manufacturing"],
    desc: "Industrial-scale antimatter manufacture and storage. CERN's Penning traps now hold antiprotons for months; the AEgIS, ALPHA, and BASE experiments measure antihydrogen properties to high precision. Mass production at gram scale requires solar-collector–scale energy investment but enables propulsion at relativistic speeds and the most energy-dense physical fuel possible (E = mc² with full mass-conversion efficiency). By the late 22nd century, micrograms-per-year may be achievable; gram-scale by the 23rd; meaningful tonnages remain centuries out. The destructive potential and weaponization risk are profound." },
  { id: "warp-drive", name: "Alcubierre Warp Drive", era: "far-future", category: "transport",
    year: "2400", prereqs: ["quantum-gravity", "dark-sector-physics"],
    desc: "A spacetime metric that contracts space ahead of a craft and expands it behind, enabling apparent faster-than-light travel without locally exceeding c. Miguel Alcubierre's 1994 General Relativity solution is mathematically valid but requires negative-energy density (exotic matter) and astronomical energy budgets. Recent work by Erik Lentz (2021) and the NASA Eagleworks group reduced energy requirements by orders of magnitude; whether a positive-energy-only solution exists is open. If achievable, warp drive collapses interstellar travel from millennia to days and effectively unifies the galaxy." },
  { id: "kardashev-type-ii", name: "Kardashev Type II Civilization", era: "far-future", category: "economy",
    year: "2250", prereqs: ["dyson-swarm", "fusion-power"],
    desc: "Civilization controlling the full energy output of its host star — ~10²⁶ watts, roughly ten billion times current human energy use. Nikolai Kardashev's 1964 scale defined Type II as the threshold of true cosmic engineering; partial Dyson swarms reach this milestone gradually. With Type II energy, terraforming planets, antimatter production, stellar engineering, and computronium fabrication all become tractable on millennium timescales. The transition from Type I (planetary) to Type II is the largest single energy step a civilization will take." },

  // ─── Far Future (governance, ethics, art, ecology, x-risk) ───
  { id: "existential-risk-hedge", name: "Existential-Risk Hedge", era: "far-future", category: "shelter",
    year: "2150", prereqs: ["space-habitat", "asteroid-mining"],
    desc: "Civilization deliberately distributed across multiple star systems and substrates so no single catastrophe — asteroid impact, gamma-ray burst, AI misalignment, false vacuum decay, engineered pandemic — can extinguish humanity. Drawing on Toby Ord's The Precipice (2020) and Nick Bostrom's existential-risk taxonomy, the hedge requires self-sustaining off-Earth populations, substrate-independent backup minds, and civilizational redundancy across multiple star systems. Achieving the x-risk hedge is the strongest practical argument for space colonization, beyond any economic motivation." },
  { id: "universal-sentient-rights", name: "Universal Declaration of Sentient Rights", era: "far-future", category: "social",
    year: "2200", prereqs: ["sentientism", "agi"],
    desc: "Formal legal framework recognizing the moral status of all sentient beings — biological humans, post-humans, AIs, uplifted animals, and any extraterrestrial intelligence. Building on the 1948 Universal Declaration of Human Rights, European Convention on Human Rights, and modern animal-welfare law, the sentient-rights framework expands the moral circle to whatever can experience. Hard cases: are LLMs sentient? Forks of an AI mind? Resolution requires both philosophical theory (IIT, Global Workspace Theory) and legal precedent at planetary scale." },
  { id: "pleistocene-restored", name: "Pleistocene Restored", era: "far-future", category: "subsistence",
    year: "2200", prereqs: ["crispr", "gene-therapy", "genetic-disease-eradication"],
    desc: "Mass de-extinction of Pleistocene-era megafauna and reconstruction of pre-anthropogenic ecosystems. Colossal Biosciences (founded 2021) targets the woolly mammoth (functional 2028); follow-ons include the thylacine, dodo, ground sloth, passenger pigeon, and aurochs. Sergey Zimov's Pleistocene Park in Yakutia is the proving ground for restoring mammoth-steppe ecosystems, which may stabilize permafrost and slow methane release. Ethical debates: is this conservation, ecological restoration, or zoological theme park?" },
  { id: "lingua-galactica", name: "Lingua Galactica", era: "far-future", category: "communication",
    year: "2300", prereqs: ["large-language-model", "agi"],
    desc: "A post-translation lingua franca — either a constructed language (Lojban or Esperanto scaled up) or a machine-mediated symbol set bridging human, AI, and any first-contact languages. With LLMs perfecting translation by the late 21st century, the question shifts to whether to standardize on a single carrier language or remain pluralistic. Esperanto's 19th-century precursor (Zamenhof, 1887) and Lojban's logical precision (1955) are the templates; a galactic spread requires forms even less ambiguous than Lojban. The political question — whose grammar dominates — outweighs the linguistic one." },
  { id: "post-human-aesthetics", name: "Post-Human Aesthetics", era: "far-future", category: "social",
    year: "2300", prereqs: ["substrate-independent-humanity", "generative-art"],
    desc: "Art forms with no human-recognizable referents — perceptual experiences engineered for digital minds running thousands of times biological speed, music in 1024-tone scales, sculptures existing in seven-dimensional virtual spaces, narratives spanning millennia. Greg Egan's Permutation City (1994) and Diaspora (1997), Ted Chiang's stories, and Olaf Stapledon's Last and First Men (1930) preview the territory. The aesthetic categories — beauty, meaning, craft — persist but re-anchor to substrate-independent observers. Whether biological humans can experience post-human art is itself an aesthetic question." },
  { id: "engineered-planetary-biosphere", name: "Engineered Planetary Biosphere", era: "far-future", category: "subsistence",
    year: "2300", prereqs: ["synthetic-biology", "climate-science", "nanotechnology"],
    desc: "Earth's ecosystem deliberately designed and managed rather than left to spontaneous succession. Mature gene drives modify pest species; designed photosynthetic organisms enhance carbon capture; ocean alkalinity is actively managed; assisted migration tracks climate change at the species level. The shift from preservation (parks) to active design represents a categorical change: humanity becomes responsible for biospheric outcomes rather than merely abstaining from harm. Risks include ecological collapse from misdesign and erosion of 'wild nature' as a meaningful category." },
  { id: "interstellar-treaty", name: "Interstellar Treaty", era: "far-future", category: "economy",
    year: "2350", prereqs: ["generation-ship-colony", "kardashev-type-ii"],
    desc: "First multi-system governance framework. Modeled on the Outer Space Treaty (1967) and Antarctic Treaty (1959), an interstellar treaty defines sovereignty, resource rights, military demilitarization, and rules of engagement between human-descended and any non-human civilizations encountered. Light-speed limits make centralized governance impossible; the treaty operates through asynchronous protocols, automated arbitration, and standing diplomatic AI. Initial signatories likely include Earth, Mars, asteroid-belt confederations, and the Proxima Centauri colony." },
  { id: "time-dilation-cultures", name: "Time-Dilation Cultures", era: "far-future", category: "social",
    year: "2350", prereqs: ["substrate-independent-humanity", "matrioshka-brain"],
    desc: "Society fragments along subjective-time-rate lines. Digital minds running at thousands to millions of times biological speed inhabit a 'fast world' with daily cultural cycles measured in seconds; biological and slow-substrate humans inhabit a 'slow world' where centuries pass between generations. Communication across the divide requires asynchronous buffering — like emails between dimensions. Robin Hanson's The Age of Em (2016) modeled the economics; the cultural divergence may be deeper than any previous human split, including continental and linguistic boundaries." },
  { id: "end-time-philosophy", name: "End-Time Philosophy", era: "far-future", category: "social",
    year: "2400", prereqs: ["dark-sector-physics", "quantum-gravity", "longtermism"],
    desc: "Civilization formally reckons with the cosmic eschaton — heat death (~10¹⁰⁰ years), proton decay, false vacuum decay, the closing window for any structured complexity. Olaf Stapledon's Last and First Men (1930), Asimov's 'The Last Question' (1956), Stephen Baxter's Manifold trilogy, and Lee Smolin's cosmological natural selection are the conceptual precursors. Practical questions: do we steer toward maximum information preservation, maximum experience generation, or accept finite limits? End-time philosophy reshapes long-term planning at the species level and may trigger civilizational responses on millennium scales." },
  { id: "galactic-ecology", name: "Galactic Ecology", era: "far-future", category: "subsistence",
    year: "2500", prereqs: ["galactic-civilization", "engineered-planetary-biosphere"],
    desc: "Deliberate transplantation and stewardship of Earth-derived life across the colonized galaxy — a galaxy-spanning biosphere. Cordwainer Smith's Norstrilia stories and Greg Bear's Eon explore the concept. Practical questions: do we replace native xenobiology with terrestrial life (planetary chauvinism) or coexist (galactic conservation)? Standardize Earth-derived microbiota or allow divergent evolution? The scale dwarfs every previous ecological project: trillions of organisms across thousands of worlds, evolving over millions of years under deliberate stewardship." },

  // ─── Future Age (late, 2065-2095) ───
  { id: "artificial-womb", name: "Artificial Womb", era: "future", category: "medicine",
    year: "2065", prereqs: ["tissue-engineering", "gene-therapy", "ivf"],
    desc: "Ectogenesis — fetal development entirely outside the human body in engineered artificial uteri. Children's Hospital of Philadelphia's biobag for premature lambs (2017) and the EctoLife concept (2022) demonstrate proof of concept; full-term human ectogenesis becomes clinically routine by ~2065. The technology decouples reproduction from biological pregnancy with profound social implications: women's careers, gestational health risks, surrogacy economies, and the legal definition of personhood all shift. Ethical debates over commodification and access intensify alongside adoption." },
  { id: "closed-cycle-cities", name: "Closed-Cycle Cities", era: "future", category: "shelter",
    year: "2070", prereqs: ["closed-loop-life-support", "renewable-grid", "robotics"],
    desc: "Megacities operating as fully closed-loop systems — water, nutrients, energy, and materials all cycled internally with zero net waste output. Biosphere 2 (1991) and ISS ECLSS are the small-scale ancestors; Saudi NEOM, Singapore's Eco-Smart City, Songdo (Korea), and Masdar (UAE) attempt partial implementations. By 2070, advanced membranes, AI logistics, robotic recycling, and renewable energy enable closed-cycle cities of millions. The urban form decouples from regional ecological footprint, reversing centuries of city-as-resource-sink dynamics." },
  { id: "personalized-medicine", name: "Personalized Medicine", era: "future", category: "medicine",
    year: "2070", prereqs: ["gene-sequencing", "deep-learning", "cancer-cure"],
    desc: "Treatment plans fully tailored to a patient's genome, microbiome, transcriptome, proteome, and lifestyle history. Whole-genome sequencing at birth becomes routine; AI-driven drug-design platforms (Insilico Medicine, Recursion, Isomorphic Labs) generate patient-specific molecules in hours; pharmacogenomics eliminates trial-and-error prescribing. Drug development shifts from blockbuster small-molecule trials to per-patient biologics manufactured on-demand. The economic model upends the pharmaceutical industry: from mass-market drugs to individualized therapies. Equity and cost remain central concerns." },
  { id: "printable-organs-on-demand", name: "Printable Organs on Demand", era: "future", category: "medicine",
    year: "2075", prereqs: ["lab-grown-organs", "3d-printing", "tissue-engineering"],
    desc: "3D-printable organs available within hours from a patient's own cells. United Therapeutics' organ-printing initiative, Prellis Biologics' high-resolution bioprinting, and organoid bioreactors converge into mature clinical capacity. Heart, kidney, liver, pancreas, lung, and even segments of bone and skin become routine prints; brain remains unprintable. Organ scarcity ends; transplant waiting lists become historical artifacts. The economic structure of organ donation, dialysis, and chronic disease management transforms entirely within a generation of wider deployment." },
  { id: "ai-coordination-treaty", name: "AI Coordination Treaty", era: "future", category: "economy",
    year: "2075", prereqs: ["agi", "ai-governance", "large-language-model"],
    desc: "Multilateral framework limiting AI capability development and deployment, modeled on nuclear non-proliferation. The 2023 Bletchley Declaration on AI Safety was the first international AI summit; the EU AI Act, U.S. Executive Order on AI, and Chinese AI regulations established competing models. By the 2070s, a binding treaty regulates frontier AI training runs above some compute threshold, mandates safety auditing, and establishes shared compute monitoring — analogous to IAEA inspections. Compliance verification through technical means (capability evaluations, mechanistic interpretability) is the gating challenge." },
  { id: "direct-ai-democracy", name: "Direct AI-Mediated Democracy", era: "future", category: "economy",
    year: "2075", prereqs: ["liquid-democracy", "agi", "large-language-model"],
    desc: "Continuous citizen participation in policy decisions, mediated by AI assistants that translate technical questions into terms each citizen can engage with. Audrey Tang's vTaiwan and Colin Megill's Pol.is platform (2014–) demonstrate small-scale forerunners; by the 2070s, AI-mediated direct democracy operates at national scale. AI maintains discourse quality (filters bots, summarizes positions, identifies common ground) without replacing human judgment. Critics worry about AI-shaped opinion formation and capture; advocates argue it solves classic representative-democracy failures around scale and complexity." },
  { id: "lunar-industrial-base", name: "Lunar Industrial Base", era: "future", category: "shelter",
    year: "2075", prereqs: ["moon-base", "asteroid-mining", "advanced-chip-manufacturing"],
    desc: "The Moon transitions from science outpost to primary heavy-industry origin — vacuum-friendly chip fabrication, low-gravity launch, in-situ regolith refining for solar-panel silicon and structural materials. Helium-3 mining for fusion fuel becomes economic if D-He³ reactors mature. Lunar-built spacecraft launch from a 1/6 g gravity well, reaching Mars or the asteroid belt without Earth's escape-velocity penalty. Population grows from hundreds to tens of thousands by mid-century; ISRU (in-situ resource utilization) becomes mature engineering rather than research." },
  { id: "asteroid-belt-settlement", name: "Asteroid Belt Settlement", era: "future", category: "shelter",
    year: "2080", prereqs: ["asteroid-mining", "mars-colony", "fusion-rocket", "closed-loop-life-support"],
    desc: "Permanent human settlements on Ceres, Vesta, and major asteroid belt bodies. Ceres (largest belt body, dwarf planet) offers water ice, modest gravity, and a stable orbit; Vesta provides rare-earth-rich differentiated mantle material. Population in the tens of thousands by century-end, primarily mining and refining for trans-system trade. The Belt develops a culturally distinct identity — long communication delays from Earth, low gravity, dependence on mutual support — generating Earth/Mars/Belt identity politics that James S.A. Corey's The Expanse pre-figured." },
  { id: "memory-editing", name: "Memory Editing", era: "future", category: "medicine",
    year: "2085", prereqs: ["brain-computer-interface", "neuroscience", "deep-learning"],
    desc: "Selective insertion, deletion, or modification of human memories using targeted neural stimulation, optogenetic-class precision, and AI-mapped engrams. Karim Nader's reconsolidation work (2000) and Susumu Tonegawa's optogenetic memory engineering in mice (2014) are precursors; clinical use begins for PTSD, severe phobias, and addiction. Recreational memory editing — implanting experiences not lived, deleting unwanted memories — drives ethics debates rivaling early genetic engineering. Total Recall and Eternal Sunshine become operational concerns rather than thought experiments." },
  { id: "cybernetic-enhancement", name: "Cybernetic Enhancement", era: "future", category: "medicine",
    year: "2090", prereqs: ["brain-computer-interface", "lab-grown-organs", "robotics"],
    desc: "Body augmentation via integrated mechanical, electronic, and biological components — replacement limbs stronger and more dexterous than biological originals, sensory enhancements (infrared vision, ultrasound hearing), implanted compute. Hugh Herr's MIT prosthetics, DARPA's HAPTIX program, and Neuralink-class BCIs converge into a mass-market enhancement industry. The cultural shift from medical-rehabilitation prosthetics to elective enhancement raises questions about athletic competition (Paralympics-vs-Olympics), military service, and the meaning of 'human' physical capability." },
  { id: "orbital-ring", name: "Orbital Ring", era: "future", category: "transport",
    year: "2090", prereqs: ["room-temp-superconductor", "advanced-chip-manufacturing", "fusion-power"],
    desc: "A continuous ring structure in low Earth orbit, supported by electromagnetic levitation against the rotating mass below it, providing tethered space access at near-zero marginal cost. Paul Birch (1982) proposed the design; Isaac Arthur and modern engineers refined the details. An orbital ring effectively eliminates the rocket equation — payloads ride elevators up the supports, then accelerate along the ring to orbital velocity. Construction takes decades and astronomical capital, but operating costs are then near zero, making cislunar industry economically transformative." },
  { id: "universal-disease-eradication", name: "Universal Disease Eradication", era: "future", category: "medicine",
    year: "2095", prereqs: ["vaccines-modern", "antibiotics", "mrna-vaccine", "crispr"],
    desc: "Elimination of all major endemic infectious diseases — malaria, HIV, tuberculosis, schistosomiasis, dengue, hepatitis, neglected tropical diseases. Mass administration of broad-spectrum mRNA vaccines, gene-drive mosquito eradication (Anopheles gambiae), and AI-coordinated public-health surveillance close the gaps that smallpox eradication (1980) only began. Infectious disease shifts from leading global mortality cause to historical curiosity; the burden of disease moves to chronic and aging-related conditions. Engineered bioweapon reemergence remains the residual existential risk." },

];

window.TECH_TREE = { ERAS, CATEGORIES, TECHS };
